window.BILARA["dn16"] = window.BILARA["dn16"] || {};
window.BILARA["dn16"]["vi"] = {
  "dn16:0.1": "Trường Bộ Kinh 16 ",
  "dn16:0.2": "Kinh Đại Bát Niết Bàn ",
  "dn16:1.1.1": "Tôi nghe như vầy",
  "dn16:1.1.2": "Một thời, Đức Thế Tôn trú tại thành Vương Xá, trên núi Linh Thứu. ",
  "dn16:1.1.3": "Lúc bấy giờ, vua A-xà-thế, con bà Vedehi của nước Ma-kiệt-đà, muốn đem quân đánh dân Vajji. ",
  "dn16:1.1.4": "Vua nói như vầy: ",
  "dn16:1.1.5": "\"Ta sẽ tiêu diệt dân Vajji này, dù chúng có thần lực lớn, có uy lực lớn đến đâu, ta sẽ làm cho họ bại vong, đem lại cho họ sự tai ương, khổ nạn.\" ",
  "dn16:1.2.1": "Rồi vua A-xà-thế, con bà Vedehi của nước Ma-kiệt-đà, gọi đại thần Ma-kiệt-đà là bà-la-môn Vassakāra đến và bảo: ",
  "dn16:1.2.2": "\"Này bà-la-môn, ngươi hãy đi đến chỗ Đức Thế Tôn. Khi đến nơi, hãy thay mặt ta cúi đầu đảnh lễ dưới chân Đức Thế Tôn, thăm hỏi Ngài có ít bệnh, ít phiền, sinh hoạt nhẹ nhàng, có sức khỏe, an trú an lạc không: ",
  "dn16:1.2.3": "'Bạch Thế Tôn, vua A-xà-thế, con bà Vedehi của nước Ma-kiệt-đà, cúi đầu đảnh lễ dưới chân Đức Thế Tôn, thăm hỏi Ngài có ít bệnh, ít phiền, sinh hoạt nhẹ nhàng, có sức khỏe, an trú an lạc không.' ",
  "dn16:1.2.4": "Rồi hãy thưa như vầy: ",
  "dn16:1.2.5": "'Bạch Thế Tôn, vua A-xà-thế, con bà Vedehi của nước Ma-kiệt-đà, muốn đem quân đánh dân Vajji. ",
  "dn16:1.2.6": "Vua nói như vầy: ",
  "dn16:1.2.7": "\"Ta sẽ tiêu diệt dân Vajji này, dù chúng có thần lực lớn, có uy lực lớn đến đâu, ta sẽ làm cho họ bại vong, đem lại cho họ sự tai ương, khổ nạn.\"' ",
  "dn16:1.2.8": "Đức Thế Tôn giải thích như thế nào, hãy ghi nhớ kỹ rồi về thưa lại cho ta. ",
  "dn16:1.2.9": "Vì chư Như Lai không bao giờ nói sai sự thật.\" ",
  "dn16:1.3.0": "1. Bà-la-môn Vassakāra ",
  "dn16:1.3.1": "\"Thưa vâng\", bà-la-môn Vassakāra, đại thần Ma-kiệt-đà, vâng lệnh vua A-xà-thế con bà Vedehi của nước Ma-kiệt-đà. Ông cho thắng những cỗ xe tốt, tự mình lên xe tốt, cùng với đoàn xe tốt rời khỏi thành Vương Xá, đi về hướng núi Linh Thứu. ",
  "dn16:1.3.2": "Đi xe cho đến hết chỗ xe có thể đi được, ông xuống xe và đi bộ đến chỗ Đức Thế Tôn. Đến nơi, ông chào hỏi Đức Thế Tôn. ",
  "dn16:1.3.3": "Sau khi nói lời chào hỏi thân tình, đáng ghi nhớ, ông ngồi sang một bên. Ngồi sang một bên, bà-la-môn Vassakāra, đại thần Ma-kiệt-đà, bạch Đức Thế Tôn: ",
  "dn16:1.3.4": "\"Thưa Tôn giả Gotama, vua A-xà-thế, con bà Vedehi của nước Ma-kiệt-đà, cúi đầu đảnh lễ dưới chân Tôn giả Gotama, thăm hỏi Ngài có ít bệnh, ít phiền, sinh hoạt nhẹ nhàng, có sức khỏe, an trú an lạc không. ",
  "dn16:1.3.5": "Thưa Tôn giả Gotama, vua A-xà-thế, con bà Vedehi của nước Ma-kiệt-đà, muốn đem quân đánh dân Vajji. ",
  "dn16:1.3.6": "Vua nói như vầy: ",
  "dn16:1.3.7": "'Ta sẽ tiêu diệt dân Vajji này, dù chúng có thần lực lớn, có uy lực lớn đến đâu, ta sẽ làm cho họ bại vong, đem lại cho họ sự tai ương, khổ nạn.'\" ",
  "dn16:1.4.0": "2. Bảy Pháp Bất Thối của Nhà Vua ",
  "dn16:1.4.1": "Lúc bấy giờ, Tôn giả Ānanda đang đứng sau lưng Đức Thế Tôn, quạt hầu Ngài. ",
  "dn16:1.4.2": "Rồi Đức Thế Tôn gọi Tôn giả Ānanda: ",
  "dn16:1.4.3": "\"Này Ānanda, ngươi có nghe nói dân Vajji thường hay họp hành, hội họp nhiều không?\" ",
  "dn16:1.4.4": "\"Bạch Thế Tôn, con có nghe nói dân Vajji thường hay họp hành, hội họp nhiều.\" ",
  "dn16:1.4.5": "\"Này Ānanda, chừng nào dân Vajji còn thường hay họp hành, hội họp nhiều, thì dân Vajji chắc chắn sẽ hưng thịnh, không suy vong. ",
  "dn16:1.4.6": "Này Ānanda, ngươi có nghe nói dân Vajji hội họp trong hòa hợp, giải tán trong hòa hợp, và làm các công việc của dân Vajji trong hòa hợp không?\" ",
  "dn16:1.4.7": "\"Bạch Thế Tôn, con có nghe nói dân Vajji hội họp trong hòa hợp, giải tán trong hòa hợp, và làm các công việc của dân Vajji trong hòa hợp.\" ",
  "dn16:1.4.8": "\"Này Ānanda, chừng nào dân Vajji còn hội họp trong hòa hợp, giải tán trong hòa hợp, và làm các công việc của dân Vajji trong hòa hợp, thì dân Vajji chắc chắn sẽ hưng thịnh, không suy vong. ",
  "dn16:1.4.9": "Này Ānanda, ngươi có nghe nói dân Vajji không ban hành những điều chưa được ban hành, không hủy bỏ những điều đã được ban hành, hành trì đúng theo các truyền thống, các pháp cổ xưa của dân Vajji không?\" ",
  "dn16:1.4.10": "\"Bạch Thế Tôn, con có nghe nói dân Vajji không ban hành những điều chưa được ban hành, không hủy bỏ những điều đã được ban hành, hành trì đúng theo các truyền thống, các pháp cổ xưa của dân Vajji.\" ",
  "dn16:1.4.11": "\"Này Ānanda, chừng nào dân Vajji còn không ban hành những điều chưa được ban hành, không hủy bỏ những điều đã được ban hành, hành trì đúng theo các truyền thống, các pháp cổ xưa của dân Vajji, thì dân Vajji chắc chắn sẽ hưng thịnh, không suy vong. ",
  "dn16:1.4.12": "Này Ānanda, ngươi có nghe nói dân Vajji tôn kính, sùng kính, kính trọng, cúng dường các bậc trưởng lão của dân Vajji, và coi lời các vị ấy đáng nghe theo không?\" ",
  "dn16:1.4.13": "\"Bạch Thế Tôn, con có nghe nói dân Vajji tôn kính, sùng kính, kính trọng, cúng dường các bậc trưởng lão của dân Vajji, và coi lời các vị ấy đáng nghe theo.\" ",
  "dn16:1.4.14": "\"Này Ānanda, chừng nào dân Vajji còn tôn kính, sùng kính, kính trọng, cúng dường các bậc trưởng lão của dân Vajji, và coi lời các vị ấy đáng nghe theo, thì dân Vajji chắc chắn sẽ hưng thịnh, không suy vong. ",
  "dn16:1.4.15": "Này Ānanda, ngươi có nghe nói dân Vajji không bắt cóc, cưỡng bức phụ nữ và thiếu nữ trong các gia đình để buộc phải chung sống không?\" ",
  "dn16:1.4.16": "\"Bạch Thế Tôn, con có nghe nói dân Vajji không bắt cóc, cưỡng bức phụ nữ và thiếu nữ trong các gia đình để buộc phải chung sống.\" ",
  "dn16:1.4.17": "\"Này Ānanda, chừng nào dân Vajji còn không bắt cóc, cưỡng bức phụ nữ và thiếu nữ trong các gia đình để buộc phải chung sống, thì dân Vajji chắc chắn sẽ hưng thịnh, không suy vong. ",
  "dn16:1.4.18": "Này Ānanda, ngươi có nghe nói dân Vajji tôn kính, sùng kính, kính trọng, cúng dường các đền thờ của dân Vajji dù ở trong thành hay ngoài thành, không bỏ phế các lễ cúng dường đúng pháp đã từng được cúng dường, đã từng được thực hiện trước đây không?\" ",
  "dn16:1.4.19": "\"Bạch Thế Tôn, con có nghe nói dân Vajji tôn kính, sùng kính, kính trọng, cúng dường các đền thờ của dân Vajji dù ở trong thành hay ngoài thành, không bỏ phế các lễ cúng dường đúng pháp đã từng được cúng dường, đã từng được thực hiện trước đây.\" ",
  "dn16:1.4.20": "\"Này Ānanda, chừng nào dân Vajji còn tôn kính, sùng kính, kính trọng, cúng dường các đền thờ của dân Vajji dù ở trong thành hay ngoài thành, không bỏ phế các lễ cúng dường đúng pháp đã từng được cúng dường, đã từng được thực hiện trước đây, thì dân Vajji chắc chắn sẽ hưng thịnh, không suy vong. ",
  "dn16:1.4.21": "Này Ānanda, ngươi có nghe nói dân Vajji đã thiết lập sự bảo vệ, che chở, canh giữ đúng pháp cho các bậc A-la-hán, để các vị A-la-hán chưa đến có thể đến xứ ấy, và các vị A-la-hán đã đến có thể sống an lạc trong xứ ấy không?\" ",
  "dn16:1.4.22": "\"Bạch Thế Tôn, con có nghe nói dân Vajji đã thiết lập sự bảo vệ, che chở, canh giữ đúng pháp cho các bậc A-la-hán, để các vị A-la-hán chưa đến có thể đến xứ ấy, và các vị A-la-hán đã đến có thể sống an lạc trong xứ ấy.\" ",
  "dn16:1.4.23": "\"Này Ānanda, chừng nào dân Vajji còn thiết lập sự bảo vệ, che chở, canh giữ đúng pháp cho các bậc A-la-hán, để các vị A-la-hán chưa đến có thể đến xứ ấy, và các vị A-la-hán đã đến có thể sống an lạc trong xứ ấy, thì dân Vajji chắc chắn sẽ hưng thịnh, không suy vong.\" ",
  "dn16:1.5.1": "Rồi Đức Thế Tôn nói với bà-la-môn Vassakāra, đại thần Ma-kiệt-đà: ",
  "dn16:1.5.2": "\"Này bà-la-môn, một thời Ta trú tại Vesāli, nơi đền Sārandada. ",
  "dn16:1.5.3": "Tại đó, Ta đã dạy dân Vajji bảy pháp bất thối này. ",
  "dn16:1.5.4": "Này bà-la-môn, chừng nào bảy pháp bất thối này còn được duy trì trong dân Vajji, chừng nào dân Vajji còn tuân giữ bảy pháp bất thối này, thì dân Vajji chắc chắn sẽ hưng thịnh, không suy vong.\" ",
  "dn16:1.5.5": "Khi được nghe nói như vậy, bà-la-môn Vassakāra, đại thần Ma-kiệt-đà, bạch Đức Thế Tôn: ",
  "dn16:1.5.6": "\"Thưa Tôn giả Gotama, dân Vajji nếu chỉ có được một trong những pháp bất thối này thôi, thì cũng chắc chắn sẽ hưng thịnh, không suy vong. ",
  "dn16:1.5.7": "Huống hồ là có đầy đủ cả bảy pháp bất thối. ",
  "dn16:1.5.8": "Thưa Tôn giả Gotama, vua A-xà-thế, con bà Vedehi của nước Ma-kiệt-đà, không thể thắng được dân Vajji bằng cách chiến tranh, ngoại trừ phải dùng cách mua chuộc hoặc gây chia rẽ nội bộ. ",
  "dn16:1.5.9": "Thôi, thưa Tôn giả Gotama, bây giờ chúng con xin cáo từ, chúng con còn nhiều công việc phải làm.\" ",
  "dn16:1.5.10": "\"Này bà-la-môn, nay ngươi hãy làm những gì ngươi thấy đúng thời.\" ",
  "dn16:1.5.11": "Rồi bà-la-môn Vassakāra, đại thần Ma-kiệt-đà, hoan hỷ, tín thọ lời dạy của Đức Thế Tôn, từ chỗ ngồi đứng dậy, ra về. ",
  "dn16:1.6.0": "3. Bảy Pháp Bất Thối của Tỳ Kheo ",
  "dn16:1.6.1": "Rồi không lâu sau khi bà-la-môn Vassakāra, đại thần Ma-kiệt-đà, ra đi, Đức Thế Tôn gọi Tôn giả Ānanda: ",
  "dn16:1.6.2": "\"Này Ānanda, hãy đi triệu tập tất cả các Tỳ Kheo hiện đang cư trú quanh thành Vương Xá đến tập trung tại giảng đường.\" ",
  "dn16:1.6.3": "\"Thưa vâng, bạch Thế Tôn\", Tôn giả Ānanda vâng lời Đức Thế Tôn, đi triệu tập tất cả các Tỳ Kheo hiện đang cư trú quanh thành Vương Xá đến tập trung tại giảng đường. Rồi đến chỗ Đức Thế Tôn, đảnh lễ và đứng sang một bên. Đứng sang một bên, Tôn giả Ānanda bạch Đức Thế Tôn: ",
  "dn16:1.6.4": "\"Bạch Thế Tôn, chúng Tỳ Kheo đã tập trung đông đủ. Nay xin Đức Thế Tôn hãy làm những gì Ngài thấy đúng thời.\" ",
  "dn16:1.6.5": "Rồi Đức Thế Tôn từ chỗ ngồi đứng dậy, đi đến giảng đường, và ngồi xuống chỗ đã soạn sẵn. ",
  "dn16:1.6.6": "Ngồi xong, Đức Thế Tôn gọi các Tỳ Kheo: ",
  "dn16:1.6.7": "\"Này các Tỳ Kheo, Ta sẽ dạy bảy pháp bất thối cho các ông. ",
  "dn16:1.6.8": "Hãy lắng nghe, hãy khéo tác ý, Ta sẽ giảng.\" ",
  "dn16:1.6.9": "\"Thưa vâng, bạch Thế Tôn\", các Tỳ Kheo đáp lời Đức Thế Tôn. ",
  "dn16:1.6.10": "Đức Thế Tôn dạy như sau: ",
  "dn16:1.6.11": "\"Này các Tỳ Kheo, chừng nào các Tỳ Kheo còn thường hay họp hành, hội họp nhiều, thì các Tỳ Kheo chắc chắn sẽ hưng thịnh, không suy vong. ",
  "dn16:1.6.12": "Này các Tỳ Kheo, chừng nào các Tỳ Kheo còn hội họp trong hòa hợp, giải tán trong hòa hợp, làm các công việc của Tăng đoàn trong hòa hợp, thì các Tỳ Kheo chắc chắn sẽ hưng thịnh, không suy vong. ",
  "dn16:1.6.13": "Này các Tỳ Kheo, chừng nào các Tỳ Kheo còn không ban hành những điều chưa được ban hành, không hủy bỏ những điều đã được ban hành, hành trì đúng theo các học giới đã được thiết lập, thì các Tỳ Kheo chắc chắn sẽ hưng thịnh, không suy vong. ",
  "dn16:1.6.14": "Này các Tỳ Kheo, chừng nào các Tỳ Kheo còn tôn kính, sùng kính, kính trọng, cúng dường các vị Tỳ Kheo trưởng lão, kỳ cựu, xuất gia đã lâu, là cha của Tăng đoàn, là người lãnh đạo Tăng đoàn, và coi lời các vị ấy đáng nghe theo, thì các Tỳ Kheo chắc chắn sẽ hưng thịnh, không suy vong. ",
  "dn16:1.6.15": "Này các Tỳ Kheo, chừng nào các Tỳ Kheo còn không bị sự tham ái sanh khởi dẫn đến tái sanh chi phối, thì các Tỳ Kheo chắc chắn sẽ hưng thịnh, không suy vong. ",
  "dn16:1.6.16": "Này các Tỳ Kheo, chừng nào các Tỳ Kheo còn có ý thích sống trong rừng, trong các chỗ ở vắng vẻ, thì các Tỳ Kheo chắc chắn sẽ hưng thịnh, không suy vong. ",
  "dn16:1.6.17": "Này các Tỳ Kheo, chừng nào các Tỳ Kheo còn tự mình duy trì chánh niệm rằng: 'Làm sao để các bạn đồng phạm hạnh lương thiện chưa đến có thể đến, và các bạn đồng phạm hạnh lương thiện đã đến có thể sống an lạc', thì các Tỳ Kheo chắc chắn sẽ hưng thịnh, không suy vong. ",
  "dn16:1.6.18": "Này các Tỳ Kheo, chừng nào bảy pháp bất thối này còn được duy trì trong các Tỳ Kheo, chừng nào các Tỳ Kheo còn tuân giữ bảy pháp bất thối này, thì các Tỳ Kheo chắc chắn sẽ hưng thịnh, không suy vong. ",
  "dn16:1.7.1": "Này các Tỳ Kheo, Ta sẽ dạy thêm bảy pháp bất thối khác cho các ông. Hãy lắng nghe, hãy khéo tác ý, Ta sẽ giảng.\" ",
  "dn16:1.7.2": "\"Thưa vâng, bạch Thế Tôn\", các Tỳ Kheo đáp lời Đức Thế Tôn. ",
  "dn16:1.7.3": "Đức Thế Tôn dạy như sau: ",
  "dn16:1.7.4": "\"Này các Tỳ Kheo, chừng nào các Tỳ Kheo còn không ham thích công việc thế gian, không mê say công việc thế gian, không đắm chìm trong công việc thế gian, thì các Tỳ Kheo chắc chắn sẽ hưng thịnh, không suy vong. ",
  "dn16:1.7.5": "Này các Tỳ Kheo, chừng nào các Tỳ Kheo còn không ham thích nói chuyện phù phiếm, không mê say nói chuyện phù phiếm, không đắm chìm trong nói chuyện phù phiếm, thì các Tỳ Kheo chắc chắn sẽ hưng thịnh, không suy vong. ",
  "dn16:1.7.6": "Này các Tỳ Kheo, chừng nào các Tỳ Kheo còn không ham thích ngủ nghỉ, không mê say ngủ nghỉ, không đắm chìm trong ngủ nghỉ, thì các Tỳ Kheo chắc chắn sẽ hưng thịnh, không suy vong. ",
  "dn16:1.7.7": "Này các Tỳ Kheo, chừng nào các Tỳ Kheo còn không ham thích tụ họp đông người, không mê say tụ họp đông người, không đắm chìm trong tụ họp đông người, thì các Tỳ Kheo chắc chắn sẽ hưng thịnh, không suy vong. ",
  "dn16:1.7.8": "Này các Tỳ Kheo, chừng nào các Tỳ Kheo còn không có ác dục, không bị các ác dục chi phối, thì các Tỳ Kheo chắc chắn sẽ hưng thịnh, không suy vong. ",
  "dn16:1.7.9": "Này các Tỳ Kheo, chừng nào các Tỳ Kheo còn không làm bạn với người ác, không kết bạn với người ác, không thân cận người ác, thì các Tỳ Kheo chắc chắn sẽ hưng thịnh, không suy vong. ",
  "dn16:1.7.10": "Này các Tỳ Kheo, chừng nào các Tỳ Kheo còn chưa dừng lại ở những thành tựu nhỏ nhặt giữa chừng, thì các Tỳ Kheo chắc chắn sẽ hưng thịnh, không suy vong. ",
  "dn16:1.8.1": "Này các Tỳ Kheo, chừng nào bảy pháp bất thối này còn được duy trì trong các Tỳ Kheo, chừng nào các Tỳ Kheo còn tuân giữ bảy pháp bất thối này, thì các Tỳ Kheo chắc chắn sẽ hưng thịnh, không suy vong. ",
  "dn16:1.8.2": "Này các Tỳ Kheo, Ta sẽ dạy thêm bảy pháp bất thối khác cho các ông …vân vân…. ",
  "dn16:1.8.3": "Này các Tỳ Kheo, chừng nào các Tỳ Kheo còn có đức tin …vân vân… ",
  "dn16:1.8.4": "còn có tàm (biết hổ thẹn) … ",
  "dn16:1.8.5": "còn có quý (biết sợ tội) … ",
  "dn16:1.8.6": "còn học rộng nghe nhiều … ",
  "dn16:1.8.7": "còn tinh tấn … ",
  "dn16:1.8.8": "còn có chánh niệm … ",
  "dn16:1.8.9": "còn có trí tuệ, thì các Tỳ Kheo chắc chắn sẽ hưng thịnh, không suy vong. ",
  "dn16:1.8.10": "Này các Tỳ Kheo, chừng nào bảy pháp bất thối này còn được duy trì trong các Tỳ Kheo, chừng nào các Tỳ Kheo còn tuân giữ bảy pháp bất thối này, thì các Tỳ Kheo chắc chắn sẽ hưng thịnh, không suy vong. ",
  "dn16:1.8.11": "Này các Tỳ Kheo, Ta sẽ dạy thêm bảy pháp bất thối khác cho các ông. Hãy lắng nghe, hãy khéo tác ý, Ta sẽ giảng.\" ",
  "dn16:1.8.12": "\"Thưa vâng, bạch Thế Tôn\", các Tỳ Kheo đáp lời Đức Thế Tôn. ",
  "dn16:1.8.13": "Đức Thế Tôn dạy như sau: ",
  "dn16:1.9.1": "\"Này các Tỳ Kheo, chừng nào các Tỳ Kheo còn tu tập Niệm giác chi …vân vân… ",
  "dn16:1.9.2": "tu tập Trạch pháp giác chi … ",
  "dn16:1.9.3": "tu tập Tinh tấn giác chi … ",
  "dn16:1.9.4": "tu tập Hỷ giác chi … ",
  "dn16:1.9.5": "tu tập Khinh an giác chi … ",
  "dn16:1.9.6": "tu tập Định giác chi … ",
  "dn16:1.9.7": "tu tập Xả giác chi, thì các Tỳ Kheo chắc chắn sẽ hưng thịnh, không suy vong. ",
  "dn16:1.10.1": "Này các Tỳ Kheo, chừng nào bảy pháp bất thối này còn được duy trì trong các Tỳ Kheo, chừng nào các Tỳ Kheo còn tuân giữ bảy pháp bất thối này, thì các Tỳ Kheo chắc chắn sẽ hưng thịnh, không suy vong. ",
  "dn16:1.10.2": "Này các Tỳ Kheo, Ta sẽ dạy thêm bảy pháp bất thối khác cho các ông. Hãy lắng nghe, hãy khéo tác ý, Ta sẽ giảng.\" ",
  "dn16:1.10.3": "\"Thưa vâng, bạch Thế Tôn\", các Tỳ Kheo đáp lời Đức Thế Tôn. ",
  "dn16:1.10.4": "Đức Thế Tôn dạy như sau: ",
  "dn16:1.10.5": "\"Này các Tỳ Kheo, chừng nào các Tỳ Kheo còn tu tập tưởng về vô thường …vân vân… ",
  "dn16:1.10.6": "tu tập tưởng về vô ngã … ",
  "dn16:1.10.7": "tu tập tưởng về bất tịnh … ",
  "dn16:1.10.8": "tu tập tưởng về nguy hại … ",
  "dn16:1.10.9": "tu tập tưởng về sự đoạn trừ … ",
  "dn16:1.10.10": "tu tập tưởng về ly tham … ",
  "dn16:1.10.11": "tu tập tưởng về đoạn diệt, thì các Tỳ Kheo chắc chắn sẽ hưng thịnh, không suy vong. ",
  "dn16:1.10.12": "Này các Tỳ Kheo, chừng nào bảy pháp bất thối này còn được duy trì trong các Tỳ Kheo, chừng nào các Tỳ Kheo còn tuân giữ bảy pháp bất thối này, thì các Tỳ Kheo chắc chắn sẽ hưng thịnh, không suy vong. ",
  "dn16:1.11.1": "Này các Tỳ Kheo, Ta sẽ dạy sáu pháp bất thối cho các ông. Hãy lắng nghe, hãy khéo tác ý, Ta sẽ giảng.\" ",
  "dn16:1.11.2": "\"Thưa vâng, bạch Thế Tôn\", các Tỳ Kheo đáp lời Đức Thế Tôn. ",
  "dn16:1.11.3": "Đức Thế Tôn dạy như sau: ",
  "dn16:1.11.4": "\"Này các Tỳ Kheo, chừng nào các Tỳ Kheo còn thể hiện thân nghiệp với tâm từ đối với các bạn đồng phạm hạnh, dù trước mặt hay sau lưng, thì các Tỳ Kheo chắc chắn sẽ hưng thịnh, không suy vong. ",
  "dn16:1.11.5": "Này các Tỳ Kheo, chừng nào các Tỳ Kheo còn thể hiện khẩu nghiệp với tâm từ …vân vân… ",
  "dn16:1.11.6": "thể hiện ý nghiệp với tâm từ đối với các bạn đồng phạm hạnh, dù trước mặt hay sau lưng, thì các Tỳ Kheo chắc chắn sẽ hưng thịnh, không suy vong. ",
  "dn16:1.11.7": "Này các Tỳ Kheo, chừng nào các Tỳ Kheo còn đối với những lợi lộc đúng pháp thu được đúng pháp, dù chỉ là một ít thức ăn trong bình bát, cũng không thọ dụng riêng mà chia sẻ công bằng với các bạn đồng phạm hạnh có giới đức, thì các Tỳ Kheo chắc chắn sẽ hưng thịnh, không suy vong. ",
  "dn16:1.11.8": "Này các Tỳ Kheo, chừng nào các Tỳ Kheo còn sống với các bạn đồng phạm hạnh, dù trước mặt hay sau lưng, đồng giữ các giới không khuyết, không thủng, không lốm đốm, không tỳ vết, đem lại tự do, được người trí tán thán, không bị chấp thủ, đưa đến thiền định, thì các Tỳ Kheo chắc chắn sẽ hưng thịnh, không suy vong. ",
  "dn16:1.11.9": "Này các Tỳ Kheo, chừng nào các Tỳ Kheo còn sống với các bạn đồng phạm hạnh, dù trước mặt hay sau lưng, đồng giữ chánh kiến thuộc bậc Thánh, đưa đến giải thoát, dẫn người thực hành đến sự đoạn tận khổ đau một cách chân chánh, thì các Tỳ Kheo chắc chắn sẽ hưng thịnh, không suy vong. ",
  "dn16:1.11.10": "Này các Tỳ Kheo, chừng nào sáu pháp bất thối này còn được duy trì trong các Tỳ Kheo, chừng nào các Tỳ Kheo còn tuân giữ sáu pháp bất thối này, thì các Tỳ Kheo chắc chắn sẽ hưng thịnh, không suy vong.\" ",
  "dn16:1.11.11": "(…) ",
  "dn16:1.12.1": "Tại đó, khi trú tại thành Vương Xá trên núi Linh Thứu, Đức Thế Tôn thường xuyên thuyết pháp cho các Tỳ Kheo như sau: ",
  "dn16:1.12.2": "\"Đây là giới, đây là định, đây là tuệ. ",
  "dn16:1.12.3": "Định được tu tập bằng giới sẽ đem lại quả lớn, lợi ích lớn. ",
  "dn16:1.12.4": "Tuệ được tu tập bằng định sẽ đem lại quả lớn, lợi ích lớn. ",
  "dn16:1.12.5": "Tâm được tu tập bằng tuệ sẽ hoàn toàn giải thoát khỏi các lậu hoặc, đó là—",
  "dn16:1.12.6": "dục lậu, hữu lậu, vô minh lậu.\" ",
  "dn16:1.13.1": "Rồi sau khi trú tại thành Vương Xá một thời gian vừa ý, Đức Thế Tôn gọi Tôn giả Ānanda: ",
  "dn16:1.13.2": "\"Này Ānanda, chúng ta hãy đi đến Ambalaṭṭhikā.\" ",
  "dn16:1.13.3": "\"Thưa vâng, bạch Thế Tôn\", Tôn giả Ānanda vâng lời Đức Thế Tôn. ",
  "dn16:1.13.4": "Rồi Đức Thế Tôn cùng với đại chúng Tỳ Kheo đi đến Ambalaṭṭhikā. ",
  "dn16:1.14.1": "Tại đó, Đức Thế Tôn trú tại nhà nghỉ của nhà vua ở Ambalaṭṭhikā. ",
  "dn16:1.14.2": "Tại đó, khi trú tại nhà nghỉ của nhà vua ở Ambalaṭṭhikā, Đức Thế Tôn thường xuyên thuyết pháp cho các Tỳ Kheo như sau: ",
  "dn16:1.14.3": "\"Đây là giới, đây là định, đây là tuệ. ",
  "dn16:1.14.4": "Định được tu tập bằng giới sẽ đem lại quả lớn, lợi ích lớn. ",
  "dn16:1.14.5": "Tuệ được tu tập bằng định sẽ đem lại quả lớn, lợi ích lớn. ",
  "dn16:1.14.6": "Tâm được tu tập bằng tuệ sẽ hoàn toàn giải thoát khỏi các lậu hoặc, đó là—",
  "dn16:1.14.7": "dục lậu, hữu lậu, vô minh lậu.\" ",
  "dn16:1.15.1": "Rồi sau khi trú tại Ambalaṭṭhikā một thời gian vừa ý, Đức Thế Tôn gọi Tôn giả Ānanda: ",
  "dn16:1.15.2": "\"Này Ānanda, chúng ta hãy đi đến Nāḷandā.\" ",
  "dn16:1.15.3": "\"Thưa vâng, bạch Thế Tôn\", Tôn giả Ānanda vâng lời Đức Thế Tôn. ",
  "dn16:1.15.4": "Rồi Đức Thế Tôn cùng với đại chúng Tỳ Kheo đi đến Nāḷandā, ",
  "dn16:1.15.5": "và tại Nāḷandā, Đức Thế Tôn trú trong rừng xoài Pāvārika. ",
  "dn16:1.16.0": "4. Tiếng Rống Sư Tử của Tôn giả Xá-lợi-phất ",
  "dn16:1.16.1": "Rồi Tôn giả Xá-lợi-phất đi đến chỗ Đức Thế Tôn; đến nơi, đảnh lễ Đức Thế Tôn rồi ngồi sang một bên. Ngồi sang một bên, Tôn giả Xá-lợi-phất bạch Đức Thế Tôn: ",
  "dn16:1.16.2": "\"Bạch Thế Tôn, con có lòng tin tuyệt đối nơi Đức Thế Tôn như sau: ",
  "dn16:1.16.3": "Không có, chưa từng có, và sẽ không có một sa-môn hay bà-la-môn nào khác có trí tuệ giác ngộ cao hơn Đức Thế Tôn.\" ",
  "dn16:1.16.4": "\"Này Xá-lợi-phất, ngươi đã nói lời vĩ đại, lời khẳng định, lời tiếng rống sư tử: ",
  "dn16:1.16.5": "'Bạch Thế Tôn, con có lòng tin tuyệt đối nơi Đức Thế Tôn như sau: ",
  "dn16:1.16.6": "Không có, chưa từng có, và sẽ không có một sa-môn hay bà-la-môn nào khác có trí tuệ giác ngộ cao hơn Đức Thế Tôn.' ",
  "dn16:1.16.7": "Này Xá-lợi-phất, vậy ngươi có dùng tâm của mình mà biết được tâm của tất cả chư Phật, bậc A-la-hán, Chánh Đẳng Giác trong quá khứ, rằng: ",
  "dn16:1.16.8": "'Các Đức Thế Tôn ấy có giới như vậy, có pháp như vậy, có trí tuệ như vậy, có cách sống như vậy, có sự giải thoát như vậy' không?\" ",
  "dn16:1.16.9": "\"Bạch Thế Tôn, không được.\" ",
  "dn16:1.16.10": "\"Này Xá-lợi-phất, vậy ngươi có dùng tâm của mình mà biết được tâm của tất cả chư Phật, bậc A-la-hán, Chánh Đẳng Giác trong tương lai, rằng: ",
  "dn16:1.16.11": "'Các Đức Thế Tôn ấy sẽ có giới như vậy, sẽ có pháp như vậy, sẽ có trí tuệ như vậy, sẽ có cách sống như vậy, sẽ có sự giải thoát như vậy' không?\" ",
  "dn16:1.16.12": "\"Bạch Thế Tôn, không được.\" ",
  "dn16:1.16.13": "\"Này Xá-lợi-phất, vậy ngươi có dùng tâm của mình mà biết được tâm của Ta, bậc A-la-hán, Chánh Đẳng Giác trong hiện tại, rằng: ",
  "dn16:1.16.14": "'Đức Thế Tôn có giới như vậy, có pháp như vậy, có trí tuệ như vậy, có cách sống như vậy, có sự giải thoát như vậy' không?\" ",
  "dn16:1.16.15": "\"Bạch Thế Tôn, không được.\" ",
  "dn16:1.16.16": "\"Như vậy, này Xá-lợi-phất, ngươi không có trí biết tâm người khác đối với chư Phật, bậc A-la-hán, Chánh Đẳng Giác trong quá khứ, tương lai, hiện tại. ",
  "dn16:1.16.17": "Vậy sao ngươi lại nói lời vĩ đại, lời khẳng định, lời tiếng rống sư tử như vậy: ",
  "dn16:1.16.18": "'Bạch Thế Tôn, con có lòng tin tuyệt đối nơi Đức Thế Tôn như sau: Không có, chưa từng có, và sẽ không có một sa-môn hay bà-la-môn nào khác có trí tuệ giác ngộ cao hơn Đức Thế Tôn'?\" ",
  "dn16:1.17.1": "\"Bạch Thế Tôn, quả thật con không có trí biết tâm người khác đối với chư Phật, bậc A-la-hán, Chánh Đẳng Giác trong quá khứ, tương lai, hiện tại, ",
  "dn16:1.17.2": "nhưng con biết được qua sự suy luận về pháp. ",
  "dn16:1.17.3": "Bạch Thế Tôn, ví như thành trì biên địa của nhà vua có nền móng vững chắc, tường thành và cổng thành kiên cố, chỉ có một cửa ra vào, ",
  "dn16:1.17.4": "tại đó có người gác cửa thông minh, lanh lợi, sáng suốt, ngăn chặn người lạ, cho người quen vào. ",
  "dn16:1.17.5": "Khi đi quanh thành theo con đường vòng quanh, người ấy không thấy khe hở nào trong tường thành, không thấy lỗ hở nào trong tường thành, thậm chí không có một lỗ nhỏ đủ cho mèo chui qua. ",
  "dn16:1.17.6": "Người ấy nghĩ: ",
  "dn16:1.17.7": "'Bất cứ sinh vật lớn nào ra vào thành này đều chỉ có thể ra vào qua cửa này mà thôi.' ",
  "dn16:1.17.8": "Cũng vậy, bạch Thế Tôn, con biết được qua sự suy luận về pháp như sau: ",
  "dn16:1.17.9": "'Bạch Thế Tôn, tất cả chư Phật, bậc A-la-hán, Chánh Đẳng Giác trong quá khứ đều đã đoạn trừ năm triền cái làm ô nhiễm tâm và làm yếu trí tuệ, đã khéo an trú tâm vào bốn niệm xứ, đã tu tập bảy giác chi đúng như thật, rồi chứng đắc Vô Thượng Chánh Đẳng Giác. ",
  "dn16:1.17.10": "Bạch Thế Tôn, tất cả chư Phật, bậc A-la-hán, Chánh Đẳng Giác trong tương lai cũng sẽ đoạn trừ năm triền cái làm ô nhiễm tâm và làm yếu trí tuệ, sẽ khéo an trú tâm vào bốn niệm xứ, sẽ tu tập bảy giác chi đúng như thật, rồi chứng đắc Vô Thượng Chánh Đẳng Giác. ",
  "dn16:1.17.11": "Bạch Thế Tôn, trong hiện tại, Đức Thế Tôn là bậc A-la-hán, Chánh Đẳng Giác cũng đã đoạn trừ năm triền cái làm ô nhiễm tâm và làm yếu trí tuệ, đã khéo an trú tâm vào bốn niệm xứ, đã tu tập bảy giác chi đúng như thật, rồi chứng đắc Vô Thượng Chánh Đẳng Giác.'\" ",
  "dn16:1.18.1": "Tại đó, khi trú ở Nāḷandā trong rừng xoài Pāvārika, Đức Thế Tôn thường xuyên thuyết pháp cho các Tỳ Kheo như sau: ",
  "dn16:1.18.2": "\"Đây là giới, đây là định, đây là tuệ. ",
  "dn16:1.18.3": "Định được tu tập bằng giới sẽ đem lại quả lớn, lợi ích lớn. ",
  "dn16:1.18.4": "Tuệ được tu tập bằng định sẽ đem lại quả lớn, lợi ích lớn. ",
  "dn16:1.18.5": "Tâm được tu tập bằng tuệ sẽ hoàn toàn giải thoát khỏi các lậu hoặc, đó là—",
  "dn16:1.18.6": "dục lậu, hữu lậu, vô minh lậu.\" ",
  "dn16:1.19.0": "5. Tai Hại của Người Phá Giới ",
  "dn16:1.19.1": "Rồi sau khi trú tại Nāḷandā một thời gian vừa ý, Đức Thế Tôn gọi Tôn giả Ānanda: ",
  "dn16:1.19.2": "\"Này Ānanda, chúng ta hãy đi đến làng Pāṭaligāma.\" ",
  "dn16:1.19.3": "\"Thưa vâng, bạch Thế Tôn\", Tôn giả Ānanda vâng lời Đức Thế Tôn. ",
  "dn16:1.19.4": "Rồi Đức Thế Tôn cùng với đại chúng Tỳ Kheo đi đến làng Pāṭaligāma. ",
  "dn16:1.20.1": "Các cư sĩ ở Pāṭaligāma nghe tin: \"Đức Thế Tôn đã đến làng Pāṭaligāma.\" ",
  "dn16:1.20.2": "Rồi các cư sĩ ở Pāṭaligāma đi đến chỗ Đức Thế Tôn; đến nơi, đảnh lễ Đức Thế Tôn rồi ngồi sang một bên. Ngồi sang một bên, các cư sĩ ở Pāṭaligāma bạch Đức Thế Tôn: ",
  "dn16:1.20.3": "\"Bạch Thế Tôn, xin Đức Thế Tôn hãy nhận lời đến nhà khách của chúng con.\" ",
  "dn16:1.20.4": "Đức Thế Tôn im lặng nhận lời. ",
  "dn16:1.21.1": "Biết Đức Thế Tôn đã nhận lời, các cư sĩ ở Pāṭaligāma từ chỗ ngồi đứng dậy, đảnh lễ Đức Thế Tôn rồi đi nhiễu bên phải và trở về nhà khách. Về đến nhà khách, họ trải kín tấm thảm trên sàn, sắp đặt chỗ ngồi, đặt bình nước, thắp đèn dầu, rồi đi đến chỗ Đức Thế Tôn. Đến nơi, đảnh lễ Đức Thế Tôn rồi đứng sang một bên. Đứng sang một bên, các cư sĩ ở Pāṭaligāma bạch Đức Thế Tôn: ",
  "dn16:1.21.2": "\"Bạch Thế Tôn, nhà khách đã được trải thảm đầy đủ, chỗ ngồi đã sắp đặt xong, bình nước đã đặt sẵn, đèn dầu đã thắp lên. ",
  "dn16:1.21.3": "Bây giờ xin Đức Thế Tôn làm gì Ngài thấy đúng thời.\" ",
  "dn16:1.22.1": "Rồi vào buổi chiều, Đức Thế Tôn đắp y, cầm y bát, cùng với chúng Tỳ Kheo đi đến nhà khách; đến nơi, rửa chân rồi vào nhà khách, ngồi tựa cột giữa, mặt hướng về phương đông. ",
  "dn16:1.22.2": "Chúng Tỳ Kheo cũng rửa chân rồi vào nhà khách, ngồi tựa tường phía tây, mặt hướng về phương đông, lấy Đức Thế Tôn làm trung tâm. ",
  "dn16:1.22.3": "Các cư sĩ ở Pāṭaligāma cũng rửa chân rồi vào nhà khách, ngồi tựa tường phía đông, mặt hướng về phương tây, lấy Đức Thế Tôn làm trung tâm. ",
  "dn16:1.22.4": "(…) ",
  "dn16:1.23.1": "Rồi Đức Thế Tôn nói với các cư sĩ ở Pāṭaligāma: ",
  "dn16:1.23.2": "\"Này các gia chủ, có năm tai hại cho người phá giới do sự phá giới. ",
  "dn16:1.23.3": "Năm đó là gì? ",
  "dn16:1.23.4": "Này các gia chủ, ở đây, người phá giới, do phá giới, vì buông lung phóng dật mà bị tổn thất tài sản lớn. ",
  "dn16:1.23.5": "Đây là tai hại thứ nhất cho người phá giới do sự phá giới. ",
  "dn16:1.23.6": "Lại nữa, này các gia chủ, người phá giới, do phá giới, tiếng xấu đồn xa. ",
  "dn16:1.23.7": "Đây là tai hại thứ hai cho người phá giới do sự phá giới. ",
  "dn16:1.23.8": "Lại nữa, này các gia chủ, người phá giới, do phá giới, khi đi vào bất cứ hội chúng nào—dù là hội chúng sát-đế-lỵ, hội chúng bà-la-môn, hội chúng gia chủ, hay hội chúng sa-môn—thì đi vào với tâm e dè, sợ sệt, bối rối. ",
  "dn16:1.23.9": "Đây là tai hại thứ ba cho người phá giới do sự phá giới. ",
  "dn16:1.23.10": "Lại nữa, này các gia chủ, người phá giới, do phá giới, khi lâm chung bị mê mờ. ",
  "dn16:1.23.11": "Đây là tai hại thứ tư cho người phá giới do sự phá giới. ",
  "dn16:1.23.12": "Lại nữa, này các gia chủ, người phá giới, do phá giới, sau khi thân tan rã, sau khi chết, sẽ sanh vào cõi dữ, ác thú, đọa xứ, địa ngục. ",
  "dn16:1.23.13": "Đây là tai hại thứ năm cho người phá giới do sự phá giới. ",
  "dn16:1.23.14": "Này các gia chủ, đó là năm tai hại cho người phá giới do sự phá giới. ",
  "dn16:1.24.0": "6. Lợi Ích của Người Giữ Giới ",
  "dn16:1.24.1": "Này các gia chủ, có năm lợi ích cho người giữ giới do sự giữ giới. ",
  "dn16:1.24.2": "Năm đó là gì? ",
  "dn16:1.24.3": "Này các gia chủ, ở đây, người giữ giới, do giữ giới, vì không buông lung phóng dật mà đạt được khối tài sản lớn. ",
  "dn16:1.24.4": "Đây là lợi ích thứ nhất cho người giữ giới do sự giữ giới. ",
  "dn16:1.24.5": "Lại nữa, này các gia chủ, người giữ giới, do giữ giới, tiếng tốt đồn xa. ",
  "dn16:1.24.6": "Đây là lợi ích thứ hai cho người giữ giới do sự giữ giới. ",
  "dn16:1.24.7": "Lại nữa, này các gia chủ, người giữ giới, do giữ giới, khi đi vào bất cứ hội chúng nào—dù là hội chúng sát-đế-lỵ, hội chúng bà-la-môn, hội chúng gia chủ, hay hội chúng sa-môn—thì đi vào với tâm tự tin, không bối rối. ",
  "dn16:1.24.8": "Đây là lợi ích thứ ba cho người giữ giới do sự giữ giới. ",
  "dn16:1.24.9": "Lại nữa, này các gia chủ, người giữ giới, do giữ giới, khi lâm chung tâm không mê mờ. ",
  "dn16:1.24.10": "Đây là lợi ích thứ tư cho người giữ giới do sự giữ giới. ",
  "dn16:1.24.11": "Lại nữa, này các gia chủ, người giữ giới, do giữ giới, sau khi thân tan rã, sau khi chết, sẽ sanh vào cõi thiện, cõi trời. ",
  "dn16:1.24.12": "Đây là lợi ích thứ năm cho người giữ giới do sự giữ giới. ",
  "dn16:1.24.13": "Này các gia chủ, đó là năm lợi ích cho người giữ giới do sự giữ giới.\" ",
  "dn16:1.25.1": "Rồi Đức Thế Tôn trong phần lớn đêm khai thị, khuyến khích, khích lệ, làm cho các cư sĩ ở Pāṭaligāma hoan hỷ với lời pháp thoại, rồi cho họ cáo lui: ",
  "dn16:1.25.2": "\"Này các gia chủ, đêm đã khuya rồi. Nay các ông hãy làm những gì các ông thấy đúng thời.\" ",
  "dn16:1.25.3": "\"Thưa vâng, bạch Thế Tôn\", các cư sĩ ở Pāṭaligāma vâng lời Đức Thế Tôn, từ chỗ ngồi đứng dậy, đảnh lễ Đức Thế Tôn, nhiễu bên phải rồi ra về. ",
  "dn16:1.25.4": "Rồi không lâu sau khi các cư sĩ ở Pāṭaligāma ra về, Đức Thế Tôn đi vào phòng vắng vẻ. ",
  "dn16:1.26.0": "7. Xây Dựng Thành Pāṭaliputta ",
  "dn16:1.26.1": "Lúc bấy giờ, đại thần Sunidha và Vassakāra của nước Ma-kiệt-đà đang xây dựng thành trì tại Pāṭaligāma để chống lại dân Vajji. ",
  "dn16:1.26.2": "Lúc bấy giờ, có rất nhiều chư thiên, hằng ngàn vị, đang chiếm giữ các khu đất tại Pāṭaligāma. ",
  "dn16:1.26.3": "Tại chỗ nào có các chư thiên uy lực lớn chiếm giữ đất, thì tâm của các vua và đại thần uy lực lớn hướng đến việc xây dựng nhà cửa tại đó. ",
  "dn16:1.27.1": "Tại chỗ nào có các chư thiên uy lực trung bình chiếm giữ đất, thì tâm của các vua và đại thần uy lực trung bình hướng đến việc xây dựng nhà cửa tại đó. ",
  "dn16:1.27.2": "Tại chỗ nào có các chư thiên uy lực thấp chiếm giữ đất, thì tâm của các vua và đại thần uy lực thấp hướng đến việc xây dựng nhà cửa tại đó. ",
  "dn16:1.27.3": "Đức Thế Tôn dùng thiên nhãn thanh tịnh, siêu nhân, thấy các chư thiên hằng ngàn vị đang chiếm giữ các khu đất tại Pāṭaligāma. ",
  "dn16:1.27.4": "Rồi Đức Thế Tôn thức dậy vào lúc tảng sáng, gọi Tôn giả Ānanda: ",
  "dn16:1.27.5": "\"Này Ānanda, ai đang xây dựng thành trì tại Pāṭaligāma vậy?\" ",
  "dn16:1.27.6": "\"Bạch Thế Tôn, đại thần Sunidha và Vassakāra của nước Ma-kiệt-đà đang xây dựng thành trì tại Pāṭaligāma để chống lại dân Vajji.\" ",
  "dn16:1.28.1": "\"Này Ānanda, giống như đã bàn bạc với chư thiên cõi Ba Mươi Ba; ",
  "dn16:1.28.2": "cũng vậy, này Ānanda, đại thần Sunidha và Vassakāra của nước Ma-kiệt-đà đang xây dựng thành trì tại Pāṭaligāma để chống lại dân Vajji. ",
  "dn16:1.28.3": "Này Ānanda, Ta đã dùng thiên nhãn thanh tịnh, siêu nhân, thấy rất nhiều chư thiên hằng ngàn vị đang chiếm giữ các khu đất tại Pāṭaligāma. ",
  "dn16:1.28.4": "Này Ānanda, tại chỗ nào có các chư thiên uy lực lớn chiếm giữ đất, thì tâm của các vua và đại thần uy lực lớn hướng đến việc xây dựng nhà cửa tại đó. ",
  "dn16:1.28.5": "Tại chỗ nào có các chư thiên uy lực trung bình chiếm giữ đất, thì tâm của các vua và đại thần uy lực trung bình hướng đến việc xây dựng nhà cửa tại đó. ",
  "dn16:1.28.6": "Tại chỗ nào có các chư thiên uy lực thấp chiếm giữ đất, thì tâm của các vua và đại thần uy lực thấp hướng đến việc xây dựng nhà cửa tại đó. ",
  "dn16:1.28.7": "Này Ānanda, trong phạm vi các vùng đất văn minh và con đường thương mại, nơi đây sẽ là thành phố đứng đầu, đó là Pāṭaliputta, nơi hàng hóa được tập trung và phân phối. ",
  "dn16:1.28.8": "Này Ānanda, Pāṭaliputta sẽ có ba tai họa—",
  "dn16:1.28.9": "hoặc từ lửa, hoặc từ nước, hoặc từ sự chia rẽ nội bộ.\" ",
  "dn16:1.29.1": "Rồi các đại thần Sunidha và Vassakāra của nước Ma-kiệt-đà đi đến chỗ Đức Thế Tôn; đến nơi, chào hỏi Đức Thế Tôn, ",
  "dn16:1.29.2": "sau khi nói lời chào hỏi thân tình, đáng ghi nhớ, họ đứng sang một bên. Đứng sang một bên, các đại thần Sunidha và Vassakāra của nước Ma-kiệt-đà bạch Đức Thế Tôn: ",
  "dn16:1.29.3": "\"Xin Tôn giả Gotama cùng chúng Tỳ Kheo nhận lời mời thọ trai hôm nay của chúng con.\" ",
  "dn16:1.29.4": "Đức Thế Tôn im lặng nhận lời. ",
  "dn16:1.30.1": "Biết Đức Thế Tôn đã nhận lời, các đại thần Sunidha và Vassakāra của nước Ma-kiệt-đà trở về chỗ ở của mình; đến nơi, cho chuẩn bị các món ăn ngon, rồi báo giờ đến Đức Thế Tôn: ",
  "dn16:1.30.2": "\"Đã đến giờ, thưa Tôn giả Gotama, cơm đã sẵn sàng.\" ",
  "dn16:1.30.3": "Rồi vào buổi sáng, Đức Thế Tôn đắp y, cầm y bát, cùng với chúng Tỳ Kheo đi đến chỗ ở của các đại thần Sunidha và Vassakāra của nước Ma-kiệt-đà; đến nơi, ngồi xuống chỗ đã soạn sẵn. ",
  "dn16:1.30.4": "Rồi các đại thần Sunidha và Vassakāra của nước Ma-kiệt-đà tự tay dâng cúng các món ăn ngon cho chúng Tỳ Kheo do Đức Phật dẫn đầu. ",
  "dn16:1.30.5": "Sau khi Đức Thế Tôn thọ trai xong, tay rời khỏi bát, các đại thần Sunidha và Vassakāra của nước Ma-kiệt-đà lấy chỗ ngồi thấp hơn và ngồi sang một bên. ",
  "dn16:1.31.1": "Khi các đại thần Sunidha và Vassakāra của nước Ma-kiệt-đà đã ngồi sang một bên, Đức Thế Tôn tùy hỷ bằng những bài kệ này: ",
  "dn16:1.31.2": "\"Tại nơi nào người hiền trí, ",
  "dn16:1.31.3": "Chọn làm chỗ ở cư trú; ",
  "dn16:1.31.4": "Cúng dường các bậc giữ giới, ",
  "dn16:1.31.5": "Các vị phạm hạnh tự chế. ",
  "dn16:1.31.6": "Các chư thiên có ở đó, ",
  "dn16:1.31.7": "Hãy hồi hướng công đức; ",
  "dn16:1.31.8": "Được cúng dường, các vị cúng dường lại, ",
  "dn16:1.31.9": "Được tôn kính, các vị tôn kính lại. ",
  "dn16:1.31.10": "Từ đó thương xót người này, ",
  "dn16:1.31.11": "Như mẹ thương con ruột; ",
  "dn16:1.31.12": "Người được chư thiên thương xót, ",
  "dn16:1.31.13": "Luôn thấy điều tốt lành.\" ",
  "dn16:1.31.14": "Rồi sau khi tùy hỷ các đại thần Sunidha và Vassakāra của nước Ma-kiệt-đà bằng những bài kệ này, Đức Thế Tôn từ chỗ ngồi đứng dậy, ra đi. ",
  "dn16:1.32.1": "Lúc bấy giờ, các đại thần Sunidha và Vassakāra của nước Ma-kiệt-đà đi theo sau Đức Thế Tôn, nghĩ rằng: ",
  "dn16:1.32.2": "\"Hôm nay, sa-môn Gotama đi ra bằng cổng nào, cổng ấy sẽ được gọi là Cổng Gotama. ",
  "dn16:1.32.3": "Vị ấy đi qua sông Hằng bằng bến nào, bến ấy sẽ được gọi là Bến Gotama.\" ",
  "dn16:1.32.4": "Rồi Đức Thế Tôn đi ra bằng cổng nào, cổng ấy trở thành Cổng Gotama. ",
  "dn16:1.32.5": "Rồi Đức Thế Tôn đi đến sông Hằng. ",
  "dn16:1.33.1": "Lúc bấy giờ, sông Hằng đang nước đầy ngang bờ, quạ có thể uống được. ",
  "dn16:1.33.2": "Có người đi tìm thuyền, có người đi tìm bè, có người buộc bè để qua bờ bên kia. ",
  "dn16:1.33.3": "Rồi Đức Thế Tôn—giống như một người lực sĩ duỗi cánh tay co lại hoặc co cánh tay duỗi ra, cũng như vậy—biến mất ở bờ bên này sông Hằng và xuất hiện ở bờ bên kia cùng với chúng Tỳ Kheo. ",
  "dn16:1.34.1": "Đức Thế Tôn thấy những người kia, có người đi tìm thuyền, có người đi tìm bè, có người buộc bè để qua bờ bên kia. ",
  "dn16:1.34.2": "Thấu hiểu ý nghĩa này, vào lúc đó, Đức Thế Tôn thốt lên lời cảm hứng như sau: ",
  "dn16:1.34.3": "\"Những ai vượt qua biển, hồ, ",
  "dn16:1.34.4": "Làm cầu mà bỏ chỗ trũng; ",
  "dn16:1.34.5": "Trong khi người ta buộc bè, ",
  "dn16:1.34.6": "Bậc trí đã vượt qua bờ.\" ",
  "dn16:1.34.7": "Hết phần tụng đọc thứ nhất. ",
  "dn16:2.1.0": "8. Bài Pháp Về Tứ Thánh Đế ",
  "dn16:2.1.1": "Rồi Đức Thế Tôn gọi Tôn giả Ānanda: ",
  "dn16:2.1.2": "\"Này Ānanda, chúng ta hãy đi đến làng Koṭigāma.\" ",
  "dn16:2.1.3": "\"Thưa vâng, bạch Thế Tôn\", Tôn giả Ānanda vâng lời Đức Thế Tôn. ",
  "dn16:2.1.4": "Rồi Đức Thế Tôn cùng với đại chúng Tỳ Kheo đi đến làng Koṭigāma. ",
  "dn16:2.1.5": "Tại đó, Đức Thế Tôn trú ở làng Koṭigāma. ",
  "dn16:2.2.1": "Tại đó, Đức Thế Tôn gọi các Tỳ Kheo: ",
  "dn16:2.2.2": "\"Này các Tỳ Kheo, do không giác ngộ, không thâm nhập Bốn Thánh Đế, mà Ta và các ông đã phải lưu chuyển, luân hồi trong vòng sinh tử lâu dài như vậy. ",
  "dn16:2.2.3": "Bốn Thánh Đế đó là gì? ",
  "dn16:2.2.4": "Này các Tỳ Kheo, do không giác ngộ, không thâm nhập Khổ Thánh Đế, mà Ta và các ông đã phải lưu chuyển, luân hồi trong vòng sinh tử lâu dài như vậy. ",
  "dn16:2.2.5": "Này các Tỳ Kheo, do không giác ngộ, không thâm nhập Khổ Tập Thánh Đế, mà Ta và các ông đã phải lưu chuyển, luân hồi trong vòng sinh tử lâu dài như vậy. ",
  "dn16:2.2.6": "Này các Tỳ Kheo, do không giác ngộ, không thâm nhập Khổ Diệt Thánh Đế, mà Ta và các ông đã phải lưu chuyển, luân hồi trong vòng sinh tử lâu dài như vậy. ",
  "dn16:2.2.7": "Này các Tỳ Kheo, do không giác ngộ, không thâm nhập Khổ Diệt Đạo Thánh Đế, mà Ta và các ông đã phải lưu chuyển, luân hồi trong vòng sinh tử lâu dài như vậy. ",
  "dn16:2.2.8": "Này các Tỳ Kheo, nay Khổ Thánh Đế đã được giác ngộ, thâm nhập; Khổ Tập Thánh Đế đã được giác ngộ, thâm nhập; Khổ Diệt Thánh Đế đã được giác ngộ, thâm nhập; Khổ Diệt Đạo Thánh Đế đã được giác ngộ, thâm nhập; hữu ái đã đoạn, dây dẫn đến tái sanh đã tận, không còn tái sanh nữa.\" ",
  "dn16:2.3.1": "Đức Thế Tôn nói như vậy. ",
  "dn16:2.3.2": "Sau khi nói như vậy, bậc Thiện Thệ, bậc Đạo Sư còn nói thêm: ",
  "dn16:2.3.3": "\"Vì không thấy như thật, ",
  "dn16:2.3.4": "Bốn Thánh Đế chơn chánh; ",
  "dn16:2.3.5": "Phải lưu chuyển luân hồi, ",
  "dn16:2.3.6": "Trong vô vàn kiếp sống. ",
  "dn16:2.3.7": "Nay các Đế đã thấy, ",
  "dn16:2.3.8": "Dây tái sanh đã đoạn; ",
  "dn16:2.3.9": "Gốc khổ đã bật tận, ",
  "dn16:2.3.10": "Không còn tái sanh nữa.\" ",
  "dn16:2.4.1": "Tại đó, khi trú ở làng Koṭigāma, Đức Thế Tôn thường xuyên thuyết pháp cho các Tỳ Kheo như sau: ",
  "dn16:2.4.2": "\"Đây là giới, đây là định, đây là tuệ. ",
  "dn16:2.4.3": "Định được tu tập bằng giới sẽ đem lại quả lớn, lợi ích lớn. ",
  "dn16:2.4.4": "Tuệ được tu tập bằng định sẽ đem lại quả lớn, lợi ích lớn. ",
  "dn16:2.4.5": "Tâm được tu tập bằng tuệ sẽ hoàn toàn giải thoát khỏi các lậu hoặc, đó là—",
  "dn16:2.4.6": "dục lậu, hữu lậu, vô minh lậu.\" ",
  "dn16:2.5.0": "9. Pháp Không Trở Lui và Hướng Đến Giác Ngộ ",
  "dn16:2.5.1": "Rồi sau khi trú tại làng Koṭigāma một thời gian vừa ý, Đức Thế Tôn gọi Tôn giả Ānanda: ",
  "dn16:2.5.2": "\"Này Ānanda, chúng ta hãy đi đến Nātikā.\" ",
  "dn16:2.5.3": "\"Thưa vâng, bạch Thế Tôn\", Tôn giả Ānanda vâng lời Đức Thế Tôn. ",
  "dn16:2.5.4": "Rồi Đức Thế Tôn cùng với đại chúng Tỳ Kheo đi đến Nātikā. ",
  "dn16:2.5.5": "Tại đó, Đức Thế Tôn trú ở Nātikā, trong nhà gạch. ",
  "dn16:2.6.1": "Rồi Tôn giả Ānanda đi đến chỗ Đức Thế Tôn; đến nơi, đảnh lễ Đức Thế Tôn rồi ngồi sang một bên. Ngồi sang một bên, Tôn giả Ānanda bạch Đức Thế Tôn: ",
  "dn16:2.6.2": "\"Bạch Thế Tôn, Tỳ Kheo tên Sāḷha đã qua đời tại Nātikā, không biết vị ấy tái sanh cõi nào, tương lai thế nào? ",
  "dn16:2.6.3": "Bạch Thế Tôn, Tỳ Kheo ni tên Nandā đã qua đời tại Nātikā, không biết vị ấy tái sanh cõi nào, tương lai thế nào? ",
  "dn16:2.6.4": "Bạch Thế Tôn, cư sĩ tên Sudatta đã qua đời tại Nātikā, không biết vị ấy tái sanh cõi nào, tương lai thế nào? ",
  "dn16:2.6.5": "Bạch Thế Tôn, nữ cư sĩ tên Sujātā đã qua đời tại Nātikā, không biết vị ấy tái sanh cõi nào, tương lai thế nào? ",
  "dn16:2.6.6": "Bạch Thế Tôn, cư sĩ tên Kukkuṭa đã qua đời tại Nātikā, không biết vị ấy tái sanh cõi nào, tương lai thế nào? ",
  "dn16:2.6.7": "Bạch Thế Tôn, cư sĩ tên Kāḷimba …vân vân… ",
  "dn16:2.6.8": "cư sĩ tên Nikaṭa … ",
  "dn16:2.6.9": "cư sĩ tên Kaṭissaha … ",
  "dn16:2.6.10": "cư sĩ tên Tuṭṭha … ",
  "dn16:2.6.11": "cư sĩ tên Santuṭṭha … ",
  "dn16:2.6.12": "cư sĩ tên Bhadda … ",
  "dn16:2.6.13": "Bạch Thế Tôn, cư sĩ tên Subhadda đã qua đời tại Nātikā, không biết vị ấy tái sanh cõi nào, tương lai thế nào?\" ",
  "dn16:2.7.1": "\"Này Ānanda, Tỳ Kheo Sāḷha đã đoạn trừ các lậu hoặc, ngay trong hiện tại tự mình chứng ngộ với thắng trí, đã chứng và trú tâm giải thoát, tuệ giải thoát vô lậu. ",
  "dn16:2.7.2": "Này Ānanda, Tỳ Kheo ni Nandā đã đoạn trừ năm hạ phần kiết sử, được hóa sanh, nhập Niết Bàn tại cõi đó, không còn trở lại cõi này. ",
  "dn16:2.7.3": "Này Ānanda, cư sĩ Sudatta đã đoạn trừ ba kiết sử, làm nhẹ tham sân si, là bậc Nhất Lai, chỉ còn trở lại cõi này một lần nữa là chấm dứt khổ đau. ",
  "dn16:2.7.4": "Này Ānanda, nữ cư sĩ Sujātā đã đoạn trừ ba kiết sử, là bậc Dự Lưu, không còn rơi vào ác đạo, chắc chắn hướng đến giác ngộ. ",
  "dn16:2.7.5": "Này Ānanda, cư sĩ Kukkuṭa đã đoạn trừ năm hạ phần kiết sử, được hóa sanh, nhập Niết Bàn tại cõi đó, không còn trở lại cõi này. ",
  "dn16:2.7.6": "Này Ānanda, cư sĩ Kāḷimba …vân vân… ",
  "dn16:2.7.7": "cư sĩ Nikaṭa … ",
  "dn16:2.7.8": "cư sĩ Kaṭissaha … ",
  "dn16:2.7.9": "cư sĩ Tuṭṭha … ",
  "dn16:2.7.10": "cư sĩ Santuṭṭha … ",
  "dn16:2.7.11": "cư sĩ Bhadda … ",
  "dn16:2.7.12": "Này Ānanda, cư sĩ Subhadda đã đoạn trừ năm hạ phần kiết sử, được hóa sanh, nhập Niết Bàn tại cõi đó, không còn trở lại cõi này. ",
  "dn16:2.7.13": "Này Ānanda, hơn năm mươi cư sĩ tại Nātikā đã qua đời, đã đoạn trừ năm hạ phần kiết sử, được hóa sanh, nhập Niết Bàn tại cõi đó, không còn trở lại cõi này. ",
  "dn16:2.7.14": "Này Ānanda, hơn chín mươi cư sĩ tại Nātikā đã qua đời, đã đoạn trừ ba kiết sử, làm nhẹ tham sân si, là bậc Nhất Lai, chỉ còn trở lại cõi này một lần nữa là chấm dứt khổ đau. ",
  "dn16:2.7.15": "Này Ānanda, hơn năm trăm cư sĩ tại Nātikā đã qua đời, đã đoạn trừ ba kiết sử, là bậc Dự Lưu, không còn rơi vào ác đạo, chắc chắn hướng đến giác ngộ. ",
  "dn16:2.8.0": "10. Pháp Môn Kính Chiếu Pháp ",
  "dn16:2.8.1": "Này Ānanda, không có gì lạ khi một con người phải chết. ",
  "dn16:2.8.2": "Nếu mỗi khi có người chết mà các ông đều đến hỏi Ta về điều này, thì đó là điều phiền nhiễu cho Ta, này Ānanda. ",
  "dn16:2.8.3": "Vì vậy, này Ānanda, Ta sẽ giảng pháp môn gọi là 'Kính Chiếu Pháp', nhờ đó vị Thánh đệ tử nếu muốn có thể tự mình tuyên bố về mình rằng: ",
  "dn16:2.8.4": "'Ta đã hết sanh vào địa ngục, hết sanh làm súc sanh, hết sanh vào cõi ngạ quỷ, hết rơi vào các cõi dữ, ác thú, đọa xứ, ta là bậc Dự Lưu, không còn rơi vào ác đạo, chắc chắn hướng đến giác ngộ.' ",
  "dn16:2.9.1": "Và này Ānanda, pháp môn gọi là 'Kính Chiếu Pháp' ấy là gì, mà nhờ đó vị Thánh đệ tử nếu muốn có thể tự mình tuyên bố về mình rằng: ",
  "dn16:2.9.2": "'Ta đã hết sanh vào địa ngục, hết sanh làm súc sanh, hết sanh vào cõi ngạ quỷ, hết rơi vào các cõi dữ, ác thú, đọa xứ, ta là bậc Dự Lưu, không còn rơi vào ác đạo, chắc chắn hướng đến giác ngộ'? ",
  "dn16:2.9.3": "Này Ānanda, ở đây vị Thánh đệ tử có lòng tịnh tín bất động đối với Đức Phật: ",
  "dn16:2.9.4": "'Đây là Đức Thế Tôn, bậc A-la-hán, Chánh Đẳng Giác, Minh Hạnh Túc, Thiện Thệ, Thế Gian Giải, Vô Thượng Sĩ, Điều Ngự Trượng Phu, Thiên Nhân Sư, Phật, Thế Tôn.' ",
  "dn16:2.9.5": "Có lòng tịnh tín bất động đối với Pháp: ",
  "dn16:2.9.6": "'Pháp được Đức Thế Tôn khéo thuyết, thiết thực hiện tại, không chờ thời gian, đến để thấy, có tính hướng thượng, được người trí tự mình chứng hiểu.' ",
  "dn16:2.9.7": "Có lòng tịnh tín bất động đối với Tăng: ",
  "dn16:2.9.8": "'Tăng chúng đệ tử của Đức Thế Tôn là những vị khéo tu tập, tu tập chánh trực, tu tập đúng lý, tu tập chân chánh, tức là bốn đôi tám vị. Đây là Tăng chúng đệ tử của Đức Thế Tôn, xứng đáng được cúng dường, xứng đáng được đón tiếp, xứng đáng được hiến tặng, xứng đáng được chắp tay đảnh lễ, là ruộng phước vô thượng ở đời.' ",
  "dn16:2.9.9": "Có các giới được bậc Thánh quý mến, không khuyết, không thủng, không lốm đốm, không tỳ vết, đem lại tự do, được người trí tán thán, không bị chấp thủ, đưa đến thiền định. ",
  "dn16:2.9.10": "Này Ānanda, đây chính là pháp môn 'Kính Chiếu Pháp', nhờ đó vị Thánh đệ tử nếu muốn có thể tự mình tuyên bố về mình rằng: ",
  "dn16:2.9.11": "'Ta đã hết sanh vào địa ngục, hết sanh làm súc sanh, hết sanh vào cõi ngạ quỷ, hết rơi vào các cõi dữ, ác thú, đọa xứ, ta là bậc Dự Lưu, không còn rơi vào ác đạo, chắc chắn hướng đến giác ngộ.'\" ",
  "dn16:2.10.1": "Tại đó, khi trú ở Nātikā trong nhà gạch, Đức Thế Tôn thường xuyên thuyết pháp cho các Tỳ Kheo như sau: ",
  "dn16:2.10.2": "\"Đây là giới, đây là định, đây là tuệ. ",
  "dn16:2.10.3": "Định được tu tập bằng giới sẽ đem lại quả lớn, lợi ích lớn. ",
  "dn16:2.10.4": "Tuệ được tu tập bằng định sẽ đem lại quả lớn, lợi ích lớn. ",
  "dn16:2.10.5": "Tâm được tu tập bằng tuệ sẽ hoàn toàn giải thoát khỏi các lậu hoặc, đó là—",
  "dn16:2.10.6": "dục lậu, hữu lậu, vô minh lậu.\" ",
  "dn16:2.10.7": "(…) ",
  "dn16:2.11.1": "Rồi sau khi trú tại Nātikā một thời gian vừa ý, Đức Thế Tôn gọi Tôn giả Ānanda: ",
  "dn16:2.11.2": "\"Này Ānanda, chúng ta hãy đi đến Vesāli.\" ",
  "dn16:2.11.3": "\"Thưa vâng, bạch Thế Tôn\", Tôn giả Ānanda vâng lời Đức Thế Tôn. ",
  "dn16:2.11.4": "Rồi Đức Thế Tôn cùng với đại chúng Tỳ Kheo đi đến Vesāli. ",
  "dn16:2.11.5": "Tại đó, Đức Thế Tôn trú ở Vesāli, trong vườn xoài của Ambapāli. ",
  "dn16:2.12.1": "Tại đó, Đức Thế Tôn gọi các Tỳ Kheo: ",
  "dn16:2.12.2": "\"Này các Tỳ Kheo, Tỳ Kheo phải sống có chánh niệm và tỉnh giác, ",
  "dn16:2.12.3": "đây là lời giáo huấn của Ta cho các ông. ",
  "dn16:2.12.4": "Và này các Tỳ Kheo, thế nào là Tỳ Kheo có chánh niệm? ",
  "dn16:2.12.5": "Này các Tỳ Kheo, ở đây Tỳ Kheo sống quán thân trên thân, tinh cần, tỉnh giác, chánh niệm, nhiếp phục tham ưu ở đời. ",
  "dn16:2.12.6": "Quán cảm thọ trên các cảm thọ …vân vân… ",
  "dn16:2.12.7": "quán tâm trên tâm …vân vân… ",
  "dn16:2.12.8": "quán pháp trên các pháp, tinh cần, tỉnh giác, chánh niệm, nhiếp phục tham ưu ở đời. ",
  "dn16:2.12.9": "Này các Tỳ Kheo, như vậy là Tỳ Kheo có chánh niệm. ",
  "dn16:2.13.1": "Và này các Tỳ Kheo, thế nào là Tỳ Kheo có tỉnh giác? ",
  "dn16:2.13.2": "Này các Tỳ Kheo, ở đây Tỳ Kheo khi đi tới, đi lui đều tỉnh giác; khi nhìn trước, nhìn sau đều tỉnh giác; khi co tay, duỗi tay đều tỉnh giác; khi mặc y tăng-già-lê, mang bát đều tỉnh giác; khi ăn, uống, nhai, nếm đều tỉnh giác; khi đại tiểu tiện đều tỉnh giác; khi đi, đứng, ngồi, nằm, thức, nói, im lặng đều tỉnh giác. ",
  "dn16:2.13.3": "Này các Tỳ Kheo, như vậy là Tỳ Kheo có tỉnh giác. ",
  "dn16:2.13.4": "Này các Tỳ Kheo, Tỳ Kheo phải sống có chánh niệm và tỉnh giác, ",
  "dn16:2.13.5": "đây là lời giáo huấn của Ta cho các ông.\" ",
  "dn16:2.14.0": "11. Kỹ Nữ Ambapāli ",
  "dn16:2.14.1": "Kỹ nữ Ambapāli nghe tin: \"Đức Thế Tôn đã đến Vesāli và trú tại Vesāli trong vườn xoài của ta.\" ",
  "dn16:2.14.2": "Rồi kỹ nữ Ambapāli cho thắng những cỗ xe tốt, tự mình lên xe tốt, cùng với đoàn xe tốt rời khỏi Vesāli, đi về hướng vườn xoài của mình. ",
  "dn16:2.14.3": "Đi xe cho đến hết chỗ xe có thể đi được, bà xuống xe và đi bộ đến chỗ Đức Thế Tôn. Đến nơi, đảnh lễ Đức Thế Tôn rồi ngồi sang một bên. ",
  "dn16:2.14.4": "Khi kỹ nữ Ambapāli đã ngồi sang một bên, Đức Thế Tôn khai thị, khuyến khích, khích lệ, làm cho bà hoan hỷ với lời pháp thoại. ",
  "dn16:2.14.5": "Rồi kỹ nữ Ambapāli, sau khi được Đức Thế Tôn khai thị, khuyến khích, khích lệ, làm cho hoan hỷ với lời pháp thoại, bạch Đức Thế Tôn: ",
  "dn16:2.14.6": "\"Bạch Thế Tôn, xin Đức Thế Tôn cùng chúng Tỳ Kheo nhận lời mời thọ trai ngày mai của con.\" ",
  "dn16:2.14.7": "Đức Thế Tôn im lặng nhận lời. ",
  "dn16:2.14.8": "Biết Đức Thế Tôn đã nhận lời, kỹ nữ Ambapāli từ chỗ ngồi đứng dậy, đảnh lễ Đức Thế Tôn, nhiễu bên phải rồi ra về. ",
  "dn16:2.15.1": "Các vị Licchavi ở Vesāli nghe tin: \"Đức Thế Tôn đã đến Vesāli và trú tại Vesāli trong vườn xoài Ambapāli.\" ",
  "dn16:2.15.2": "Rồi các vị Licchavi cho thắng những cỗ xe tốt, tự mình lên xe tốt, cùng với đoàn xe tốt rời khỏi Vesāli. ",
  "dn16:2.15.3": "Trong đó có một số vị Licchavi đi với màu xanh, da xanh, mặc áo xanh, trang sức xanh; một số vị Licchavi đi với màu vàng, da vàng, mặc áo vàng, trang sức vàng; một số vị Licchavi đi với màu đỏ, da đỏ, mặc áo đỏ, trang sức đỏ; một số vị Licchavi đi với màu trắng, da trắng, mặc áo trắng, trang sức trắng. ",
  "dn16:2.16.1": "Rồi kỹ nữ Ambapāli đi xe va chạm trục với trục, bánh xe với bánh xe, ách với ách của những xe các vị Licchavi trẻ tuổi. ",
  "dn16:2.16.2": "Các vị Licchavi mới nói với kỹ nữ Ambapāli: ",
  "dn16:2.16.3": "\"Này Ambapāli, sao bà lại đi xe va chạm trục với trục, bánh xe với bánh xe, ách với ách với các vị Licchavi trẻ tuổi?\" ",
  "dn16:2.16.4": "\"Thưa các vương tử, bởi vì tôi đã thỉnh Đức Thế Tôn cùng chúng Tỳ Kheo thọ trai ngày mai.\" ",
  "dn16:2.16.5": "\"Này Ambapāli, hãy nhường bữa cơm đó cho chúng tôi với giá một trăm ngàn.\" ",
  "dn16:2.16.6": "\"Thưa các vương tử, dù các ngài có cho tôi cả Vesāli với các vùng phụ cận, tôi cũng không nhường bữa cơm đó đâu.\" ",
  "dn16:2.16.7": "Rồi các vị Licchavi búng ngón tay: ",
  "dn16:2.16.8": "\"Ôi, chúng ta đã thua ả đàn bà xoài mất rồi! Ôi, chúng ta đã thua ả đàn bà xoài mất rồi!\" ",
  "dn16:2.16.9": "Rồi các vị Licchavi đi đến vườn xoài Ambapāli. ",
  "dn16:2.17.1": "Đức Thế Tôn thấy các vị Licchavi ấy đang đến từ xa. ",
  "dn16:2.17.2": "Thấy xong, Ngài gọi các Tỳ Kheo: ",
  "dn16:2.17.3": "\"Này các Tỳ Kheo, những Tỳ Kheo nào chưa từng thấy chư thiên cõi Ba Mươi Ba, hãy nhìn vào đoàn Licchavi này; ",
  "dn16:2.17.4": "hãy quan sát đoàn Licchavi này; ",
  "dn16:2.17.5": "hãy so sánh đoàn Licchavi này—",
  "dn16:2.17.6": "giống như chư thiên cõi Ba Mươi Ba.\" ",
  "dn16:2.18.1": "Rồi các vị Licchavi đi xe cho đến hết chỗ xe có thể đi được, các vị xuống xe và đi bộ đến chỗ Đức Thế Tôn; đến nơi, đảnh lễ Đức Thế Tôn rồi ngồi sang một bên. ",
  "dn16:2.18.2": "Khi các vị Licchavi đã ngồi sang một bên, Đức Thế Tôn khai thị, khuyến khích, khích lệ, làm cho họ hoan hỷ với lời pháp thoại. ",
  "dn16:2.18.3": "Rồi các vị Licchavi, sau khi được Đức Thế Tôn khai thị, khuyến khích, khích lệ, làm cho hoan hỷ với lời pháp thoại, bạch Đức Thế Tôn: ",
  "dn16:2.18.4": "\"Bạch Thế Tôn, xin Đức Thế Tôn cùng chúng Tỳ Kheo nhận lời mời thọ trai ngày mai của chúng con.\" ",
  "dn16:2.18.5": "Rồi Đức Thế Tôn nói với các vị Licchavi: ",
  "dn16:2.18.6": "\"Này các Licchavi, Ta đã nhận lời mời thọ trai ngày mai của kỹ nữ Ambapāli rồi.\" ",
  "dn16:2.18.7": "Rồi các vị Licchavi búng ngón tay: ",
  "dn16:2.18.8": "\"Ôi, chúng ta đã thua ả đàn bà xoài mất rồi! Ôi, chúng ta đã thua ả đàn bà xoài mất rồi!\" ",
  "dn16:2.18.9": "Rồi các vị Licchavi hoan hỷ, tín thọ lời dạy của Đức Thế Tôn, từ chỗ ngồi đứng dậy, đảnh lễ Đức Thế Tôn, nhiễu bên phải rồi ra về. ",
  "dn16:2.19.1": "Rồi kỹ nữ Ambapāli, sau khi đêm đã qua, tại vườn xoài của mình, cho chuẩn bị các món ăn ngon, rồi báo giờ đến Đức Thế Tôn: ",
  "dn16:2.19.2": "\"Đã đến giờ, bạch Thế Tôn, cơm đã sẵn sàng.\" ",
  "dn16:2.19.3": "Rồi vào buổi sáng, Đức Thế Tôn đắp y, cầm y bát, cùng với chúng Tỳ Kheo đi đến nhà của kỹ nữ Ambapāli; đến nơi, ngồi xuống chỗ đã soạn sẵn. ",
  "dn16:2.19.4": "Rồi kỹ nữ Ambapāli tự tay dâng cúng các món ăn ngon cho chúng Tỳ Kheo do Đức Phật dẫn đầu. ",
  "dn16:2.19.5": "Sau khi Đức Thế Tôn thọ trai xong, tay rời khỏi bát, kỹ nữ Ambapāli lấy chỗ ngồi thấp hơn và ngồi sang một bên. ",
  "dn16:2.19.6": "Khi kỹ nữ Ambapāli đã ngồi sang một bên, bà bạch Đức Thế Tôn: ",
  "dn16:2.19.7": "\"Bạch Thế Tôn, con xin cúng dường khu vườn này cho chúng Tỳ Kheo do Đức Phật dẫn đầu.\" ",
  "dn16:2.19.8": "Đức Thế Tôn nhận khu vườn. ",
  "dn16:2.19.9": "Rồi Đức Thế Tôn sau khi khai thị, khuyến khích, khích lệ, làm cho kỹ nữ Ambapāli hoan hỷ với lời pháp thoại, từ chỗ ngồi đứng dậy, ra đi. ",
  "dn16:2.20.1": "Tại đó, khi trú ở Vesāli trong vườn xoài Ambapāli, Đức Thế Tôn thường xuyên thuyết pháp cho các Tỳ Kheo như sau: ",
  "dn16:2.20.2": "\"Đây là giới, đây là định, đây là tuệ. ",
  "dn16:2.20.3": "Định được tu tập bằng giới sẽ đem lại quả lớn, lợi ích lớn. ",
  "dn16:2.20.4": "Tuệ được tu tập bằng định sẽ đem lại quả lớn, lợi ích lớn. ",
  "dn16:2.20.5": "Tâm được tu tập bằng tuệ sẽ hoàn toàn giải thoát khỏi các lậu hoặc, đó là—",
  "dn16:2.20.6": "dục lậu, hữu lậu, vô minh lậu.\" ",
  "dn16:2.21.0": "12. An Cư Mùa Mưa tại Làng Veḷuva ",
  "dn16:2.21.1": "Rồi sau khi trú tại vườn xoài Ambapāli một thời gian vừa ý, Đức Thế Tôn gọi Tôn giả Ānanda: ",
  "dn16:2.21.2": "\"Này Ānanda, chúng ta hãy đi đến làng Veḷuva.\" ",
  "dn16:2.21.3": "\"Thưa vâng, bạch Thế Tôn\", Tôn giả Ānanda vâng lời Đức Thế Tôn. ",
  "dn16:2.21.4": "Rồi Đức Thế Tôn cùng với đại chúng Tỳ Kheo đi đến làng Veḷuva. ",
  "dn16:2.21.5": "Tại đó, Đức Thế Tôn trú ở làng Veḷuva. ",
  "dn16:2.22.1": "Tại đó, Đức Thế Tôn gọi các Tỳ Kheo: ",
  "dn16:2.22.2": "\"Này các Tỳ Kheo, các ông hãy đi khắp vùng quanh Vesāli, tùy theo chỗ có bạn bè, người quen, người thân thuộc mà an cư mùa mưa. ",
  "dn16:2.22.3": "Còn Ta sẽ an cư mùa mưa ngay tại đây, tại làng Veḷuva này.\" ",
  "dn16:2.22.4": "\"Thưa vâng, bạch Thế Tôn\", các Tỳ Kheo vâng lời Đức Thế Tôn, đi khắp vùng quanh Vesāli, tùy theo chỗ có bạn bè, người quen, người thân thuộc mà an cư mùa mưa. ",
  "dn16:2.22.5": "Còn Đức Thế Tôn an cư mùa mưa tại làng Veḷuva. ",
  "dn16:2.23.1": "Rồi khi Đức Thế Tôn đang an cư mùa mưa, Ngài bị bệnh trầm trọng, cảm thọ dữ dội, gần như chết đến nơi. ",
  "dn16:2.23.2": "Đức Thế Tôn chánh niệm, tỉnh giác chịu đựng, không bị dao động. ",
  "dn16:2.23.3": "Rồi Đức Thế Tôn nghĩ: ",
  "dn16:2.23.4": "\"Không thích hợp nếu Ta nhập Niết Bàn mà không báo cho các thị giả, không từ giã chúng Tỳ Kheo. ",
  "dn16:2.23.5": "Vậy Ta hãy dùng tinh tấn đẩy lui bệnh này, và duy trì mạng sống mà sống.\" ",
  "dn16:2.24.1": "Rồi Đức Thế Tôn dùng tinh tấn đẩy lui bệnh ấy, duy trì mạng sống mà sống. ",
  "dn16:2.24.2": "Bệnh của Đức Thế Tôn liền được thuyên giảm. ",
  "dn16:2.24.3": "Rồi Đức Thế Tôn sau khi khỏi bệnh không lâu, ra khỏi tịnh thất và ngồi xuống chỗ đã soạn sẵn trong bóng mát của tịnh thất. ",
  "dn16:2.24.4": "Rồi Tôn giả Ānanda đi đến chỗ Đức Thế Tôn; đến nơi, đảnh lễ Đức Thế Tôn rồi ngồi sang một bên. Ngồi sang một bên, Tôn giả Ānanda bạch Đức Thế Tôn: ",
  "dn16:2.24.5": "\"Bạch Thế Tôn, con đã thấy Đức Thế Tôn khỏe mạnh; con đã thấy Đức Thế Tôn có thể chịu đựng được; nhưng bạch Thế Tôn, thân thể con như thể say rượu, con không còn phân biệt được phương hướng, các pháp cũng không còn hiện ra trong tâm con, do bệnh duyên của Đức Thế Tôn. ",
  "dn16:2.24.6": "Nhưng bạch Thế Tôn, con còn có chút an ủi rằng: ",
  "dn16:2.24.7": "'Đức Thế Tôn sẽ không nhập Niết Bàn khi chưa dạy bảo điều gì về chúng Tỳ Kheo.'\" ",
  "dn16:2.25.1": "\"Này Ānanda, chúng Tỳ Kheo còn mong đợi điều gì ở Ta? ",
  "dn16:2.25.2": "Này Ānanda, Ta đã giảng dạy Giáo Pháp không phân biệt trong ngoài. ",
  "dn16:2.25.3": "Này Ānanda, Như Lai không có bàn tay nắm chặt của thầy đối với các pháp. ",
  "dn16:2.25.4": "Này Ānanda, nếu có ai nghĩ rằng: ",
  "dn16:2.25.5": "'Ta sẽ lãnh đạo chúng Tỳ Kheo' hoặc 'chúng Tỳ Kheo phải lệ thuộc vào Ta', thì người đó mới cần phải dặn dò gì về chúng Tỳ Kheo. ",
  "dn16:2.25.6": "Này Ānanda, Như Lai không nghĩ rằng: ",
  "dn16:2.25.7": "'Ta sẽ lãnh đạo chúng Tỳ Kheo' hoặc 'chúng Tỳ Kheo phải lệ thuộc vào Ta'. ",
  "dn16:2.25.8": "Này Ānanda, vậy Như Lai còn dặn dò gì về chúng Tỳ Kheo nữa? ",
  "dn16:2.25.9": "Này Ānanda, nay Ta đã già, đã suy yếu, đã lớn tuổi, đã đến cuối đời, đã đến tuổi cao. ",
  "dn16:2.25.10": "Tuổi của Ta đã tám mươi. ",
  "dn16:2.25.11": "Này Ānanda, giống như một cỗ xe cũ kỹ phải nhờ dây đai mà đi được; ",
  "dn16:2.25.12": "cũng vậy, này Ānanda, thân Như Lai hình như phải nhờ dây đai mà đi được. ",
  "dn16:2.25.13": "Này Ānanda, khi nào Như Lai không tác ý đến tất cả tướng, đoạn diệt một số cảm thọ, chứng và trú vô tướng tâm định, chính lúc ấy, thân Như Lai được an ổn hơn. ",
  "dn16:2.26.1": "Vì vậy, này Ānanda, hãy tự mình là ngọn đèn, tự mình là nơi nương tựa, không nương tựa nơi nào khác; hãy lấy Pháp làm ngọn đèn, lấy Pháp làm nơi nương tựa, không nương tựa nơi nào khác. ",
  "dn16:2.26.2": "Và này Ānanda, thế nào là Tỳ Kheo tự mình là ngọn đèn, tự mình là nơi nương tựa, không nương tựa nơi nào khác; lấy Pháp làm ngọn đèn, lấy Pháp làm nơi nương tựa, không nương tựa nơi nào khác? ",
  "dn16:2.26.3": "Này Ānanda, ở đây Tỳ Kheo sống quán thân trên thân, tinh cần, tỉnh giác, chánh niệm, nhiếp phục tham ưu ở đời. ",
  "dn16:2.26.4": "Quán cảm thọ trên các cảm thọ …vân vân… ",
  "dn16:2.26.5": "quán tâm trên tâm …vân vân… ",
  "dn16:2.26.6": "quán pháp trên các pháp, tinh cần, tỉnh giác, chánh niệm, nhiếp phục tham ưu ở đời. ",
  "dn16:2.26.7": "Này Ānanda, như vậy là Tỳ Kheo tự mình là ngọn đèn, tự mình là nơi nương tựa, không nương tựa nơi nào khác; lấy Pháp làm ngọn đèn, lấy Pháp làm nơi nương tựa, không nương tựa nơi nào khác. ",
  "dn16:2.26.8": "Này Ānanda, những Tỳ Kheo nào trong hiện tại hoặc sau khi Ta nhập diệt còn tự mình là ngọn đèn, tự mình là nơi nương tựa, không nương tựa nơi nào khác; lấy Pháp làm ngọn đèn, lấy Pháp làm nơi nương tựa, không nương tựa nơi nào khác, thì này Ānanda, những Tỳ Kheo ấy sẽ là những người đứng đầu trong số những vị ham học.\" ",
  "dn16:2.26.9": "Hết phần tụng đọc thứ hai. ",
  "dn16:3.1.0": "13. Câu Chuyện Về Điềm Báo và Tín Hiệu ",
  "dn16:3.1.1": "Rồi vào buổi sáng, Đức Thế Tôn đắp y, cầm y bát, đi vào Vesāli để khất thực. ",
  "dn16:3.1.2": "Sau khi khất thực ở Vesāli, sau bữa ăn, trên đường khất thực trở về, Ngài gọi Tôn giả Ānanda: ",
  "dn16:3.1.3": "\"Này Ānanda, hãy cầm theo tọa cụ, ",
  "dn16:3.1.4": "chúng ta sẽ đi đến đền Cāpāla để nghỉ ban ngày.\" ",
  "dn16:3.1.5": "\"Thưa vâng, bạch Thế Tôn\", Tôn giả Ānanda vâng lời Đức Thế Tôn, cầm tọa cụ đi theo sau Đức Thế Tôn. ",
  "dn16:3.2.1": "Rồi Đức Thế Tôn đi đến đền Cāpāla; đến nơi, ngồi xuống chỗ đã soạn sẵn. ",
  "dn16:3.2.2": "Tôn giả Ānanda cũng đảnh lễ Đức Thế Tôn rồi ngồi sang một bên. ",
  "dn16:3.2.3": "Khi Tôn giả Ānanda đã ngồi sang một bên, Đức Thế Tôn nói với Tôn giả: ",
  "dn16:3.2.4": "\"Này Ānanda, Vesāli thật đáng yêu, đền Udena thật đáng yêu, đền Gotamaka thật đáng yêu, đền Sattamba thật đáng yêu, đền Bahuputta thật đáng yêu, đền Sārandada thật đáng yêu, đền Cāpāla thật đáng yêu. ",
  "dn16:3.3.1": "Này Ānanda, người nào đã tu tập, làm cho sung mãn, làm thành cỗ xe, làm thành nền tảng, vận dụng, tích lũy, khéo kiên trì bốn như ý túc, thì người ấy nếu muốn, có thể sống trọn một kiếp hoặc phần còn lại của một kiếp. ",
  "dn16:3.3.2": "Này Ānanda, Như Lai đã tu tập, làm cho sung mãn, làm thành cỗ xe, làm thành nền tảng, vận dụng, tích lũy, khéo kiên trì bốn như ý túc, vậy này Ānanda, Như Lai nếu muốn, có thể sống trọn một kiếp hoặc phần còn lại của một kiếp.\" ",
  "dn16:3.4.1": "Ngay cả khi Đức Thế Tôn đã đưa ra dấu hiệu rõ ràng, đã gợi ý rõ ràng như vậy, Tôn giả Ānanda vẫn không thể nhận ra; ",
  "dn16:3.4.2": "không thỉnh cầu Đức Thế Tôn: ",
  "dn16:3.4.3": "\"Bạch Thế Tôn, xin Đức Thế Tôn hãy sống trọn một kiếp, xin bậc Thiện Thệ hãy sống trọn một kiếp, vì lợi ích cho đại chúng, vì an lạc cho đại chúng, vì thương tưởng cho đời, vì lợi ích, vì hạnh phúc, vì an lạc cho chư thiên và loài người\"—vì tâm Tôn giả đã bị ác ma ám ảnh. ",
  "dn16:3.5.1": "Lần thứ hai, Đức Thế Tôn …vân vân… ",
  "dn16:3.5.2": "lần thứ ba, Đức Thế Tôn gọi Tôn giả Ānanda: ",
  "dn16:3.5.3": "\"Này Ānanda, Vesāli thật đáng yêu, đền Udena thật đáng yêu, đền Gotamaka thật đáng yêu, đền Sattamba thật đáng yêu, đền Bahuputta thật đáng yêu, đền Sārandada thật đáng yêu, đền Cāpāla thật đáng yêu. ",
  "dn16:3.5.4": "Này Ānanda, người nào đã tu tập, làm cho sung mãn, làm thành cỗ xe, làm thành nền tảng, vận dụng, tích lũy, khéo kiên trì bốn như ý túc, thì người ấy nếu muốn, có thể sống trọn một kiếp hoặc phần còn lại của một kiếp. ",
  "dn16:3.5.5": "Này Ānanda, Như Lai đã tu tập, làm cho sung mãn, làm thành cỗ xe, làm thành nền tảng, vận dụng, tích lũy, khéo kiên trì bốn như ý túc, vậy này Ānanda, Như Lai nếu muốn, có thể sống trọn một kiếp hoặc phần còn lại của một kiếp.\" ",
  "dn16:3.5.6": "Ngay cả khi Đức Thế Tôn đã đưa ra dấu hiệu rõ ràng, đã gợi ý rõ ràng như vậy, Tôn giả Ānanda vẫn không thể nhận ra; ",
  "dn16:3.5.7": "không thỉnh cầu Đức Thế Tôn: ",
  "dn16:3.5.8": "\"Bạch Thế Tôn, xin Đức Thế Tôn hãy sống trọn một kiếp, xin bậc Thiện Thệ hãy sống trọn một kiếp, vì lợi ích cho đại chúng, vì an lạc cho đại chúng, vì thương tưởng cho đời, vì lợi ích, vì hạnh phúc, vì an lạc cho chư thiên và loài người\"—vì tâm Tôn giả đã bị ác ma ám ảnh. ",
  "dn16:3.6.1": "Rồi Đức Thế Tôn gọi Tôn giả Ānanda: ",
  "dn16:3.6.2": "\"Này Ānanda, ngươi hãy đi, ",
  "dn16:3.6.3": "hãy làm những gì ngươi thấy đúng thời.\" ",
  "dn16:3.6.4": "\"Thưa vâng, bạch Thế Tôn\", Tôn giả Ānanda vâng lời Đức Thế Tôn, từ chỗ ngồi đứng dậy, đảnh lễ Đức Thế Tôn, nhiễu bên phải rồi ngồi xuống dưới một gốc cây không xa đó. ",
  "dn16:3.7.0": "14. Ác Ma Khẩn Cầu ",
  "dn16:3.7.1": "Rồi không lâu sau khi Tôn giả Ānanda đi ra, ác ma đi đến chỗ Đức Thế Tôn; đến nơi, đứng sang một bên. Đứng sang một bên, ác ma bạch Đức Thế Tôn: ",
  "dn16:3.7.2": "\"Bạch Thế Tôn, bây giờ xin Đức Thế Tôn nhập Niết Bàn, xin bậc Thiện Thệ nhập Niết Bàn, bây giờ đã đến lúc Đức Thế Tôn nhập Niết Bàn rồi. ",
  "dn16:3.7.3": "Bạch Thế Tôn, Đức Thế Tôn đã từng nói lời này: ",
  "dn16:3.7.4": "'Này ác ma, Ta sẽ không nhập Niết Bàn chừng nào các Tỳ Kheo đệ tử của Ta chưa trở thành những người thông thạo, có kỷ luật, tự tin, đa văn, thọ trì Giáo Pháp, tu tập đúng pháp, thực hành đúng đắn, hành động đúng theo pháp; chưa học được pháp từ thầy mình rồi truyền dạy, tuyên thuyết, làm cho rõ, thiết lập, mở bày, phân tích, làm cho sáng tỏ; chưa có thể dùng chánh pháp khéo chế phục các tà thuyết ngoại đạo khởi lên, rồi thuyết pháp có tính chất thần diệu.' ",
  "dn16:3.8.1": "Bạch Thế Tôn, nay các Tỳ Kheo đệ tử của Đức Thế Tôn đã trở thành những người thông thạo, có kỷ luật, tự tin, đa văn, thọ trì Giáo Pháp, tu tập đúng pháp, thực hành đúng đắn, hành động đúng theo pháp; đã học được pháp từ thầy mình và đang truyền dạy, tuyên thuyết, làm cho rõ, thiết lập, mở bày, phân tích, làm cho sáng tỏ; đã có thể dùng chánh pháp khéo chế phục các tà thuyết ngoại đạo khởi lên, rồi thuyết pháp có tính chất thần diệu. ",
  "dn16:3.8.2": "Bạch Thế Tôn, bây giờ xin Đức Thế Tôn nhập Niết Bàn, xin bậc Thiện Thệ nhập Niết Bàn, bây giờ đã đến lúc Đức Thế Tôn nhập Niết Bàn rồi. ",
  "dn16:3.8.3": "Bạch Thế Tôn, Đức Thế Tôn đã từng nói lời này: ",
  "dn16:3.8.4": "'Này ác ma, Ta sẽ không nhập Niết Bàn chừng nào các Tỳ Kheo ni đệ tử của Ta chưa trở thành những người thông thạo, có kỷ luật, tự tin, đa văn, thọ trì Giáo Pháp, tu tập đúng pháp, thực hành đúng đắn, hành động đúng theo pháp; chưa học được pháp từ thầy mình rồi truyền dạy, tuyên thuyết, làm cho rõ, thiết lập, mở bày, phân tích, làm cho sáng tỏ; chưa có thể dùng chánh pháp khéo chế phục các tà thuyết ngoại đạo khởi lên, rồi thuyết pháp có tính chất thần diệu.' ",
  "dn16:3.8.5": "Bạch Thế Tôn, nay các Tỳ Kheo ni đệ tử của Đức Thế Tôn đã trở thành những người thông thạo, có kỷ luật, tự tin, đa văn, thọ trì Giáo Pháp, tu tập đúng pháp, thực hành đúng đắn, hành động đúng theo pháp; đã học được pháp từ thầy mình và đang truyền dạy, tuyên thuyết, làm cho rõ, thiết lập, mở bày, phân tích, làm cho sáng tỏ; đã có thể dùng chánh pháp khéo chế phục các tà thuyết ngoại đạo khởi lên, rồi thuyết pháp có tính chất thần diệu. ",
  "dn16:3.8.6": "Bạch Thế Tôn, bây giờ xin Đức Thế Tôn nhập Niết Bàn, xin bậc Thiện Thệ nhập Niết Bàn, bây giờ đã đến lúc Đức Thế Tôn nhập Niết Bàn rồi. ",
  "dn16:3.8.7": "Bạch Thế Tôn, Đức Thế Tôn đã từng nói lời này: ",
  "dn16:3.8.8": "'Này ác ma, Ta sẽ không nhập Niết Bàn chừng nào các nam cư sĩ đệ tử của Ta chưa trở thành những người thông thạo, có kỷ luật, tự tin, đa văn, thọ trì Giáo Pháp, tu tập đúng pháp, thực hành đúng đắn, hành động đúng theo pháp; chưa học được pháp từ thầy mình rồi truyền dạy, tuyên thuyết, làm cho rõ, thiết lập, mở bày, phân tích, làm cho sáng tỏ; chưa có thể dùng chánh pháp khéo chế phục các tà thuyết ngoại đạo khởi lên, rồi thuyết pháp có tính chất thần diệu.' ",
  "dn16:3.8.9": "Bạch Thế Tôn, nay các nam cư sĩ đệ tử của Đức Thế Tôn đã trở thành những người thông thạo, có kỷ luật, tự tin, đa văn, thọ trì Giáo Pháp, tu tập đúng pháp, thực hành đúng đắn, hành động đúng theo pháp; đã học được pháp từ thầy mình và đang truyền dạy, tuyên thuyết, làm cho rõ, thiết lập, mở bày, phân tích, làm cho sáng tỏ; đã có thể dùng chánh pháp khéo chế phục các tà thuyết ngoại đạo khởi lên, rồi thuyết pháp có tính chất thần diệu. ",
  "dn16:3.8.10": "Bạch Thế Tôn, bây giờ xin Đức Thế Tôn nhập Niết Bàn, xin bậc Thiện Thệ nhập Niết Bàn, bây giờ đã đến lúc Đức Thế Tôn nhập Niết Bàn rồi. ",
  "dn16:3.8.11": "Bạch Thế Tôn, Đức Thế Tôn đã từng nói lời này: ",
  "dn16:3.8.12": "'Này ác ma, Ta sẽ không nhập Niết Bàn chừng nào các nữ cư sĩ đệ tử của Ta chưa trở thành những người thông thạo, có kỷ luật, tự tin, đa văn, thọ trì Giáo Pháp, tu tập đúng pháp, thực hành đúng đắn, hành động đúng theo pháp; chưa học được pháp từ thầy mình rồi truyền dạy, tuyên thuyết, làm cho rõ, thiết lập, mở bày, phân tích, làm cho sáng tỏ; chưa có thể dùng chánh pháp khéo chế phục các tà thuyết ngoại đạo khởi lên, rồi thuyết pháp có tính chất thần diệu.' ",
  "dn16:3.8.13": "Bạch Thế Tôn, nay các nữ cư sĩ đệ tử của Đức Thế Tôn đã trở thành những người thông thạo, có kỷ luật, tự tin, đa văn, thọ trì Giáo Pháp, tu tập đúng pháp, thực hành đúng đắn, hành động đúng theo pháp; đã học được pháp từ thầy mình và đang truyền dạy, tuyên thuyết, làm cho rõ, thiết lập, mở bày, phân tích, làm cho sáng tỏ; đã có thể dùng chánh pháp khéo chế phục các tà thuyết ngoại đạo khởi lên, rồi thuyết pháp có tính chất thần diệu. ",
  "dn16:3.8.14": "Bạch Thế Tôn, bây giờ xin Đức Thế Tôn nhập Niết Bàn, xin bậc Thiện Thệ nhập Niết Bàn, bây giờ đã đến lúc Đức Thế Tôn nhập Niết Bàn rồi. ",
  "dn16:3.8.15": "Bạch Thế Tôn, Đức Thế Tôn đã từng nói lời này: ",
  "dn16:3.8.16": "'Này ác ma, Ta sẽ không nhập Niết Bàn chừng nào phạm hạnh của Ta chưa hưng thịnh, phát triển, phổ biến rộng rãi, được nhiều người biết đến, chưa được tuyên thuyết rộng rãi cho chư thiên và loài người.' ",
  "dn16:3.8.17": "Bạch Thế Tôn, nay phạm hạnh của Đức Thế Tôn đã hưng thịnh, phát triển, phổ biến rộng rãi, được nhiều người biết đến, đã được tuyên thuyết rộng rãi cho chư thiên và loài người. ",
  "dn16:3.8.18": "Bạch Thế Tôn, bây giờ xin Đức Thế Tôn nhập Niết Bàn, xin bậc Thiện Thệ nhập Niết Bàn, bây giờ đã đến lúc Đức Thế Tôn nhập Niết Bàn rồi.\" ",
  "dn16:3.9.1": "Khi được nghe nói như vậy, Đức Thế Tôn nói với ác ma: ",
  "dn16:3.9.2": "\"Này ác ma, ngươi hãy yên tâm, không lâu nữa Như Lai sẽ nhập Niết Bàn. ",
  "dn16:3.9.3": "Ba tháng kể từ bây giờ, Như Lai sẽ nhập Niết Bàn.\" ",
  "dn16:3.10.0": "15. Từ Bỏ Thọ Hành ",
  "dn16:3.10.1": "Rồi tại đền Cāpāla, Đức Thế Tôn chánh niệm, tỉnh giác, từ bỏ thọ hành. ",
  "dn16:3.10.2": "Khi Đức Thế Tôn đã từ bỏ thọ hành, thì đất rung chuyển lớn, kinh hãi, rợn người, và sấm trời vang dội. ",
  "dn16:3.10.3": "Thấu hiểu ý nghĩa này, vào lúc đó, Đức Thế Tôn thốt lên lời cảm hứng như sau: ",
  "dn16:3.10.4": "\"Hữu vi và vô vi, ",
  "dn16:3.10.5": "Bậc Mâu-ni từ bỏ các hành của hữu; ",
  "dn16:3.10.6": "Vui trong nội tâm, định tĩnh, ",
  "dn16:3.10.7": "Phá vỡ gốc hữu như phá áo giáp.\" ",
  "dn16:3.11.0": "16. Nguyên Nhân Đại Địa Chấn ",
  "dn16:3.11.1": "Rồi Tôn giả Ānanda nghĩ: ",
  "dn16:3.11.2": "\"Thật kỳ diệu thay! Thật hy hữu thay! Đây quả là một trận động đất lớn; ",
  "dn16:3.11.3": "quả là một trận động đất rất lớn, kinh hãi, rợn người; và sấm trời vang dội. ",
  "dn16:3.11.4": "Do nhân gì, do duyên gì mà có trận động đất lớn này xuất hiện?\" ",
  "dn16:3.12.1": "Rồi Tôn giả Ānanda đi đến chỗ Đức Thế Tôn, ",
  "dn16:3.12.2": "đến nơi, đảnh lễ Đức Thế Tôn rồi ngồi sang một bên, ",
  "dn16:3.12.3": "ngồi sang một bên, Tôn giả Ānanda bạch Đức Thế Tôn: ",
  "dn16:3.12.4": "\"Thật kỳ diệu thay, bạch Thế Tôn! Thật hy hữu thay, bạch Thế Tôn! ",
  "dn16:3.12.5": "Bạch Thế Tôn, đây quả là một trận động đất lớn; ",
  "dn16:3.12.6": "bạch Thế Tôn, quả là một trận động đất rất lớn, kinh hãi, rợn người; và sấm trời vang dội. ",
  "dn16:3.12.7": "Bạch Thế Tôn, do nhân gì, do duyên gì mà có trận động đất lớn này xuất hiện?\" ",
  "dn16:3.13.1": "\"Này Ānanda, có tám nhân, tám duyên làm cho có trận động đất lớn xuất hiện. ",
  "dn16:3.13.2": "Tám đó là gì? ",
  "dn16:3.13.3": "Này Ānanda, quả địa cầu này nằm trên nước, nước nằm trên gió, gió ở trong hư không. Này Ānanda, có những lúc các cơn gió lớn thổi. Các cơn gió lớn thổi làm nước chuyển động. Nước chuyển động làm đất chuyển động. ",
  "dn16:3.13.4": "Đây là nhân thứ nhất, duyên thứ nhất làm cho có trận động đất lớn xuất hiện. ",
  "dn16:3.14.1": "Lại nữa, này Ānanda, có vị sa-môn hoặc bà-la-môn có thần thông, đã đạt đến tự tại về tâm, hoặc có vị chư thiên có đại thần lực, đại uy lực, tu tập tưởng về đất là hạn lượng, tưởng về nước là vô lượng. Vị ấy làm đất này rung chuyển, rung động mạnh, chuyển động, lay động. ",
  "dn16:3.14.2": "Đây là nhân thứ hai, duyên thứ hai làm cho có trận động đất lớn xuất hiện. ",
  "dn16:3.15.1": "Lại nữa, này Ānanda, khi Bồ Tát, sau khi chết từ cõi trời Đâu-suất, chánh niệm, tỉnh giác nhập vào bụng mẹ, thì đất này rung chuyển, rung động mạnh, chuyển động, lay động. ",
  "dn16:3.15.2": "Đây là nhân thứ ba, duyên thứ ba làm cho có trận động đất lớn xuất hiện. ",
  "dn16:3.16.1": "Lại nữa, này Ānanda, khi Bồ Tát chánh niệm, tỉnh giác ra khỏi bụng mẹ, thì đất này rung chuyển, rung động mạnh, chuyển động, lay động. ",
  "dn16:3.16.2": "Đây là nhân thứ tư, duyên thứ tư làm cho có trận động đất lớn xuất hiện. ",
  "dn16:3.17.1": "Lại nữa, này Ānanda, khi Như Lai chứng đắc Vô Thượng Chánh Đẳng Giác, thì đất này rung chuyển, rung động mạnh, chuyển động, lay động. ",
  "dn16:3.17.2": "Đây là nhân thứ năm, duyên thứ năm làm cho có trận động đất lớn xuất hiện. ",
  "dn16:3.18.1": "Lại nữa, này Ānanda, khi Như Lai chuyển bánh xe Pháp vô thượng, thì đất này rung chuyển, rung động mạnh, chuyển động, lay động. ",
  "dn16:3.18.2": "Đây là nhân thứ sáu, duyên thứ sáu làm cho có trận động đất lớn xuất hiện. ",
  "dn16:3.19.1": "Lại nữa, này Ānanda, khi Như Lai chánh niệm, tỉnh giác từ bỏ thọ hành, thì đất này rung chuyển, rung động mạnh, chuyển động, lay động. ",
  "dn16:3.19.2": "Đây là nhân thứ bảy, duyên thứ bảy làm cho có trận động đất lớn xuất hiện. ",
  "dn16:3.20.1": "Lại nữa, này Ānanda, khi Như Lai nhập Niết Bàn trong trạng thái vô dư y Niết Bàn giới, thì đất này rung chuyển, rung động mạnh, chuyển động, lay động. ",
  "dn16:3.20.2": "Đây là nhân thứ tám, duyên thứ tám làm cho có trận động đất lớn xuất hiện. ",
  "dn16:3.20.3": "Này Ānanda, đó là tám nhân, tám duyên làm cho có trận động đất lớn xuất hiện. ",
  "dn16:3.21.0": "17. Tám Hội Chúng ",
  "dn16:3.21.1": "Này Ānanda, có tám hội chúng này. ",
  "dn16:3.21.2": "Tám đó là gì? ",
  "dn16:3.21.3": "Hội chúng sát-đế-lỵ, hội chúng bà-la-môn, hội chúng gia chủ, hội chúng sa-môn, hội chúng Tứ Thiên Vương, hội chúng cõi Ba Mươi Ba, hội chúng ác ma, hội chúng Phạm Thiên. ",
  "dn16:3.22.1": "Này Ānanda, Ta nhớ đã đi đến hàng trăm hội chúng sát-đế-lỵ. ",
  "dn16:3.22.2": "Tại đó, Ta đã từng cùng họ ngồi, cùng họ nói chuyện, cùng họ đàm luận. ",
  "dn16:3.22.3": "Tại đó, sắc tướng của họ như thế nào, sắc tướng của Ta cũng như thế; âm thanh của họ như thế nào, âm thanh của Ta cũng như thế. ",
  "dn16:3.22.4": "Ta khai thị, khuyến khích, khích lệ, làm cho họ hoan hỷ với lời pháp thoại. ",
  "dn16:3.22.5": "Khi Ta đang nói, họ không biết: ",
  "dn16:3.22.6": "'Ai nói đây, là chư thiên hay loài người?' ",
  "dn16:3.22.7": "Sau khi đã khai thị, khuyến khích, khích lệ, làm cho họ hoan hỷ với lời pháp thoại, Ta biến mất. ",
  "dn16:3.22.8": "Khi Ta biến mất, họ không biết: ",
  "dn16:3.22.9": "'Ai vừa biến mất đây, là chư thiên hay loài người?' ",
  "dn16:3.23.1": "Này Ānanda, Ta nhớ đã đi đến hàng trăm hội chúng bà-la-môn …vân vân… ",
  "dn16:3.23.2": "hội chúng gia chủ … ",
  "dn16:3.23.3": "hội chúng sa-môn … ",
  "dn16:3.23.4": "hội chúng Tứ Thiên Vương … ",
  "dn16:3.23.5": "hội chúng cõi Ba Mươi Ba … ",
  "dn16:3.23.6": "hội chúng ác ma … ",
  "dn16:3.23.7": "hội chúng Phạm Thiên. ",
  "dn16:3.23.8": "Tại đó, Ta đã từng cùng họ ngồi, cùng họ nói chuyện, cùng họ đàm luận. ",
  "dn16:3.23.9": "Tại đó, sắc tướng của họ như thế nào, sắc tướng của Ta cũng như thế. ",
  "dn16:3.23.10": "Âm thanh của họ như thế nào, âm thanh của Ta cũng như thế. ",
  "dn16:3.23.11": "Ta khai thị, khuyến khích, khích lệ, làm cho họ hoan hỷ với lời pháp thoại. ",
  "dn16:3.23.12": "Khi Ta đang nói, họ không biết: ",
  "dn16:3.23.13": "'Ai nói đây, là chư thiên hay loài người?' ",
  "dn16:3.23.14": "Sau khi đã khai thị, khuyến khích, khích lệ, làm cho họ hoan hỷ với lời pháp thoại, Ta biến mất. ",
  "dn16:3.23.15": "Khi Ta biến mất, họ không biết: ",
  "dn16:3.23.16": "'Ai vừa biến mất đây, là chư thiên hay loài người?' ",
  "dn16:3.23.17": "Này Ānanda, đó là tám hội chúng. ",
  "dn16:3.24.0": "18. Tám Thắng Xứ ",
  "dn16:3.24.1": "Này Ānanda, có tám thắng xứ này. ",
  "dn16:3.24.2": "Tám đó là gì? ",
  "dn16:3.25.1": "Một vị có sắc tưởng bên trong, thấy các sắc bên ngoài có hạn lượng, đẹp hoặc xấu. ",
  "dn16:3.25.2": "'Sau khi chế ngự chúng, ta biết, ta thấy', vị ấy có tưởng như vậy. ",
  "dn16:3.25.3": "Đây là thắng xứ thứ nhất. ",
  "dn16:3.26.1": "Một vị có sắc tưởng bên trong, thấy các sắc bên ngoài vô lượng, đẹp hoặc xấu. ",
  "dn16:3.26.2": "'Sau khi chế ngự chúng, ta biết, ta thấy', vị ấy có tưởng như vậy. ",
  "dn16:3.26.3": "Đây là thắng xứ thứ hai. ",
  "dn16:3.27.1": "Một vị không có sắc tưởng bên trong, thấy các sắc bên ngoài có hạn lượng, đẹp hoặc xấu. ",
  "dn16:3.27.2": "'Sau khi chế ngự chúng, ta biết, ta thấy', vị ấy có tưởng như vậy. ",
  "dn16:3.27.3": "Đây là thắng xứ thứ ba. ",
  "dn16:3.28.1": "Một vị không có sắc tưởng bên trong, thấy các sắc bên ngoài vô lượng, đẹp hoặc xấu. ",
  "dn16:3.28.2": "'Sau khi chế ngự chúng, ta biết, ta thấy', vị ấy có tưởng như vậy. ",
  "dn16:3.28.3": "Đây là thắng xứ thứ tư. ",
  "dn16:3.29.1": "Một vị không có sắc tưởng bên trong, thấy các sắc bên ngoài màu xanh, sắc xanh, tướng xanh, ánh xanh. ",
  "dn16:3.29.2": "Giống như bông hoa umā màu xanh, sắc xanh, tướng xanh, ánh xanh. Hoặc giống như vải Ba-la-nại mịn cả hai mặt, màu xanh, sắc xanh, tướng xanh, ánh xanh. ",
  "dn16:3.29.3": "Cũng vậy, một vị không có sắc tưởng bên trong, thấy các sắc bên ngoài màu xanh, sắc xanh, tướng xanh, ánh xanh. ",
  "dn16:3.29.4": "'Sau khi chế ngự chúng, ta biết, ta thấy', vị ấy có tưởng như vậy. ",
  "dn16:3.29.5": "Đây là thắng xứ thứ năm. ",
  "dn16:3.30.1": "Một vị không có sắc tưởng bên trong, thấy các sắc bên ngoài màu vàng, sắc vàng, tướng vàng, ánh vàng. ",
  "dn16:3.30.2": "Giống như bông hoa kaṇikāra màu vàng, sắc vàng, tướng vàng, ánh vàng. Hoặc giống như vải Ba-la-nại mịn cả hai mặt, màu vàng, sắc vàng, tướng vàng, ánh vàng. ",
  "dn16:3.30.3": "Cũng vậy, một vị không có sắc tưởng bên trong, thấy các sắc bên ngoài màu vàng, sắc vàng, tướng vàng, ánh vàng. ",
  "dn16:3.30.4": "'Sau khi chế ngự chúng, ta biết, ta thấy', vị ấy có tưởng như vậy. ",
  "dn16:3.30.5": "Đây là thắng xứ thứ sáu. ",
  "dn16:3.31.1": "Một vị không có sắc tưởng bên trong, thấy các sắc bên ngoài màu đỏ, sắc đỏ, tướng đỏ, ánh đỏ. ",
  "dn16:3.31.2": "Giống như bông hoa bandhujīvaka màu đỏ, sắc đỏ, tướng đỏ, ánh đỏ. Hoặc giống như vải Ba-la-nại mịn cả hai mặt, màu đỏ, sắc đỏ, tướng đỏ, ánh đỏ. ",
  "dn16:3.31.3": "Cũng vậy, một vị không có sắc tưởng bên trong, thấy các sắc bên ngoài màu đỏ, sắc đỏ, tướng đỏ, ánh đỏ. ",
  "dn16:3.31.4": "'Sau khi chế ngự chúng, ta biết, ta thấy', vị ấy có tưởng như vậy. ",
  "dn16:3.31.5": "Đây là thắng xứ thứ bảy. ",
  "dn16:3.32.1": "Một vị không có sắc tưởng bên trong, thấy các sắc bên ngoài màu trắng, sắc trắng, tướng trắng, ánh trắng. ",
  "dn16:3.32.2": "Giống như sao Mai màu trắng, sắc trắng, tướng trắng, ánh trắng. Hoặc giống như vải Ba-la-nại mịn cả hai mặt, màu trắng, sắc trắng, tướng trắng, ánh trắng. ",
  "dn16:3.32.3": "Cũng vậy, một vị không có sắc tưởng bên trong, thấy các sắc bên ngoài màu trắng, sắc trắng, tướng trắng, ánh trắng. ",
  "dn16:3.32.4": "'Sau khi chế ngự chúng, ta biết, ta thấy', vị ấy có tưởng như vậy. ",
  "dn16:3.32.5": "Đây là thắng xứ thứ tám. ",
  "dn16:3.32.6": "Này Ānanda, đó là tám thắng xứ. ",
  "dn16:3.33.0": "19. Tám Giải Thoát ",
  "dn16:3.33.1": "Này Ānanda, có tám giải thoát này. ",
  "dn16:3.33.2": "Tám đó là gì? ",
  "dn16:3.33.3": "Có sắc, thấy các sắc, ",
  "dn16:3.33.4": "đây là giải thoát thứ nhất. ",
  "dn16:3.33.5": "Không có sắc tưởng bên trong, thấy các sắc bên ngoài, ",
  "dn16:3.33.6": "đây là giải thoát thứ hai. ",
  "dn16:3.33.7": "Thiên về tịnh, ",
  "dn16:3.33.8": "đây là giải thoát thứ ba. ",
  "dn16:3.33.9": "Vượt hoàn toàn mọi sắc tưởng, các tưởng chướng ngại diệt đi, không tác ý đến các tưởng sai biệt, chứng và trú Không Vô Biên Xứ với ý nghĩ 'hư không là vô biên', ",
  "dn16:3.33.10": "đây là giải thoát thứ tư. ",
  "dn16:3.33.11": "Vượt hoàn toàn Không Vô Biên Xứ, chứng và trú Thức Vô Biên Xứ với ý nghĩ 'thức là vô biên', ",
  "dn16:3.33.12": "đây là giải thoát thứ năm. ",
  "dn16:3.33.13": "Vượt hoàn toàn Thức Vô Biên Xứ, chứng và trú Vô Sở Hữu Xứ với ý nghĩ 'không có gì cả', ",
  "dn16:3.33.14": "đây là giải thoát thứ sáu. ",
  "dn16:3.33.15": "Vượt hoàn toàn Vô Sở Hữu Xứ, chứng và trú Phi Tưởng Phi Phi Tưởng Xứ, ",
  "dn16:3.33.16": "đây là giải thoát thứ bảy. ",
  "dn16:3.33.17": "Vượt hoàn toàn Phi Tưởng Phi Phi Tưởng Xứ, chứng và trú Diệt Thọ Tưởng Định, ",
  "dn16:3.33.18": "đây là giải thoát thứ tám. ",
  "dn16:3.33.19": "Này Ānanda, đó là tám giải thoát. ",
  "dn16:3.33.20": "(…) ",
  "dn16:3.34.1": "Này Ānanda, một thời Ta trú tại Uruvelā, bên bờ sông Nerañjarā, dưới gốc cây đa của người chăn dê, không lâu sau khi Ta mới giác ngộ. ",
  "dn16:3.34.2": "Rồi này Ānanda, ác ma đi đến chỗ Ta; đến nơi, đứng sang một bên. Đứng sang một bên, này Ānanda, ác ma nói với Ta: ",
  "dn16:3.34.3": "'Bạch Thế Tôn, bây giờ xin Đức Thế Tôn nhập Niết Bàn, xin bậc Thiện Thệ nhập Niết Bàn, bây giờ đã đến lúc Đức Thế Tôn nhập Niết Bàn rồi.' ",
  "dn16:3.34.4": "Khi được nghe nói như vậy, này Ānanda, Ta nói với ác ma: ",
  "dn16:3.35.1": "'Này ác ma, Ta sẽ không nhập Niết Bàn chừng nào các Tỳ Kheo đệ tử của Ta chưa trở thành những người thông thạo, có kỷ luật, tự tin, đa văn, thọ trì Giáo Pháp, tu tập đúng pháp, thực hành đúng đắn, hành động đúng theo pháp; chưa học được pháp từ thầy mình rồi truyền dạy, tuyên thuyết, làm cho rõ, thiết lập, mở bày, phân tích, làm cho sáng tỏ; chưa có thể dùng chánh pháp khéo chế phục các tà thuyết ngoại đạo khởi lên, rồi thuyết pháp có tính chất thần diệu. ",
  "dn16:3.35.2": "Này ác ma, Ta sẽ không nhập Niết Bàn chừng nào các Tỳ Kheo ni đệ tử của Ta chưa trở thành những người thông thạo, có kỷ luật, tự tin, đa văn, thọ trì Giáo Pháp, tu tập đúng pháp, thực hành đúng đắn, hành động đúng theo pháp; chưa học được pháp từ thầy mình rồi truyền dạy, tuyên thuyết, làm cho rõ, thiết lập, mở bày, phân tích, làm cho sáng tỏ; chưa có thể dùng chánh pháp khéo chế phục các tà thuyết ngoại đạo khởi lên, rồi thuyết pháp có tính chất thần diệu. ",
  "dn16:3.35.3": "Này ác ma, Ta sẽ không nhập Niết Bàn chừng nào các nam cư sĩ đệ tử của Ta chưa trở thành những người thông thạo, có kỷ luật, tự tin, đa văn, thọ trì Giáo Pháp, tu tập đúng pháp, thực hành đúng đắn, hành động đúng theo pháp; chưa học được pháp từ thầy mình rồi truyền dạy, tuyên thuyết, làm cho rõ, thiết lập, mở bày, phân tích, làm cho sáng tỏ; chưa có thể dùng chánh pháp khéo chế phục các tà thuyết ngoại đạo khởi lên, rồi thuyết pháp có tính chất thần diệu. ",
  "dn16:3.35.4": "Này ác ma, Ta sẽ không nhập Niết Bàn chừng nào các nữ cư sĩ đệ tử của Ta chưa trở thành những người thông thạo, có kỷ luật, tự tin, đa văn, thọ trì Giáo Pháp, tu tập đúng pháp, thực hành đúng đắn, hành động đúng theo pháp; chưa học được pháp từ thầy mình rồi truyền dạy, tuyên thuyết, làm cho rõ, thiết lập, mở bày, phân tích, làm cho sáng tỏ; chưa có thể dùng chánh pháp khéo chế phục các tà thuyết ngoại đạo khởi lên, rồi thuyết pháp có tính chất thần diệu. ",
  "dn16:3.35.5": "Này ác ma, Ta sẽ không nhập Niết Bàn chừng nào phạm hạnh của Ta chưa hưng thịnh, phát triển, phổ biến rộng rãi, được nhiều người biết đến, chưa được tuyên thuyết rộng rãi cho chư thiên và loài người.' ",
  "dn16:3.36.1": "Vừa rồi đây, này Ānanda, hôm nay tại đền Cāpāla, ác ma đi đến chỗ Ta; đến nơi, đứng sang một bên. Đứng sang một bên, này Ānanda, ác ma nói với Ta: ",
  "dn16:3.36.2": "'Bạch Thế Tôn, bây giờ xin Đức Thế Tôn nhập Niết Bàn, xin bậc Thiện Thệ nhập Niết Bàn, bây giờ đã đến lúc Đức Thế Tôn nhập Niết Bàn rồi. ",
  "dn16:3.36.3": "Bạch Thế Tôn, Đức Thế Tôn đã từng nói lời này: ",
  "dn16:3.36.4": "\"Này ác ma, Ta sẽ không nhập Niết Bàn chừng nào các Tỳ Kheo đệ tử của Ta chưa …vân vân… ",
  "dn16:3.36.5": "chừng nào các Tỳ Kheo ni đệ tử của Ta chưa …vân vân… ",
  "dn16:3.36.6": "chừng nào các nam cư sĩ đệ tử của Ta chưa …vân vân… ",
  "dn16:3.36.7": "chừng nào các nữ cư sĩ đệ tử của Ta chưa …vân vân… ",
  "dn16:3.36.8": "chừng nào phạm hạnh của Ta chưa hưng thịnh, phát triển, phổ biến rộng rãi, được nhiều người biết đến, chưa được tuyên thuyết rộng rãi cho chư thiên và loài người.\" ",
  "dn16:3.36.9": "Bạch Thế Tôn, nay phạm hạnh của Đức Thế Tôn đã hưng thịnh, phát triển, phổ biến rộng rãi, được nhiều người biết đến, đã được tuyên thuyết rộng rãi cho chư thiên và loài người. ",
  "dn16:3.36.10": "Bạch Thế Tôn, bây giờ xin Đức Thế Tôn nhập Niết Bàn, xin bậc Thiện Thệ nhập Niết Bàn, bây giờ đã đến lúc Đức Thế Tôn nhập Niết Bàn rồi.' ",
  "dn16:3.37.1": "Khi được nghe nói như vậy, này Ānanda, Ta nói với ác ma: ",
  "dn16:3.37.2": "'Này ác ma, ngươi hãy yên tâm, không lâu nữa Như Lai sẽ nhập Niết Bàn. ",
  "dn16:3.37.3": "Ba tháng kể từ bây giờ, Như Lai sẽ nhập Niết Bàn.' ",
  "dn16:3.37.4": "Vừa rồi đây, này Ānanda, hôm nay tại đền Cāpāla, Như Lai chánh niệm, tỉnh giác, đã từ bỏ thọ hành.\" ",
  "dn16:3.38.0": "20. Lời Khẩn Cầu Của Ānanda ",
  "dn16:3.38.1": "Khi được nghe nói như vậy, Tôn giả Ānanda bạch Đức Thế Tôn: ",
  "dn16:3.38.2": "\"Bạch Thế Tôn, xin Đức Thế Tôn hãy sống trọn một kiếp, xin bậc Thiện Thệ hãy sống trọn một kiếp, vì lợi ích cho đại chúng, vì an lạc cho đại chúng, vì thương tưởng cho đời, vì lợi ích, vì hạnh phúc, vì an lạc cho chư thiên và loài người.\" ",
  "dn16:3.38.3": "\"Này Ānanda, thôi đủ rồi. ",
  "dn16:3.38.4": "Đừng xin Như Lai nữa, này Ānanda, bây giờ không phải là lúc để xin Như Lai.\" ",
  "dn16:3.39.1": "Lần thứ hai, Tôn giả Ānanda …vân vân… ",
  "dn16:3.39.2": "lần thứ ba, Tôn giả Ānanda bạch Đức Thế Tôn: ",
  "dn16:3.39.3": "\"Bạch Thế Tôn, xin Đức Thế Tôn hãy sống trọn một kiếp, xin bậc Thiện Thệ hãy sống trọn một kiếp, vì lợi ích cho đại chúng, vì an lạc cho đại chúng, vì thương tưởng cho đời, vì lợi ích, vì hạnh phúc, vì an lạc cho chư thiên và loài người.\" ",
  "dn16:3.39.4": "\"Này Ānanda, ngươi có tin vào sự giác ngộ của Như Lai không?\" ",
  "dn16:3.39.5": "\"Thưa có, bạch Thế Tôn.\" ",
  "dn16:3.39.6": "\"Vậy sao, này Ānanda, ngươi còn ba lần ép buộc Như Lai?\" ",
  "dn16:3.40.1": "\"Bạch Thế Tôn, chính con đã tận miệng nghe, tận mặt nhận từ Đức Thế Tôn: ",
  "dn16:3.40.2": "'Này Ānanda, người nào đã tu tập, làm cho sung mãn, làm thành cỗ xe, làm thành nền tảng, vận dụng, tích lũy, khéo kiên trì bốn như ý túc, thì người ấy nếu muốn, có thể sống trọn một kiếp hoặc phần còn lại của một kiếp. ",
  "dn16:3.40.3": "Này Ānanda, Như Lai đã tu tập, làm cho sung mãn, làm thành cỗ xe, làm thành nền tảng, vận dụng, tích lũy, khéo kiên trì bốn như ý túc. Vậy này Ānanda, Như Lai nếu muốn, có thể sống trọn một kiếp hoặc phần còn lại của một kiếp.'\" ",
  "dn16:3.40.4": "\"Này Ānanda, ngươi có tin không?\" ",
  "dn16:3.40.5": "\"Thưa có, bạch Thế Tôn.\" ",
  "dn16:3.40.6": "\"Vậy, này Ānanda, đó chính là lỗi của ngươi, đó là sai lầm của ngươi, vì ngươi đã không thể nhận ra được khi Như Lai đã đưa ra dấu hiệu rõ ràng, gợi ý rõ ràng như vậy, không thỉnh cầu Như Lai: ",
  "dn16:3.40.7": "'Bạch Thế Tôn, xin Đức Thế Tôn hãy sống trọn một kiếp, xin bậc Thiện Thệ hãy sống trọn một kiếp, vì lợi ích cho đại chúng, vì an lạc cho đại chúng, vì thương tưởng cho đời, vì lợi ích, vì hạnh phúc, vì an lạc cho chư thiên và loài người.' ",
  "dn16:3.40.8": "Này Ānanda, nếu ngươi đã thỉnh cầu Như Lai, Như Lai có thể đã từ chối hai lần, nhưng đến lần thứ ba sẽ nhận lời. ",
  "dn16:3.40.9": "Vậy, này Ānanda, đó chính là lỗi của ngươi, đó là sai lầm của ngươi. ",
  "dn16:3.41.1": "Này Ānanda, một thời Ta trú tại thành Vương Xá, trên núi Linh Thứu. ",
  "dn16:3.41.2": "Tại đó, này Ānanda, Ta đã nói với ngươi: ",
  "dn16:3.41.3": "'Này Ānanda, thành Vương Xá thật đáng yêu, núi Linh Thứu thật đáng yêu. ",
  "dn16:3.41.4": "Này Ānanda, người nào đã tu tập, làm cho sung mãn, làm thành cỗ xe, làm thành nền tảng, vận dụng, tích lũy, khéo kiên trì bốn như ý túc, thì người ấy nếu muốn, có thể sống trọn một kiếp hoặc phần còn lại của một kiếp. ",
  "dn16:3.41.5": "Này Ānanda, Như Lai đã tu tập, làm cho sung mãn, làm thành cỗ xe, làm thành nền tảng, vận dụng, tích lũy, khéo kiên trì bốn như ý túc, vậy này Ānanda, Như Lai nếu muốn, có thể sống trọn một kiếp hoặc phần còn lại của một kiếp.' ",
  "dn16:3.41.6": "Ngay cả khi Như Lai đã đưa ra dấu hiệu rõ ràng, đã gợi ý rõ ràng như vậy, này Ānanda, ngươi vẫn không thể nhận ra, không thỉnh cầu Như Lai: ",
  "dn16:3.41.7": "'Bạch Thế Tôn, xin Đức Thế Tôn hãy sống trọn một kiếp, xin bậc Thiện Thệ hãy sống trọn một kiếp, vì lợi ích cho đại chúng, vì an lạc cho đại chúng, vì thương tưởng cho đời, vì lợi ích, vì hạnh phúc, vì an lạc cho chư thiên và loài người.' ",
  "dn16:3.41.8": "Này Ānanda, nếu ngươi đã thỉnh cầu Như Lai, Như Lai có thể đã từ chối hai lần, nhưng đến lần thứ ba sẽ nhận lời. ",
  "dn16:3.41.9": "Vậy, này Ānanda, đó chính là lỗi của ngươi, đó là sai lầm của ngươi. ",
  "dn16:3.42.1": "Này Ānanda, một thời Ta cũng trú tại thành Vương Xá, dưới cây đa Gotama …vân vân… ",
  "dn16:3.42.2": "cũng trú tại thành Vương Xá, tại vách núi Corapapāta … ",
  "dn16:3.42.3": "cũng trú tại thành Vương Xá, bên sườn núi Vebhāra, trong hang Sattapaṇṇi … ",
  "dn16:3.42.4": "cũng trú tại thành Vương Xá, bên sườn núi Isigili, trên tảng đá Kāḷasilā … ",
  "dn16:3.42.5": "cũng trú tại thành Vương Xá, trong rừng Sītavana, trong hang Sappasoṇḍika … ",
  "dn16:3.42.6": "cũng trú tại thành Vương Xá, trong vườn Tapoda … ",
  "dn16:3.42.7": "cũng trú tại thành Vương Xá, trong vườn trúc, tại chỗ cho sóc ăn … ",
  "dn16:3.42.8": "cũng trú tại thành Vương Xá, trong vườn xoài của Jīvaka … ",
  "dn16:3.42.9": "cũng trú tại thành Vương Xá, tại khu săn nai Maddakucchi. ",
  "dn16:3.43.1": "Tại đó, này Ānanda, Ta đã nói với ngươi: ",
  "dn16:3.43.2": "'Này Ānanda, thành Vương Xá thật đáng yêu, núi Linh Thứu thật đáng yêu, cây đa Gotama thật đáng yêu, vách núi Corapapāta thật đáng yêu, hang Sattapaṇṇi bên sườn núi Vebhāra thật đáng yêu, tảng đá Kāḷasilā bên sườn núi Isigili thật đáng yêu, hang Sappasoṇḍika trong rừng Sītavana thật đáng yêu, vườn Tapoda thật đáng yêu, chỗ cho sóc ăn trong vườn trúc thật đáng yêu, vườn xoài Jīvaka thật đáng yêu, khu săn nai Maddakucchi thật đáng yêu. ",
  "dn16:3.44.1": "Này Ānanda, người nào đã tu tập, làm cho sung mãn, làm thành cỗ xe, làm thành nền tảng, vận dụng, tích lũy, khéo kiên trì bốn như ý túc …vân vân… ",
  "dn16:3.44.2": "vậy này Ānanda, Như Lai nếu muốn, có thể sống trọn một kiếp hoặc phần còn lại của một kiếp.' ",
  "dn16:3.44.3": "Ngay cả khi Như Lai đã đưa ra dấu hiệu rõ ràng, đã gợi ý rõ ràng như vậy, này Ānanda, ngươi vẫn không thể nhận ra, không thỉnh cầu Như Lai: ",
  "dn16:3.44.4": "'Bạch Thế Tôn, xin Đức Thế Tôn hãy sống trọn một kiếp, xin bậc Thiện Thệ hãy sống trọn một kiếp, vì lợi ích cho đại chúng, vì an lạc cho đại chúng, vì thương tưởng cho đời, vì lợi ích, vì hạnh phúc, vì an lạc cho chư thiên và loài người.' ",
  "dn16:3.44.5": "Này Ānanda, nếu ngươi đã thỉnh cầu Như Lai, Như Lai có thể đã từ chối hai lần, nhưng đến lần thứ ba sẽ nhận lời. ",
  "dn16:3.44.6": "Vậy, này Ānanda, đó chính là lỗi của ngươi, đó là sai lầm của ngươi. ",
  "dn16:3.45.1": "Này Ānanda, một thời Ta cũng trú tại Vesāli, ở đền Udena. ",
  "dn16:3.45.2": "Tại đó, này Ānanda, Ta đã nói với ngươi: ",
  "dn16:3.45.3": "'Này Ānanda, Vesāli thật đáng yêu, đền Udena thật đáng yêu. ",
  "dn16:3.45.4": "Này Ānanda, người nào đã tu tập, làm cho sung mãn, làm thành cỗ xe, làm thành nền tảng, vận dụng, tích lũy, khéo kiên trì bốn như ý túc, thì người ấy nếu muốn, có thể sống trọn một kiếp hoặc phần còn lại của một kiếp. ",
  "dn16:3.45.5": "Này Ānanda, Như Lai đã tu tập, làm cho sung mãn, làm thành cỗ xe, làm thành nền tảng, vận dụng, tích lũy, khéo kiên trì bốn như ý túc, vậy này Ānanda, Như Lai nếu muốn, có thể sống trọn một kiếp hoặc phần còn lại của một kiếp.' ",
  "dn16:3.45.6": "Ngay cả khi Như Lai đã đưa ra dấu hiệu rõ ràng, đã gợi ý rõ ràng như vậy, này Ānanda, ngươi vẫn không thể nhận ra, không thỉnh cầu Như Lai: ",
  "dn16:3.45.7": "'Bạch Thế Tôn, xin Đức Thế Tôn hãy sống trọn một kiếp, xin bậc Thiện Thệ hãy sống trọn một kiếp, vì lợi ích cho đại chúng, vì an lạc cho đại chúng, vì thương tưởng cho đời, vì lợi ích, vì hạnh phúc, vì an lạc cho chư thiên và loài người.' ",
  "dn16:3.45.8": "Này Ānanda, nếu ngươi đã thỉnh cầu Như Lai, Như Lai có thể đã từ chối hai lần, nhưng đến lần thứ ba sẽ nhận lời. Vậy, này Ānanda, đó chính là lỗi của ngươi, đó là sai lầm của ngươi. ",
  "dn16:3.46.1": "Này Ānanda, một thời Ta cũng trú tại Vesāli, ở đền Gotamaka …vân vân… ",
  "dn16:3.46.2": "cũng trú tại Vesāli, ở đền Sattamba … ",
  "dn16:3.46.3": "cũng trú tại Vesāli, ở đền Bahuputta … ",
  "dn16:3.46.4": "cũng trú tại Vesāli, ở đền Sārandada … ",
  "dn16:3.47.1": "Vừa rồi đây, này Ānanda, hôm nay tại đền Cāpāla, Ta đã nói với ngươi: ",
  "dn16:3.47.2": "'Này Ānanda, Vesāli thật đáng yêu, đền Udena thật đáng yêu, đền Gotamaka thật đáng yêu, đền Sattamba thật đáng yêu, đền Bahuputta thật đáng yêu, đền Sārandada thật đáng yêu, đền Cāpāla thật đáng yêu. ",
  "dn16:3.47.3": "Này Ānanda, người nào đã tu tập, làm cho sung mãn, làm thành cỗ xe, làm thành nền tảng, vận dụng, tích lũy, khéo kiên trì bốn như ý túc, thì người ấy nếu muốn, có thể sống trọn một kiếp hoặc phần còn lại của một kiếp. ",
  "dn16:3.47.4": "Này Ānanda, Như Lai đã tu tập, làm cho sung mãn, làm thành cỗ xe, làm thành nền tảng, vận dụng, tích lũy, khéo kiên trì bốn như ý túc, vậy này Ānanda, Như Lai nếu muốn, có thể sống trọn một kiếp hoặc phần còn lại của một kiếp.' ",
  "dn16:3.47.5": "Ngay cả khi Như Lai đã đưa ra dấu hiệu rõ ràng, đã gợi ý rõ ràng như vậy, này Ānanda, ngươi vẫn không thể nhận ra, không thỉnh cầu Như Lai: ",
  "dn16:3.47.6": "'Xin Đức Thế Tôn hãy sống trọn một kiếp, xin bậc Thiện Thệ hãy sống trọn một kiếp, vì lợi ích cho đại chúng, vì an lạc cho đại chúng, vì thương tưởng cho đời, vì lợi ích, vì hạnh phúc, vì an lạc cho chư thiên và loài người.' ",
  "dn16:3.47.7": "Này Ānanda, nếu ngươi đã thỉnh cầu Như Lai, Như Lai có thể đã từ chối hai lần, nhưng đến lần thứ ba sẽ nhận lời. ",
  "dn16:3.47.8": "Vậy, này Ānanda, đó chính là lỗi của ngươi, đó là sai lầm của ngươi. ",
  "dn16:3.48.1": "Này Ānanda, chẳng phải Ta đã nói trước kia rằng: ",
  "dn16:3.48.2": "'Tất cả những gì thân yêu, vừa lòng đều phải chia lìa, phân tán, biến đổi. ",
  "dn16:3.48.3": "Này Ānanda, làm sao có thể được điều này, rằng cái gì đã sinh, đã thành, bị tạo tác, phải hoại diệt, mà lại không hoại diệt—điều đó không thể có được'? ",
  "dn16:3.48.4": "Này Ānanda, cái mà Như Lai đã từ bỏ, đã nhả ra, đã giải thoát, đã đoạn trừ, đã xả ly, từ bỏ thọ hành, lời đã tuyên bố dứt khoát: ",
  "dn16:3.48.5": "'Không lâu nữa Như Lai sẽ nhập Niết Bàn. ",
  "dn16:3.48.6": "Ba tháng kể từ bây giờ, Như Lai sẽ nhập Niết Bàn.' ",
  "dn16:3.48.7": "Việc Như Lai vì lý do mạng sống mà rút lại lời ấy là điều không thể có được. ",
  "dn16:3.48.8": "Này Ānanda, chúng ta hãy đi đến giảng đường trong Đại Lâm.\" ",
  "dn16:3.48.9": "\"Thưa vâng, bạch Thế Tôn\", Tôn giả Ānanda vâng lời Đức Thế Tôn. ",
  "dn16:3.49.1": "Rồi Đức Thế Tôn cùng với Tôn giả Ānanda đi đến giảng đường trong Đại Lâm; đến nơi, Ngài gọi Tôn giả Ānanda: ",
  "dn16:3.49.2": "\"Này Ānanda, hãy đi triệu tập tất cả các Tỳ Kheo hiện đang cư trú quanh Vesāli đến tập trung tại giảng đường.\" ",
  "dn16:3.49.3": "\"Thưa vâng, bạch Thế Tôn\", Tôn giả Ānanda vâng lời Đức Thế Tôn, đi triệu tập tất cả các Tỳ Kheo hiện đang cư trú quanh Vesāli đến tập trung tại giảng đường, rồi đến chỗ Đức Thế Tôn; đến nơi, đảnh lễ Đức Thế Tôn rồi đứng sang một bên. Đứng sang một bên, Tôn giả Ānanda bạch Đức Thế Tôn: ",
  "dn16:3.49.4": "\"Bạch Thế Tôn, chúng Tỳ Kheo đã tập trung đông đủ. Nay xin Đức Thế Tôn hãy làm những gì Ngài thấy đúng thời.\" ",
  "dn16:3.49.5": "(…) ",
  "dn16:3.50.1": "Rồi Đức Thế Tôn đi đến giảng đường; đến nơi, ngồi xuống chỗ đã soạn sẵn. ",
  "dn16:3.50.2": "Ngồi xong, Đức Thế Tôn gọi các Tỳ Kheo: ",
  "dn16:3.50.3": "\"Vì vậy, này các Tỳ Kheo, các pháp Ta đã chứng ngộ với thắng trí và giảng dạy cho các ông, các ông hãy khéo học thuộc, thực hành, tu tập, làm cho sung mãn, để phạm hạnh được tồn tại lâu dài, bền vững, vì lợi ích cho đại chúng, vì an lạc cho đại chúng, vì thương tưởng cho đời, vì lợi ích, vì hạnh phúc, vì an lạc cho chư thiên và loài người. ",
  "dn16:3.50.4": "Và này các Tỳ Kheo, những pháp Ta đã chứng ngộ với thắng trí và giảng dạy cho các ông, mà các ông phải khéo học thuộc, thực hành, tu tập, làm cho sung mãn, để phạm hạnh được tồn tại lâu dài, bền vững, vì lợi ích cho đại chúng, vì an lạc cho đại chúng, vì thương tưởng cho đời, vì lợi ích, vì hạnh phúc, vì an lạc cho chư thiên và loài người là những pháp gì? ",
  "dn16:3.50.5": "Đó là—bốn niệm xứ, bốn chánh cần, bốn như ý túc, năm căn, năm lực, bảy giác chi, Bát Thánh Đạo. ",
  "dn16:3.51.1": "Này các Tỳ Kheo, đây là những pháp Ta đã chứng ngộ với thắng trí và giảng dạy cho các ông, mà các ông phải khéo học thuộc, thực hành, tu tập, làm cho sung mãn, để phạm hạnh được tồn tại lâu dài, bền vững, vì lợi ích cho đại chúng, vì an lạc cho đại chúng, vì thương tưởng cho đời, vì lợi ích, vì hạnh phúc, vì an lạc cho chư thiên và loài người.\" ",
  "dn16:3.51.2": "Rồi Đức Thế Tôn gọi các Tỳ Kheo: ",
  "dn16:3.51.3": "\"Này các Tỳ Kheo, nay Ta nói với các ông, ",
  "dn16:3.51.4": "các pháp hữu vi là vô thường, hãy tinh cần không buông lung. ",
  "dn16:3.51.5": "Không lâu nữa Như Lai sẽ nhập Niết Bàn. ",
  "dn16:3.51.6": "Ba tháng kể từ bây giờ, Như Lai sẽ nhập Niết Bàn.\" ",
  "dn16:3.51.7": "Đức Thế Tôn nói như vậy. ",
  "dn16:3.51.8": "Sau khi nói như vậy, bậc Thiện Thệ, bậc Đạo Sư còn nói thêm: ",
  "dn16:3.51.9": "\"Tuổi Ta đã chín rồi, ",
  "dn16:3.51.10": "Mạng Ta không còn dài; ",
  "dn16:3.51.11": "Ta sẽ từ biệt các ông mà đi, ",
  "dn16:3.51.12": "Ta đã làm xong chỗ nương tựa cho chính mình. ",
  "dn16:3.51.13": "Hãy không buông lung, có chánh niệm, ",
  "dn16:3.51.14": "Hãy khéo giữ giới, các Tỳ Kheo; ",
  "dn16:3.51.15": "Với tư duy khéo an trú, ",
  "dn16:3.51.16": "Hãy phòng hộ tâm mình. ",
  "dn16:3.51.17": "Ai trong Pháp và Luật này, ",
  "dn16:3.51.18": "Sống không buông lung; ",
  "dn16:3.51.19": "Sẽ từ bỏ vòng sinh tử, ",
  "dn16:3.51.20": "Chấm dứt mọi khổ đau.\" ",
  "dn16:3.51.21": "Hết phần tụng đọc thứ ba. ",
  "dn16:4.1.0": "21. Cái Nhìn Của Con Voi ",
  "dn16:4.1.1": "Rồi vào buổi sáng, Đức Thế Tôn đắp y, cầm y bát, đi vào Vesāli để khất thực. ",
  "dn16:4.1.2": "Sau khi khất thực ở Vesāli, sau bữa ăn, trên đường khất thực trở về, Ngài ngoảnh lại nhìn Vesāli bằng cái nhìn của con voi, rồi gọi Tôn giả Ānanda: ",
  "dn16:4.1.3": "\"Này Ānanda, đây là lần cuối cùng Như Lai nhìn Vesāli. ",
  "dn16:4.1.4": "Này Ānanda, chúng ta hãy đi đến làng Bhaṇḍagāma.\" ",
  "dn16:4.1.5": "\"Thưa vâng, bạch Thế Tôn\", Tôn giả Ānanda vâng lời Đức Thế Tôn. ",
  "dn16:4.2.1": "Rồi Đức Thế Tôn cùng với đại chúng Tỳ Kheo đi đến làng Bhaṇḍagāma. ",
  "dn16:4.2.2": "Tại đó, Đức Thế Tôn trú ở làng Bhaṇḍagāma. ",
  "dn16:4.2.3": "Tại đó, Đức Thế Tôn gọi các Tỳ Kheo: ",
  "dn16:4.2.4": "\"Này các Tỳ Kheo, do không giác ngộ, không thâm nhập bốn pháp, mà Ta và các ông đã phải lưu chuyển, luân hồi trong vòng sinh tử lâu dài như vậy. ",
  "dn16:4.2.5": "Bốn đó là gì? ",
  "dn16:4.2.6": "Này các Tỳ Kheo, do không giác ngộ, không thâm nhập Thánh giới, mà Ta và các ông đã phải lưu chuyển, luân hồi trong vòng sinh tử lâu dài như vậy. ",
  "dn16:4.2.7": "Này các Tỳ Kheo, do không giác ngộ, không thâm nhập Thánh định, mà Ta và các ông đã phải lưu chuyển, luân hồi trong vòng sinh tử lâu dài như vậy. ",
  "dn16:4.2.8": "Này các Tỳ Kheo, do không giác ngộ, không thâm nhập Thánh tuệ, mà Ta và các ông đã phải lưu chuyển, luân hồi trong vòng sinh tử lâu dài như vậy. ",
  "dn16:4.2.9": "Này các Tỳ Kheo, do không giác ngộ, không thâm nhập Thánh giải thoát, mà Ta và các ông đã phải lưu chuyển, luân hồi trong vòng sinh tử lâu dài như vậy. ",
  "dn16:4.2.10": "Này các Tỳ Kheo, nay Thánh giới đã được giác ngộ, thâm nhập; Thánh định đã được giác ngộ, thâm nhập; Thánh tuệ đã được giác ngộ, thâm nhập; Thánh giải thoát đã được giác ngộ, thâm nhập; hữu ái đã đoạn, dây dẫn đến tái sanh đã tận, không còn tái sanh nữa.\" ",
  "dn16:4.3.1": "Đức Thế Tôn nói như vậy. ",
  "dn16:4.3.2": "Sau khi nói như vậy, bậc Thiện Thệ, bậc Đạo Sư còn nói thêm: ",
  "dn16:4.3.3": "\"Giới, định và trí tuệ, ",
  "dn16:4.3.4": "Cùng giải thoát vô thượng; ",
  "dn16:4.3.5": "Các pháp này đã được giác ngộ, ",
  "dn16:4.3.6": "Bởi Gotama nổi tiếng. ",
  "dn16:4.3.7": "Như vậy, Đức Phật với thắng trí, ",
  "dn16:4.3.8": "Đã tuyên thuyết Pháp cho các Tỳ Kheo; ",
  "dn16:4.3.9": "Đạo Sư chấm dứt khổ đau, ",
  "dn16:4.3.10": "Bậc Hữu Nhãn đã nhập Niết Bàn.\" ",
  "dn16:4.4.1": "Tại đó, khi trú ở làng Bhaṇḍagāma, Đức Thế Tôn thường xuyên thuyết pháp cho các Tỳ Kheo như sau: ",
  "dn16:4.4.2": "\"Đây là giới, đây là định, đây là tuệ. ",
  "dn16:4.4.3": "Định được tu tập bằng giới sẽ đem lại quả lớn, lợi ích lớn. ",
  "dn16:4.4.4": "Tuệ được tu tập bằng định sẽ đem lại quả lớn, lợi ích lớn. ",
  "dn16:4.4.5": "Tâm được tu tập bằng tuệ sẽ hoàn toàn giải thoát khỏi các lậu hoặc, đó là—",
  "dn16:4.4.6": "dục lậu, hữu lậu, vô minh lậu.\" ",
  "dn16:4.5.0": "22. Bài Pháp Về Bốn Đại Giáo Pháp ",
  "dn16:4.5.1": "Rồi sau khi trú tại làng Bhaṇḍagāma một thời gian vừa ý, Đức Thế Tôn gọi Tôn giả Ānanda: ",
  "dn16:4.5.2": "\"Này Ānanda, chúng ta hãy đi đến làng Hatthi, ",
  "dn16:4.5.3": "đến làng Amba, ",
  "dn16:4.5.4": "đến làng Jambu, ",
  "dn16:4.5.5": "đến thành Bhoga.\" ",
  "dn16:4.6.1": "\"Thưa vâng, bạch Thế Tôn\", Tôn giả Ānanda vâng lời Đức Thế Tôn. ",
  "dn16:4.6.2": "Rồi Đức Thế Tôn cùng với đại chúng Tỳ Kheo đi đến thành Bhoga. ",
  "dn16:4.7.1": "Tại đó, Đức Thế Tôn trú ở thành Bhoga, tại đền Ānanda. ",
  "dn16:4.7.2": "Tại đó, Đức Thế Tôn gọi các Tỳ Kheo: ",
  "dn16:4.7.3": "\"Này các Tỳ Kheo, Ta sẽ dạy bốn Đại Giáo Pháp này. ",
  "dn16:4.7.4": "Hãy lắng nghe, hãy khéo tác ý, Ta sẽ giảng.\" ",
  "dn16:4.7.5": "\"Thưa vâng, bạch Thế Tôn\", các Tỳ Kheo đáp lời Đức Thế Tôn. ",
  "dn16:4.7.6": "Đức Thế Tôn dạy như sau: ",
  "dn16:4.8.1": "\"Này các Tỳ Kheo, ở đây một Tỳ Kheo có thể nói như sau: ",
  "dn16:4.8.2": "'Thưa các hiền giả, chính tôi đã tận miệng nghe, tận mặt nhận từ Đức Thế Tôn: ",
  "dn16:4.8.3": "đây là Pháp, đây là Luật, đây là lời dạy của Đức Đạo Sư.' ",
  "dn16:4.8.4": "Này các Tỳ Kheo, lời nói của vị Tỳ Kheo ấy không nên vội tin cũng không nên vội bác bỏ. ",
  "dn16:4.8.5": "Không vội tin, không vội bác bỏ, hãy khéo học thuộc từng chữ từng câu rồi đem đối chiếu với Kinh, đem so sánh với Luật. ",
  "dn16:4.8.6": "Nếu khi đối chiếu với Kinh, so sánh với Luật, những câu chữ ấy không phù hợp với Kinh, không phù hợp với Luật, thì nên đi đến kết luận: ",
  "dn16:4.8.7": "'Chắc chắn đây không phải là lời của Đức Thế Tôn; ",
  "dn16:4.8.8": "vị Tỳ Kheo ấy đã hiểu sai.' ",
  "dn16:4.8.9": "Và như vậy, này các Tỳ Kheo, các ông hãy loại bỏ nó. ",
  "dn16:4.8.10": "Nếu khi đối chiếu với Kinh, so sánh với Luật, những câu chữ ấy phù hợp với Kinh, phù hợp với Luật, thì nên đi đến kết luận: ",
  "dn16:4.8.11": "'Chắc chắn đây là lời của Đức Thế Tôn; ",
  "dn16:4.8.12": "vị Tỳ Kheo ấy đã hiểu đúng.' ",
  "dn16:4.8.13": "Này các Tỳ Kheo, hãy ghi nhớ đây là Đại Giáo Pháp thứ nhất. ",
  "dn16:4.9.1": "Lại nữa, này các Tỳ Kheo, ở đây một Tỳ Kheo có thể nói như sau: ",
  "dn16:4.9.2": "'Tại một trú xứ nọ, có Tăng chúng cùng các vị trưởng lão, các vị thượng tọa đang cư trú. ",
  "dn16:4.9.3": "Tôi đã tận miệng nghe, tận mặt nhận từ Tăng chúng ấy: ",
  "dn16:4.9.4": "đây là Pháp, đây là Luật, đây là lời dạy của Đức Đạo Sư.' ",
  "dn16:4.9.5": "Này các Tỳ Kheo, lời nói của vị Tỳ Kheo ấy không nên vội tin cũng không nên vội bác bỏ. ",
  "dn16:4.9.6": "Không vội tin, không vội bác bỏ, hãy khéo học thuộc từng chữ từng câu rồi đem đối chiếu với Kinh, đem so sánh với Luật. ",
  "dn16:4.9.7": "Nếu khi đối chiếu với Kinh, so sánh với Luật, những câu chữ ấy không phù hợp với Kinh, không phù hợp với Luật, thì nên đi đến kết luận: ",
  "dn16:4.9.8": "'Chắc chắn đây không phải là lời của Đức Thế Tôn; ",
  "dn16:4.9.9": "Tăng chúng ấy đã hiểu sai.' ",
  "dn16:4.9.10": "Và như vậy, này các Tỳ Kheo, các ông hãy loại bỏ nó. ",
  "dn16:4.9.11": "Nếu khi đối chiếu với Kinh, so sánh với Luật, những câu chữ ấy phù hợp với Kinh, phù hợp với Luật, thì nên đi đến kết luận: ",
  "dn16:4.9.12": "'Chắc chắn đây là lời của Đức Thế Tôn; ",
  "dn16:4.9.13": "Tăng chúng ấy đã hiểu đúng.' ",
  "dn16:4.9.14": "Này các Tỳ Kheo, hãy ghi nhớ đây là Đại Giáo Pháp thứ hai. ",
  "dn16:4.10.1": "Lại nữa, này các Tỳ Kheo, ở đây một Tỳ Kheo có thể nói như sau: ",
  "dn16:4.10.2": "'Tại một trú xứ nọ, có nhiều vị Tỳ Kheo trưởng lão đang cư trú, các vị đa văn, thuộc các bộ A-hàm, thọ trì Pháp, thọ trì Luật, thọ trì Mātikā. ",
  "dn16:4.10.3": "Tôi đã tận miệng nghe, tận mặt nhận từ các vị trưởng lão ấy—",
  "dn16:4.10.4": "đây là Pháp, đây là Luật, đây là lời dạy của Đức Đạo Sư.' ",
  "dn16:4.10.5": "Này các Tỳ Kheo, lời nói của vị Tỳ Kheo ấy không nên vội tin … ",
  "dn16:4.10.6": "vân vân… ",
  "dn16:4.10.7": "không phù hợp với Luật, thì nên đi đến kết luận: ",
  "dn16:4.10.8": "'Chắc chắn đây không phải là lời của Đức Thế Tôn; ",
  "dn16:4.10.9": "các vị trưởng lão ấy đã hiểu sai.' ",
  "dn16:4.10.10": "Và như vậy, này các Tỳ Kheo, các ông hãy loại bỏ nó. ",
  "dn16:4.10.11": "Nếu khi đối chiếu với Kinh …vân vân… ",
  "dn16:4.10.12": "phù hợp với Luật, thì nên đi đến kết luận: ",
  "dn16:4.10.13": "'Chắc chắn đây là lời của Đức Thế Tôn; ",
  "dn16:4.10.14": "các vị trưởng lão ấy đã hiểu đúng.' ",
  "dn16:4.10.15": "Này các Tỳ Kheo, hãy ghi nhớ đây là Đại Giáo Pháp thứ ba. ",
  "dn16:4.11.1": "Lại nữa, này các Tỳ Kheo, ở đây một Tỳ Kheo có thể nói như sau: ",
  "dn16:4.11.2": "'Tại một trú xứ nọ, có một vị Tỳ Kheo trưởng lão đang cư trú, là vị đa văn, thuộc các bộ A-hàm, thọ trì Pháp, thọ trì Luật, thọ trì Mātikā. ",
  "dn16:4.11.3": "Tôi đã tận miệng nghe, tận mặt nhận từ vị trưởng lão ấy—",
  "dn16:4.11.4": "đây là Pháp, đây là Luật, đây là lời dạy của Đức Đạo Sư.' ",
  "dn16:4.11.5": "Này các Tỳ Kheo, lời nói của vị Tỳ Kheo ấy không nên vội tin cũng không nên vội bác bỏ. ",
  "dn16:4.11.6": "Không vội tin, không vội bác bỏ, hãy khéo học thuộc từng chữ từng câu rồi đem đối chiếu với Kinh, đem so sánh với Luật. ",
  "dn16:4.11.7": "Nếu khi đối chiếu với Kinh, so sánh với Luật, những câu chữ ấy không phù hợp với Kinh, không phù hợp với Luật, thì nên đi đến kết luận: ",
  "dn16:4.11.8": "'Chắc chắn đây không phải là lời của Đức Thế Tôn; ",
  "dn16:4.11.9": "vị trưởng lão ấy đã hiểu sai.' ",
  "dn16:4.11.10": "Và như vậy, này các Tỳ Kheo, các ông hãy loại bỏ nó. ",
  "dn16:4.11.11": "Nếu khi đối chiếu với Kinh, so sánh với Luật, những câu chữ ấy phù hợp với Kinh, phù hợp với Luật, thì nên đi đến kết luận: ",
  "dn16:4.11.12": "'Chắc chắn đây là lời của Đức Thế Tôn; ",
  "dn16:4.11.13": "vị trưởng lão ấy đã hiểu đúng.' ",
  "dn16:4.11.14": "Này các Tỳ Kheo, hãy ghi nhớ đây là Đại Giáo Pháp thứ tư. ",
  "dn16:4.11.15": "Này các Tỳ Kheo, hãy ghi nhớ bốn Đại Giáo Pháp này.\" ",
  "dn16:4.12.1": "Tại đó, khi trú ở thành Bhoga, tại đền Ānanda, Đức Thế Tôn thường xuyên thuyết pháp cho các Tỳ Kheo như sau: ",
  "dn16:4.12.2": "\"Đây là giới, đây là định, đây là tuệ. ",
  "dn16:4.12.3": "Định được tu tập bằng giới sẽ đem lại quả lớn, lợi ích lớn. ",
  "dn16:4.12.4": "Tuệ được tu tập bằng định sẽ đem lại quả lớn, lợi ích lớn. ",
  "dn16:4.12.5": "Tâm được tu tập bằng tuệ sẽ hoàn toàn giải thoát khỏi các lậu hoặc, đó là—",
  "dn16:4.12.6": "dục lậu, hữu lậu, vô minh lậu.\" ",
  "dn16:4.13.0": "23. Câu Chuyện Về Cunda Con Người Thợ Rèn ",
  "dn16:4.13.1": "Rồi sau khi trú tại thành Bhoga một thời gian vừa ý, Đức Thế Tôn gọi Tôn giả Ānanda: ",
  "dn16:4.13.2": "\"Này Ānanda, chúng ta hãy đi đến Pāvā.\" ",
  "dn16:4.13.3": "\"Thưa vâng, bạch Thế Tôn\", Tôn giả Ānanda vâng lời Đức Thế Tôn. ",
  "dn16:4.13.4": "Rồi Đức Thế Tôn cùng với đại chúng Tỳ Kheo đi đến Pāvā. ",
  "dn16:4.13.5": "Tại đó, Đức Thế Tôn trú ở Pāvā, trong vườn xoài của Cunda, con người thợ rèn. ",
  "dn16:4.14.1": "Cunda, con người thợ rèn, nghe tin: \"Đức Thế Tôn đã đến Pāvā và trú tại Pāvā, trong vườn xoài của ta.\" ",
  "dn16:4.14.2": "Rồi Cunda, con người thợ rèn, đi đến chỗ Đức Thế Tôn; đến nơi, đảnh lễ Đức Thế Tôn rồi ngồi sang một bên. ",
  "dn16:4.14.3": "Khi Cunda, con người thợ rèn, đã ngồi sang một bên, Đức Thế Tôn khai thị, khuyến khích, khích lệ, làm cho ông hoan hỷ với lời pháp thoại. ",
  "dn16:4.14.4": "Rồi Cunda, con người thợ rèn, sau khi được Đức Thế Tôn khai thị, khuyến khích, khích lệ, làm cho hoan hỷ với lời pháp thoại, bạch Đức Thế Tôn: ",
  "dn16:4.15.1": "\"Bạch Thế Tôn, xin Đức Thế Tôn cùng chúng Tỳ Kheo nhận lời mời thọ trai ngày mai của con.\" ",
  "dn16:4.15.2": "Đức Thế Tôn im lặng nhận lời. ",
  "dn16:4.16.1": "Biết Đức Thế Tôn đã nhận lời, Cunda, con người thợ rèn, từ chỗ ngồi đứng dậy, đảnh lễ Đức Thế Tôn, nhiễu bên phải rồi ra về. ",
  "dn16:4.17.1": "Rồi Cunda, con người thợ rèn, sau khi đêm đã qua, tại nhà của mình, cho chuẩn bị các món ăn ngon và thật nhiều món sūkaramaddava (nấm thịt lợn mềm), rồi báo giờ đến Đức Thế Tôn: ",
  "dn16:4.17.2": "\"Đã đến giờ, bạch Thế Tôn, cơm đã sẵn sàng.\" ",
  "dn16:4.18.1": "Rồi vào buổi sáng, Đức Thế Tôn đắp y, cầm y bát, cùng với chúng Tỳ Kheo đi đến nhà của Cunda, con người thợ rèn; đến nơi, ngồi xuống chỗ đã soạn sẵn. ",
  "dn16:4.18.2": "Ngồi xong, Đức Thế Tôn gọi Cunda, con người thợ rèn: ",
  "dn16:4.18.3": "\"Này Cunda, món sūkaramaddava ngươi đã chuẩn bị, hãy dâng nó cho Ta. ",
  "dn16:4.18.4": "Còn các món ăn khác đã chuẩn bị, hãy dâng cho chúng Tỳ Kheo.\" ",
  "dn16:4.18.5": "\"Thưa vâng, bạch Thế Tôn\", Cunda, con người thợ rèn, vâng lời Đức Thế Tôn, dâng món sūkaramaddava đã chuẩn bị cho Đức Thế Tôn. ",
  "dn16:4.18.6": "Còn các món ăn khác đã chuẩn bị, ông dâng cho chúng Tỳ Kheo. ",
  "dn16:4.19.1": "Rồi Đức Thế Tôn gọi Cunda, con người thợ rèn: ",
  "dn16:4.19.2": "\"Này Cunda, món sūkaramaddava còn dư lại, hãy đem chôn dưới hố. ",
  "dn16:4.19.3": "Này Cunda, Ta không thấy trong thế gian có chư thiên, ác ma, Phạm Thiên, sa-môn, bà-la-môn, chư thiên và loài người nào có thể tiêu hóa được món ấy, ngoại trừ Như Lai.\" ",
  "dn16:4.19.4": "\"Thưa vâng, bạch Thế Tôn\", Cunda, con người thợ rèn, vâng lời Đức Thế Tôn, đem món sūkaramaddava còn dư lại chôn dưới hố, rồi đi đến chỗ Đức Thế Tôn; đến nơi, đảnh lễ Đức Thế Tôn rồi ngồi sang một bên. ",
  "dn16:4.19.5": "Khi Cunda, con người thợ rèn, đã ngồi sang một bên, Đức Thế Tôn sau khi khai thị, khuyến khích, khích lệ, làm cho ông hoan hỷ với lời pháp thoại, từ chỗ ngồi đứng dậy, ra đi. ",
  "dn16:4.19.6": "(…) ",
  "dn16:4.20.1": "Rồi sau khi Đức Thế Tôn thọ trai do Cunda, con người thợ rèn, cúng dường, Ngài bị bệnh trầm trọng, đại tiện ra máu, cảm thọ dữ dội, gần như chết đến nơi. ",
  "dn16:4.20.2": "Đức Thế Tôn chánh niệm, tỉnh giác chịu đựng, không bị dao động. ",
  "dn16:4.20.3": "Rồi Đức Thế Tôn gọi Tôn giả Ānanda: ",
  "dn16:4.20.4": "\"Này Ānanda, chúng ta hãy đi đến Kusinārā.\" ",
  "dn16:4.20.5": "\"Thưa vâng, bạch Thế Tôn\", Tôn giả Ānanda vâng lời Đức Thế Tôn. ",
  "dn16:4.20.6": "Sau khi ăn bữa cơm của Cunda, ",
  "dn16:4.20.7": "Con người thợ rèn, tôi nghe như vậy; ",
  "dn16:4.20.8": "Bậc Trí giả bị trọng bệnh, ",
  "dn16:4.20.9": "Cảm thọ dữ dội, gần chết. ",
  "dn16:4.20.10": "Sau khi ăn món sūkaramaddava, ",
  "dn16:4.20.11": "Bệnh nặng khởi lên nơi Đức Đạo Sư; ",
  "dn16:4.20.12": "Trong khi bị đi ngoài, Đức Thế Tôn nói, ",
  "dn16:4.20.13": "\"Ta sẽ đi đến thành Kusinārā.\" ",
  "dn16:4.21.0": "24. Mang Nước Uống Đến ",
  "dn16:4.21.1": "Rồi Đức Thế Tôn rời khỏi con đường và đi đến gốc một cây nọ; đến nơi, Ngài gọi Tôn giả Ānanda: ",
  "dn16:4.21.2": "\"Này Ānanda, hãy trải y tăng-già-lê gấp tư cho Ta. Ta mệt rồi, này Ānanda, Ta muốn ngồi.\" ",
  "dn16:4.21.3": "\"Thưa vâng, bạch Thế Tôn\", Tôn giả Ānanda vâng lời Đức Thế Tôn, trải y tăng-già-lê gấp tư. ",
  "dn16:4.21.4": "Đức Thế Tôn ngồi xuống chỗ đã soạn sẵn. ",
  "dn16:4.22.1": "Ngồi xong, Đức Thế Tôn gọi Tôn giả Ānanda: ",
  "dn16:4.22.2": "\"Này Ānanda, hãy mang nước uống đến cho Ta. Ta khát rồi, này Ānanda, Ta muốn uống.\" ",
  "dn16:4.22.3": "Khi được nghe nói như vậy, Tôn giả Ānanda bạch Đức Thế Tôn: ",
  "dn16:4.22.4": "\"Bạch Thế Tôn, vừa có khoảng năm trăm cỗ xe đi qua, nước bị các bánh xe xẻ đang chảy, đục ngầu, vẩn đục. ",
  "dn16:4.22.5": "Bạch Thế Tôn, sông Kakudhā ở gần đây, nước trong, nước ngọt, nước mát, nước trắng, có bến nước tốt, đẹp đẽ. ",
  "dn16:4.22.6": "Tại đó, Đức Thế Tôn sẽ uống nước và làm mát thân thể.\" ",
  "dn16:4.23.1": "Lần thứ hai, Đức Thế Tôn gọi Tôn giả Ānanda: ",
  "dn16:4.23.2": "\"Này Ānanda, hãy mang nước uống đến cho Ta. Ta khát rồi, này Ānanda, Ta muốn uống.\" ",
  "dn16:4.23.3": "Lần thứ hai, Tôn giả Ānanda bạch Đức Thế Tôn: ",
  "dn16:4.23.4": "\"Bạch Thế Tôn, vừa có khoảng năm trăm cỗ xe đi qua, nước bị các bánh xe xẻ đang chảy, đục ngầu, vẩn đục. ",
  "dn16:4.23.5": "Bạch Thế Tôn, sông Kakudhā ở gần đây, nước trong, nước ngọt, nước mát, nước trắng, có bến nước tốt, đẹp đẽ. ",
  "dn16:4.23.6": "Tại đó, Đức Thế Tôn sẽ uống nước và làm mát thân thể.\" ",
  "dn16:4.24.1": "Lần thứ ba, Đức Thế Tôn gọi Tôn giả Ānanda: ",
  "dn16:4.24.2": "\"Này Ānanda, hãy mang nước uống đến cho Ta. Ta khát rồi, này Ānanda, Ta muốn uống.\" ",
  "dn16:4.24.3": "\"Thưa vâng, bạch Thế Tôn\", Tôn giả Ānanda vâng lời Đức Thế Tôn, cầm bát đi đến con suối nhỏ kia. ",
  "dn16:4.24.4": "Rồi con suối nhỏ vốn bị các bánh xe xẻ đang chảy, đục ngầu, vẩn đục, khi Tôn giả Ānanda đến, nước trở nên trong, sạch, không vẩn đục. ",
  "dn16:4.25.1": "Rồi Tôn giả Ānanda nghĩ: ",
  "dn16:4.25.2": "\"Thật kỳ diệu thay! Thật hy hữu thay! Như Lai có đại thần lực, đại uy lực. ",
  "dn16:4.25.3": "Con suối nhỏ này vốn bị các bánh xe xẻ đang chảy, đục ngầu, vẩn đục, mà khi ta đến, nước lại trở nên trong, sạch, không vẩn đục.\" ",
  "dn16:4.25.4": "Ngài múc nước uống vào bát, đi đến chỗ Đức Thế Tôn; đến nơi, bạch Đức Thế Tôn: ",
  "dn16:4.25.5": "\"Thật kỳ diệu thay, bạch Thế Tôn! Thật hy hữu thay, bạch Thế Tôn! Như Lai có đại thần lực, đại uy lực. ",
  "dn16:4.25.6": "Bạch Thế Tôn, con suối nhỏ kia vốn bị các bánh xe xẻ đang chảy, đục ngầu, vẩn đục, mà khi con đến, nước lại trở nên trong, sạch, không vẩn đục. ",
  "dn16:4.25.7": "Xin Đức Thế Tôn hãy uống nước, xin bậc Thiện Thệ hãy uống nước.\" ",
  "dn16:4.25.8": "Rồi Đức Thế Tôn uống nước. ",
  "dn16:4.26.0": "25. Câu Chuyện Về Pukkusa, Vương Tử Mallā ",
  "dn16:4.26.1": "Lúc bấy giờ, Pukkusa, vương tử Mallā, đệ tử của Āḷāra Kālāma, đang đi trên con đường từ Kusinārā đến Pāvā. ",
  "dn16:4.26.2": "Pukkusa, vương tử Mallā, thấy Đức Thế Tôn đang ngồi dưới một gốc cây. ",
  "dn16:4.26.3": "Thấy vậy, ông đi đến chỗ Đức Thế Tôn; đến nơi, đảnh lễ Đức Thế Tôn rồi ngồi sang một bên. Ngồi sang một bên, Pukkusa, vương tử Mallā, bạch Đức Thế Tôn: ",
  "dn16:4.26.4": "\"Thật kỳ diệu thay, bạch Thế Tôn! Thật hy hữu thay, bạch Thế Tôn! Các vị xuất gia sống trong trạng thái thật an tịnh. ",
  "dn16:4.27.1": "Bạch Thế Tôn, trước đây Āḷāra Kālāma đang đi trên đường, rời đường, đến ngồi nghỉ ban ngày dưới một gốc cây không xa đường. ",
  "dn16:4.27.2": "Rồi bạch Thế Tôn, khoảng năm trăm cỗ xe đi qua rất gần Āḷāra Kālāma. ",
  "dn16:4.27.3": "Rồi bạch Thế Tôn, có một người nọ đi theo sau đoàn xe ấy, đến chỗ Āḷāra Kālāma; đến nơi, nói với Āḷāra Kālāma: ",
  "dn16:4.27.4": "'Thưa ngài, ngài có thấy năm trăm cỗ xe vừa đi qua không?' ",
  "dn16:4.27.5": "'Này hiền giả, tôi không thấy.' ",
  "dn16:4.27.6": "'Thưa ngài, vậy ngài có nghe tiếng không?' ",
  "dn16:4.27.7": "'Này hiền giả, tôi không nghe tiếng.' ",
  "dn16:4.27.8": "'Thưa ngài, vậy ngài đang ngủ sao?' ",
  "dn16:4.27.9": "'Này hiền giả, tôi không ngủ.' ",
  "dn16:4.27.10": "'Thưa ngài, vậy ngài có tỉnh không?' ",
  "dn16:4.27.11": "'Có, này hiền giả.' ",
  "dn16:4.27.12": "'Thưa ngài, trong lúc tỉnh giác, ngài không thấy năm trăm cỗ xe đi qua rất gần, cũng không nghe tiếng; ",
  "dn16:4.27.13": "thậm chí, thưa ngài, y tăng-già-lê của ngài bị phủ đầy bụi sao?' ",
  "dn16:4.27.14": "'Đúng vậy, này hiền giả.' ",
  "dn16:4.27.15": "Rồi bạch Thế Tôn, người đàn ông ấy nghĩ: ",
  "dn16:4.27.16": "'Thật kỳ diệu thay! Thật hy hữu thay! Các vị xuất gia sống trong trạng thái thật an tịnh. ",
  "dn16:4.27.17": "Vì rằng, trong lúc tỉnh giác, mà không thấy năm trăm cỗ xe đi qua rất gần, cũng không nghe tiếng.' ",
  "dn16:4.27.18": "Sau khi tuyên bố lòng tịnh tín lớn đối với Āḷāra Kālāma, người ấy ra đi.\" ",
  "dn16:4.28.1": "\"Này Pukkusa, ngươi nghĩ thế nào, ",
  "dn16:4.28.2": "điều nào khó làm hơn, khó thực hiện hơn—",
  "dn16:4.28.3": "người trong lúc tỉnh giác không thấy năm trăm cỗ xe đi qua rất gần, cũng không nghe tiếng; ",
  "dn16:4.28.4": "hay người trong lúc tỉnh giác, dù trời đang mưa to, sấm vang, tia chớp xẹt liên tục, sét đánh ầm ầm, cũng không thấy, cũng không nghe tiếng?\" ",
  "dn16:4.29.1": "\"Bạch Thế Tôn, dù là năm trăm cỗ xe, hay sáu trăm, bảy trăm, tám trăm, chín trăm, một ngàn, hay một trăm ngàn cỗ xe, chúng có là gì đâu. ",
  "dn16:4.29.2": "Chính điều này mới là khó làm hơn, khó thực hiện hơn—người trong lúc tỉnh giác, dù trời đang mưa to, sấm vang, tia chớp xẹt liên tục, sét đánh ầm ầm, cũng không thấy, cũng không nghe tiếng.\" ",
  "dn16:4.30.1": "\"Này Pukkusa, một thời Ta trú tại Ātumā, trong một vựa lúa. ",
  "dn16:4.30.2": "Lúc bấy giờ, trời đang mưa to, sấm vang, tia chớp xẹt liên tục, sét đánh ầm ầm, ở gần vựa lúa có hai anh em nông phu bị sét đánh chết cùng bốn con bò đực. ",
  "dn16:4.30.3": "Rồi này Pukkusa, một đoàn người đông đảo ở Ātumā ra đi đến chỗ hai anh em nông phu và bốn con bò đực bị sét đánh chết. ",
  "dn16:4.31.1": "Này Pukkusa, lúc bấy giờ Ta vừa đi ra khỏi vựa lúa và đang đi kinh hành ngoài trời ở cửa vựa lúa. ",
  "dn16:4.31.2": "Rồi này Pukkusa, có một người nọ từ đoàn người đông đảo ấy đi đến chỗ Ta; đến nơi, đảnh lễ Ta rồi đứng sang một bên. Đứng sang một bên, này Pukkusa, Ta nói với người đó: ",
  "dn16:4.32.1": "'Này hiền giả, vì sao đoàn người đông đảo này tụ tập?' ",
  "dn16:4.32.2": "'Bạch Thế Tôn, vừa rồi, trời đang mưa to, sấm vang, tia chớp xẹt liên tục, sét đánh ầm ầm, có hai anh em nông phu bị sét đánh chết cùng bốn con bò đực. ",
  "dn16:4.32.3": "Vì vậy đoàn người đông đảo này tụ tập ở đây. ",
  "dn16:4.32.4": "Còn Ngài, bạch Thế Tôn, lúc ấy Ngài ở đâu?' ",
  "dn16:4.32.5": "'Này hiền giả, Ta ở ngay đây.' ",
  "dn16:4.32.6": "'Thưa Ngài, vậy Ngài có thấy không?' ",
  "dn16:4.32.7": "'Này hiền giả, Ta không thấy.' ",
  "dn16:4.32.8": "'Thưa Ngài, vậy Ngài có nghe tiếng không?' ",
  "dn16:4.32.9": "'Này hiền giả, Ta không nghe tiếng.' ",
  "dn16:4.32.10": "'Thưa Ngài, vậy Ngài đang ngủ sao?' ",
  "dn16:4.32.11": "'Này hiền giả, Ta không ngủ.' ",
  "dn16:4.32.12": "'Thưa Ngài, vậy Ngài có tỉnh không?' ",
  "dn16:4.32.13": "'Có, này hiền giả.' ",
  "dn16:4.32.14": "'Thưa Ngài, trong lúc tỉnh giác, dù trời đang mưa to, sấm vang, tia chớp xẹt liên tục, sét đánh ầm ầm, Ngài không thấy, cũng không nghe tiếng sao?' ",
  "dn16:4.32.15": "'Đúng vậy, này hiền giả.' ",
  "dn16:4.33.1": "Rồi này Pukkusa, người ấy nghĩ: ",
  "dn16:4.33.2": "'Thật kỳ diệu thay! Thật hy hữu thay! Các vị xuất gia sống trong trạng thái thật an tịnh. ",
    "dn16:4.33.3": "Vì rằng, trong lúc tỉnh giác, dù trời đang mưa to, sấm vang, tia chớp xẹt liên tục, sét đánh ầm ầm, Ngài cũng không thấy, cũng không nghe tiếng.' ",
  "dn16:4.33.4": "Sau khi tuyên bố lòng tịnh tín lớn đối với Ta, đảnh lễ Ta, nhiễu bên phải, người ấy ra đi.\" ",
  "dn16:4.34.1": "Khi được nghe nói như vậy, Pukkusa, vương tử Mallā, bạch Đức Thế Tôn: ",
  "dn16:4.34.2": "\"Bạch Thế Tôn, lòng tịnh tín của con đối với Āḷāra Kālāma, nay con thổi bay theo gió lớn hoặc để nó trôi theo dòng nước chảy xiết. ",
  "dn16:4.34.3": "Thật vi diệu thay, bạch Thế Tôn! Thật vi diệu thay, bạch Thế Tôn! ",
  "dn16:4.34.4": "Bạch Thế Tôn, như người dựng đứng lại những gì bị lật úp, phơi bày những gì bị che đậy, chỉ đường cho kẻ lạc lối, hay cầm đèn dầu vào trong bóng tối với ý nghĩ: 'Người có mắt sẽ thấy được các vật'; cũng vậy, Đức Thế Tôn với nhiều phương tiện đã làm sáng tỏ Giáo Pháp. ",
  "dn16:4.34.5": "Bạch Thế Tôn, con xin quy y Đức Thế Tôn, quy y Pháp và quy y Tăng. ",
  "dn16:4.34.6": "Mong Đức Thế Tôn nhận con làm nam cư sĩ, từ nay cho đến trọn đời quy y.\" ",
  "dn16:4.35.1": "Rồi Pukkusa, vương tử Mallā, gọi một người đàn ông: ",
  "dn16:4.35.2": "\"Này bạn, hãy mang đến cho tôi một đôi y màu vàng kim mịn, đáng mang.\" ",
  "dn16:4.35.3": "\"Thưa vâng\", người đàn ông đó vâng lời Pukkusa, vương tử Mallā, mang đến một đôi y màu vàng kim mịn, đáng mang. ",
  "dn16:4.35.4": "Rồi Pukkusa, vương tử Mallā, dâng đôi y màu vàng kim mịn, đáng mang đó lên Đức Thế Tôn: ",
  "dn16:4.35.5": "\"Bạch Thế Tôn, đây là đôi y màu vàng kim mịn, đáng mang, xin Đức Thế Tôn vì lòng thương xót mà thọ nhận.\" ",
  "dn16:4.35.6": "\"Vậy, này Pukkusa, hãy dùng một y đắp cho Ta, một y đắp cho Ānanda.\" ",
  "dn16:4.35.7": "\"Thưa vâng, bạch Thế Tôn\", Pukkusa, vương tử Mallā, vâng lời Đức Thế Tôn, dùng một y đắp cho Đức Thế Tôn, một y đắp cho Tôn giả Ānanda. ",
  "dn16:4.36.1": "Rồi Đức Thế Tôn khai thị, khuyến khích, khích lệ, làm cho Pukkusa, vương tử Mallā, hoan hỷ với lời pháp thoại. ",
  "dn16:4.36.2": "Rồi Pukkusa, vương tử Mallā, sau khi được Đức Thế Tôn khai thị, khuyến khích, khích lệ, làm cho hoan hỷ với lời pháp thoại, từ chỗ ngồi đứng dậy, đảnh lễ Đức Thế Tôn, nhiễu bên phải rồi ra đi. ",
  "dn16:4.37.1": "Rồi không lâu sau khi Pukkusa, vương tử Mallā, ra đi, Tôn giả Ānanda đắp đôi y màu vàng kim mịn, đáng mang, lên thân Đức Thế Tôn. ",
  "dn16:4.37.2": "Đôi y được đắp lên thân Đức Thế Tôn trông như tàn lụi đi. ",
  "dn16:4.37.3": "Rồi Tôn giả Ānanda bạch Đức Thế Tôn: ",
  "dn16:4.37.4": "\"Thật kỳ diệu thay, bạch Thế Tôn! Thật hy hữu thay, bạch Thế Tôn! Bạch Thế Tôn, thật là trong sạch và sáng tỏ thay màu da của Như Lai! ",
  "dn16:4.37.5": "Bạch Thế Tôn, đôi y màu vàng kim mịn, đáng mang này khi được đắp lên thân Đức Thế Tôn trông như tàn lụi đi.\" ",
  "dn16:4.37.6": "\"Này Ānanda, đúng vậy, đúng vậy. Có hai thời kỳ thân của Như Lai trở nên đặc biệt trong sạch và sáng tỏ. ",
  "dn16:4.38.1": "Hai đó là gì? ",
  "dn16:4.38.2": "Này Ānanda, đó là đêm Như Lai chứng đắc Vô Thượng Chánh Đẳng Giác, và đêm Như Lai nhập Niết Bàn trong Vô Dư Y Niết Bàn Giới. ",
  "dn16:4.38.3": "Này Ānanda, trong hai thời kỳ này, thân của Như Lai đặc biệt trong sạch và sáng tỏ. ",
  "dn16:4.38.4": "Này Ānanda, hôm nay, vào canh cuối của đêm, tại Kusinārā, trong rừng sālā Upavattana của dân Mallā, giữa hai cây sālā song sinh, Như Lai sẽ nhập Niết Bàn. ",
  "dn16:4.38.5": "Này Ānanda, chúng ta hãy đi đến sông Kakudhā.\" ",
  "dn16:4.38.6": "\"Thưa vâng, bạch Thế Tôn\", Tôn giả Ānanda vâng lời Đức Thế Tôn. ",
  "dn16:4.38.7": "Đôi y màu vàng kim mịn, ",
  "dn16:4.38.8": "Pukkusa dâng lên cúng dường; ",
  "dn16:4.38.9": "Được đắp bởi đôi y ấy, Đức Đạo Sư, ",
  "dn16:4.38.10": "Hiện sắc như vàng ròng, rạng rỡ. ",
  "dn16:4.38.11": "(…) ",
  "dn16:4.39.1": "Rồi Đức Thế Tôn cùng với đại chúng Tỳ Kheo đi đến sông Kakudhā; đến nơi, Ngài xuống sông Kakudhā tắm và uống nước, rồi lên bờ đi đến khu rừng xoài. ",
  "dn16:4.39.2": "Đến nơi, Ngài gọi Tôn giả Cundaka: ",
  "dn16:4.39.3": "\"Này Cundaka, hãy trải y tăng-già-lê gấp tư cho Ta. Ta mệt rồi, này Cundaka, Ta muốn nằm.\" ",
  "dn16:4.40.1": "\"Thưa vâng, bạch Thế Tôn\", Tôn giả Cundaka vâng lời Đức Thế Tôn, trải y tăng-già-lê gấp tư. ",
  "dn16:4.40.2": "Rồi Đức Thế Tôn nằm nghiêng bên phải theo tư thế sư tử, chân này đặt trên chân kia, chánh niệm, tỉnh giác, tác ý đến tưởng về sự ngồi dậy. ",
  "dn16:4.40.3": "Còn Tôn giả Cundaka thì ngồi ngay trước mặt Đức Thế Tôn. ",
  "dn16:4.41.1": "Đức Phật đến sông Kakudhā, ",
  "dn16:4.41.2": "Nước trong, nước ngọt, trong vắt; ",
  "dn16:4.41.3": "Đức Đạo Sư đi xuống, không mệt mỏi, ",
  "dn16:4.41.4": "Đấng Như Lai vô song trong đời. ",
  "dn16:4.41.5": "Sau khi tắm và uống nước, Đức Đạo Sư lên bờ, ",
  "dn16:4.41.6": "Đi đầu giữa chúng Tỳ Kheo; ",
  "dn16:4.41.7": "Đức Thế Tôn thuyết giảng Pháp ở đây, ",
  "dn16:4.41.8": "Bậc Đại Ẩn Sĩ đi đến rừng xoài. ",
  "dn16:4.41.9": "Ngài gọi Tỳ Kheo tên Cundaka, ",
  "dn16:4.41.10": "\"Hãy trải y gấp tư cho Ta nằm\"; ",
  "dn16:4.41.11": "Được thúc giục bởi bậc tu hành, Cunda, ",
  "dn16:4.41.12": "Lập tức trải y gấp tư; ",
  "dn16:4.41.13": "Đức Đạo Sư nằm xuống, không mệt mỏi, ",
  "dn16:4.41.14": "Còn Cunda cũng ngồi ngay trước mặt Ngài. ",
  "dn16:4.42.1": "Rồi Đức Thế Tôn gọi Tôn giả Ānanda: ",
  "dn16:4.42.2": "\"Này Ānanda, có thể có ai đó làm cho Cunda, con người thợ rèn, hối hận rằng: ",
  "dn16:4.42.3": "'Này hiền giả Cunda, thật bất lợi cho ngươi, thật là điều xui rủi cho ngươi, vì Như Lai đã thọ bữa ăn cuối cùng của ngươi rồi nhập Niết Bàn.' ",
  "dn16:4.42.4": "Này Ānanda, sự hối hận của Cunda, con người thợ rèn, nên được xua tan như sau: ",
  "dn16:4.42.5": "'Này hiền giả Cunda, thật lợi ích cho ngươi, thật là phúc lớn cho ngươi, ",
  "dn16:4.42.6": "vì Như Lai đã thọ bữa ăn cuối cùng của ngươi rồi nhập Niết Bàn. ",
  "dn16:4.42.7": "Này hiền giả Cunda, chính tôi đã tận miệng nghe, tận mặt nhận từ Đức Thế Tôn: ",
  "dn16:4.42.8": "có hai bữa cúng dường thực phẩm đem lại quả báo ngang nhau, dị thục ngang nhau, vượt trội hơn nhiều so với các bữa cúng dường khác về quả báo và lợi ích. ",
  "dn16:4.42.9": "Hai đó là gì? ",
  "dn16:4.42.10": "Đó là bữa ăn mà Như Lai thọ nhận rồi chứng đắc Vô Thượng Chánh Đẳng Giác, và bữa ăn mà Như Lai thọ nhận rồi nhập Niết Bàn trong Vô Dư Y Niết Bàn Giới. ",
  "dn16:4.42.11": "Hai bữa cúng dường thực phẩm này đem lại quả báo ngang nhau, dị thục ngang nhau, vượt trội hơn nhiều so với các bữa cúng dường khác về quả báo và lợi ích. ",
  "dn16:4.42.12": "Hiền giả Cunda, con người thợ rèn, đã tích lũy nghiệp đem lại tuổi thọ dài, đã tích lũy nghiệp đem lại sắc đẹp, đã tích lũy nghiệp đem lại an lạc, đã tích lũy nghiệp đem lại danh tiếng, đã tích lũy nghiệp đem lại cõi trời, đã tích lũy nghiệp đem lại địa vị cao sang.' ",
  "dn16:4.42.13": "Này Ānanda, sự hối hận của Cunda, con người thợ rèn, phải được xua tan như vậy.\" ",
  "dn16:4.43.1": "Thấu hiểu ý nghĩa này, vào lúc đó, Đức Thế Tôn thốt lên lời cảm hứng như sau: ",
  "dn16:4.43.2": "\"Công đức tăng trưởng do bố thí, ",
  "dn16:4.43.3": "Thù oán không sanh do tự chế; ",
  "dn16:4.43.4": "Người thiện từ bỏ điều ác, ",
  "dn16:4.43.5": "Đoạn tận tham sân si, đạt tịch tịnh.\" ",
  "dn16:4.43.6": "Hết phần tụng đọc thứ tư. ",
  "dn16:5.1.0": "26. Cây Sālā Song Sinh ",
  "dn16:5.1.1": "Rồi Đức Thế Tôn gọi Tôn giả Ānanda: ",
  "dn16:5.1.2": "\"Này Ānanda, chúng ta hãy đi qua bờ bên kia sông Hiraññavatī, đến rừng sālā Upavattana của dân Mallā, ở Kusinārā.\" ",
  "dn16:5.1.3": "\"Thưa vâng, bạch Thế Tôn\", Tôn giả Ānanda vâng lời Đức Thế Tôn. ",
  "dn16:5.1.4": "Rồi Đức Thế Tôn cùng với đại chúng Tỳ Kheo qua bờ bên kia sông Hiraññavatī, đến rừng sālā Upavattana của dân Mallā, ở Kusinārā. Đến nơi, Ngài gọi Tôn giả Ānanda: ",
  "dn16:5.1.5": "\"Này Ānanda, hãy soạn chỗ nằm cho Ta giữa hai cây sālā song sinh, đầu hướng về phía bắc. Ta mệt rồi, này Ānanda, Ta muốn nằm.\" ",
  "dn16:5.1.6": "\"Thưa vâng, bạch Thế Tôn\", Tôn giả Ānanda vâng lời Đức Thế Tôn, soạn chỗ nằm giữa hai cây sālā song sinh, đầu hướng về phía bắc. ",
  "dn16:5.1.7": "Rồi Đức Thế Tôn nằm nghiêng bên phải theo tư thế sư tử, chân này đặt trên chân kia, chánh niệm, tỉnh giác. ",
  "dn16:5.2.1": "Lúc bấy giờ, hai cây sālā song sinh nở hoa đầy cây dù trái mùa. ",
  "dn16:5.2.2": "Các hoa ấy rơi xuống, rắc xuống, phủ kín lên thân Như Lai để cúng dường Như Lai. ",
  "dn16:5.2.3": "Các hoa mạn-đà-la của cõi trời cũng từ hư không rơi xuống, rắc xuống, phủ kín lên thân Như Lai để cúng dường Như Lai. ",
  "dn16:5.2.4": "Bột trầm hương của cõi trời cũng từ hư không rơi xuống, rắc xuống, phủ kín lên thân Như Lai để cúng dường Như Lai. ",
  "dn16:5.2.5": "Âm nhạc của cõi trời cũng trỗi lên trong hư không để cúng dường Như Lai. ",
  "dn16:5.2.6": "Tiếng hát của cõi trời cũng vang lên trong hư không để cúng dường Như Lai. ",
  "dn16:5.3.1": "Rồi Đức Thế Tôn gọi Tôn giả Ānanda: ",
  "dn16:5.3.2": "\"Này Ānanda, hai cây sālā song sinh nở hoa đầy cây dù trái mùa. ",
  "dn16:5.3.3": "Các hoa ấy rơi xuống, rắc xuống, phủ kín lên thân Như Lai để cúng dường Như Lai. ",
  "dn16:5.3.4": "Các hoa mạn-đà-la của cõi trời cũng từ hư không rơi xuống, rắc xuống, phủ kín lên thân Như Lai để cúng dường Như Lai. ",
  "dn16:5.3.5": "Bột trầm hương của cõi trời cũng từ hư không rơi xuống, rắc xuống, phủ kín lên thân Như Lai để cúng dường Như Lai. ",
  "dn16:5.3.6": "Âm nhạc của cõi trời cũng trỗi lên trong hư không để cúng dường Như Lai. ",
  "dn16:5.3.7": "Tiếng hát của cõi trời cũng vang lên trong hư không để cúng dường Như Lai. ",
  "dn16:5.3.8": "Này Ānanda, nhưng không phải chỉ cúng dường như vậy mà Như Lai được cung kính, tôn trọng, quý trọng, cúng dường, sùng kính. ",
  "dn16:5.3.9": "Này Ānanda, bất cứ Tỳ Kheo, Tỳ Kheo ni, nam cư sĩ, nữ cư sĩ nào sống thực hành Pháp đúng theo Pháp, thực hành đúng đắn, sống đúng theo Pháp, người ấy mới thực sự cung kính, tôn trọng, quý trọng, cúng dường, sùng kính Như Lai bằng sự cúng dường cao thượng nhất. ",
  "dn16:5.3.10": "Vì vậy, này Ānanda, chúng ta hãy sống thực hành Pháp đúng theo Pháp, thực hành đúng đắn, sống đúng theo Pháp. ",
  "dn16:5.3.11": "Này Ānanda, các ông phải học như vậy.\" ",
  "dn16:5.4.0": "27. Trưởng lão Upavāṇa ",
  "dn16:5.4.1": "Lúc bấy giờ, Tôn giả Upavāṇa đang đứng trước mặt Đức Thế Tôn, quạt hầu Ngài. ",
  "dn16:5.4.2": "Rồi Đức Thế Tôn bảo Tôn giả Upavāṇa tránh ra: ",
  "dn16:5.4.3": "\"Này Tỳ Kheo, hãy tránh ra, đừng đứng trước mặt Ta.\" ",
  "dn16:5.4.4": "Rồi Tôn giả Ānanda nghĩ: ",
  "dn16:5.4.5": "\"Tôn giả Upavāṇa này đã lâu năm làm thị giả hầu cận Đức Thế Tôn, thân cận, gần gũi. ",
  "dn16:5.4.6": "Thế mà Đức Thế Tôn, vào lúc cuối cùng, lại bảo Tôn giả Upavāṇa tránh ra: ",
  "dn16:5.4.7": "'Này Tỳ Kheo, hãy tránh ra, đừng đứng trước mặt Ta.' ",
  "dn16:5.4.8": "Do nhân gì, do duyên gì mà Đức Thế Tôn bảo Tôn giả Upavāṇa tránh ra: ",
  "dn16:5.4.9": "'Này Tỳ Kheo, hãy tránh ra, đừng đứng trước mặt Ta'?\" ",
  "dn16:5.5.1": "Rồi Tôn giả Ānanda bạch Đức Thế Tôn: ",
  "dn16:5.5.2": "\"Bạch Thế Tôn, Tôn giả Upavāṇa này đã lâu năm làm thị giả hầu cận Đức Thế Tôn, thân cận, gần gũi. ",
  "dn16:5.5.3": "Thế mà Đức Thế Tôn, vào lúc cuối cùng, lại bảo Tôn giả Upavāṇa tránh ra: ",
  "dn16:5.5.4": "'Này Tỳ Kheo, hãy tránh ra, đừng đứng trước mặt Ta.' ",
  "dn16:5.5.5": "Bạch Thế Tôn, do nhân gì, do duyên gì mà Đức Thế Tôn bảo Tôn giả Upavāṇa tránh ra: ",
  "dn16:5.5.6": "'Này Tỳ Kheo, hãy tránh ra, đừng đứng trước mặt Ta'?\" ",
  "dn16:5.5.7": "\"Này Ānanda, phần lớn chư thiên trong mười thế giới đã tụ họp để đến chiêm ngưỡng Như Lai. ",
  "dn16:5.5.8": "Này Ānanda, trong phạm vi mười hai do-tuần quanh rừng sālā Upavattana của dân Mallā ở Kusinārā, không có chỗ nào dù chỉ nhỏ bằng đầu sợi tóc mà không có các chư thiên đại uy lực đang đứng. ",
  "dn16:5.5.9": "Này Ānanda, các chư thiên đang than phiền: ",
  "dn16:5.5.10": "'Chúng ta đã từ xa đến để chiêm ngưỡng Như Lai. ",
  "dn16:5.5.11": "Thật hiếm hoi mới có Như Lai, bậc A-la-hán, Chánh Đẳng Giác xuất hiện ở đời. ",
  "dn16:5.5.12": "Đêm nay, vào canh cuối, Như Lai sẽ nhập Niết Bàn. ",
  "dn16:5.5.13": "Mà vị Tỳ Kheo đại uy lực này lại đứng trước mặt Đức Thế Tôn, che khuất, khiến chúng ta không có cơ hội chiêm ngưỡng Như Lai vào lúc cuối cùng.'\" ",
  "dn16:5.6.1": "\"Bạch Thế Tôn, vậy các chư thiên mà Đức Thế Tôn đang nghĩ đến ở trong trạng thái nào?\" ",
  "dn16:5.6.2": "\"Này Ānanda, có những chư thiên ở trên không trung có tưởng về đất, các vị ấy xõa tóc khóc than, đưa tay khóc than, ngã lăn lộn, lăn qua lăn lại: ",
  "dn16:5.6.3": "'Đức Thế Tôn nhập Niết Bàn quá sớm, bậc Thiện Thệ nhập Niết Bàn quá sớm, con mắt của thế gian biến mất quá sớm.' ",
  "dn16:5.6.4": "Này Ānanda, có những chư thiên ở trên đất có tưởng về đất, các vị ấy xõa tóc khóc than, đưa tay khóc than, ngã lăn lộn, lăn qua lăn lại: ",
  "dn16:5.6.5": "'Đức Thế Tôn nhập Niết Bàn quá sớm, bậc Thiện Thệ nhập Niết Bàn quá sớm, con mắt của thế gian biến mất quá sớm.' ",
  "dn16:5.6.6": "Còn những chư thiên đã ly tham, các vị ấy chánh niệm, tỉnh giác chịu đựng: ",
  "dn16:5.6.7": "'Các pháp hữu vi là vô thường, làm sao có thể khác được.'\" ",
  "dn16:5.7.0": "28. Bốn Nơi Đáng Chiêm Ngưỡng ",
  "dn16:5.7.1": "\"Bạch Thế Tôn, trước đây các Tỳ Kheo sau khi an cư mùa mưa ở các phương đến chiêm ngưỡng Như Lai. ",
  "dn16:5.7.2": "Chúng con có được gặp các vị Tỳ Kheo khả kính, có được phụng sự các vị. ",
  "dn16:5.7.3": "Bạch Thế Tôn, nhưng sau khi Đức Thế Tôn nhập diệt, chúng con sẽ không còn được gặp các vị Tỳ Kheo khả kính, không còn được phụng sự các vị nữa.\" ",
  "dn16:5.8.1": "\"Này Ānanda, có bốn nơi mà người thiện tín có lòng tin nên đến chiêm ngưỡng và động tâm. ",
  "dn16:5.8.2": "Bốn đó là gì? ",
  "dn16:5.8.3": "'Đây là nơi Như Lai đản sanh', này Ānanda, đây là nơi mà người thiện tín có lòng tin nên đến chiêm ngưỡng và động tâm. ",
  "dn16:5.8.4": "'Đây là nơi Như Lai chứng đắc Vô Thượng Chánh Đẳng Giác', này Ānanda, đây là nơi mà người thiện tín có lòng tin nên đến chiêm ngưỡng và động tâm. ",
  "dn16:5.8.5": "'Đây là nơi Như Lai chuyển bánh xe Pháp vô thượng', này Ānanda, đây là nơi mà người thiện tín có lòng tin nên đến chiêm ngưỡng và động tâm. ",
  "dn16:5.8.6": "'Đây là nơi Như Lai nhập Niết Bàn trong Vô Dư Y Niết Bàn Giới', này Ānanda, đây là nơi mà người thiện tín có lòng tin nên đến chiêm ngưỡng và động tâm. ",
  "dn16:5.8.7": "Này Ānanda, đây là bốn nơi mà người thiện tín có lòng tin nên đến chiêm ngưỡng và động tâm. ",
  "dn16:5.8.8": "Này Ānanda, các Tỳ Kheo, Tỳ Kheo ni, nam cư sĩ, nữ cư sĩ có lòng tin sẽ đến chiêm ngưỡng và nói: ",
  "dn16:5.8.9": "'Đây là nơi Như Lai đản sanh', 'Đây là nơi Như Lai chứng đắc Vô Thượng Chánh Đẳng Giác', 'Đây là nơi Như Lai chuyển bánh xe Pháp vô thượng', 'Đây là nơi Như Lai nhập Niết Bàn trong Vô Dư Y Niết Bàn Giới'. ",
  "dn16:5.8.10": "Này Ānanda, bất cứ ai trong lúc đi chiêm bái các đền tháp, qua đời với tâm thanh tịnh, sau khi thân tan rã, sau khi chết, đều sẽ tái sanh vào cõi thiện, cõi trời.\" ",
  "dn16:5.9.0": "29. Câu Hỏi Của Ānanda ",
  "dn16:5.9.1": "\"Bạch Thế Tôn, chúng con phải cư xử với phụ nữ như thế nào?\" ",
  "dn16:5.9.2": "\"Này Ānanda, đừng nhìn.\" ",
  "dn16:5.9.3": "\"Bạch Thế Tôn, nếu nhìn thấy thì phải cư xử như thế nào?\" ",
  "dn16:5.9.4": "\"Này Ānanda, đừng nói chuyện.\" ",
  "dn16:5.9.5": "\"Bạch Thế Tôn, nếu có nói chuyện thì phải cư xử như thế nào?\" ",
  "dn16:5.9.6": "\"Này Ānanda, phải an trú chánh niệm.\" ",
  "dn16:5.10.1": "\"Bạch Thế Tôn, chúng con phải xử lý thân Như Lai như thế nào?\" ",
  "dn16:5.10.2": "\"Này Ānanda, các ông không nên bận tâm đến việc cúng dường thân xác Như Lai. ",
  "dn16:5.10.3": "Này Ānanda, hãy cố gắng phấn đấu vì mục đích tối thượng, hãy tu tập vì mục đích tối thượng, hãy không buông lung, tinh cần, chuyên chú vì mục đích tối thượng. ",
  "dn16:5.10.4": "Này Ānanda, có những bậc hiền trí sát-đế-lỵ, những bậc hiền trí bà-la-môn, những bậc hiền trí gia chủ có lòng tịnh tín nơi Như Lai, họ sẽ cúng dường thân xác Như Lai.\" ",
  "dn16:5.11.1": "\"Bạch Thế Tôn, nhưng phải xử lý thân Như Lai như thế nào?\" ",
  "dn16:5.11.2": "\"Này Ānanda, xử lý thân Như Lai cũng như xử lý thân của Chuyển Luân Thánh Vương.\" ",
  "dn16:5.11.3": "\"Bạch Thế Tôn, xử lý thân của Chuyển Luân Thánh Vương như thế nào?\" ",
  "dn16:5.11.4": "\"Này Ānanda, thân của Chuyển Luân Thánh Vương được quấn bằng vải mới, quấn xong vải mới, lại quấn bằng bông đã được chải, quấn xong bông đã được chải, lại quấn bằng vải mới. ",
  "dn16:5.11.5": "Bằng cách này, quấn thân Chuyển Luân Thánh Vương bằng năm trăm lớp vải, đặt vào quan tài sắt chứa đầy dầu, đậy bằng một quan tài sắt khác, rồi làm một giàn hỏa táng bằng đủ các loại hương thơm, và hỏa táng thân Chuyển Luân Thánh Vương. ",
  "dn16:5.11.6": "Sau đó, dựng tháp tôn thờ Chuyển Luân Thánh Vương ở ngã tư đường. ",
  "dn16:5.11.7": "Này Ānanda, đó là cách xử lý thân của Chuyển Luân Thánh Vương. ",
  "dn16:5.11.8": "Này Ānanda, xử lý thân Như Lai cũng phải như cách xử lý thân của Chuyển Luân Thánh Vương. ",
  "dn16:5.11.9": "Tháp thờ Như Lai phải được dựng ở ngã tư đường. ",
  "dn16:5.11.10": "Những ai tại đó dâng hoa, hương liệu, bột thơm, đảnh lễ, hoặc khởi tâm tịnh tín, sẽ được lợi ích và an lạc lâu dài. ",
  "dn16:5.12.0": "30. Những Bậc Đáng Dựng Tháp Thờ ",
  "dn16:5.12.1": "Này Ānanda, có bốn hạng người đáng được dựng tháp thờ. ",
  "dn16:5.12.2": "Bốn đó là gì? ",
  "dn16:5.12.3": "Như Lai, bậc A-la-hán, Chánh Đẳng Giác đáng được dựng tháp thờ; Độc Giác Phật đáng được dựng tháp thờ; đệ tử của Như Lai đáng được dựng tháp thờ; Chuyển Luân Thánh Vương đáng được dựng tháp thờ. ",
  "dn16:5.12.4": "Và này Ānanda, vì lý do gì mà Như Lai, bậc A-la-hán, Chánh Đẳng Giác đáng được dựng tháp thờ? ",
  "dn16:5.12.5": "Này Ānanda, khi nghĩ: 'Đây là tháp của Đức Thế Tôn, bậc A-la-hán, Chánh Đẳng Giác', nhiều người khởi tâm tịnh tín. ",
  "dn16:5.12.6": "Sau khi tâm được tịnh tín, sau khi thân tan rã, sau khi chết, họ sẽ tái sanh vào cõi thiện, cõi trời. ",
  "dn16:5.12.7": "Này Ānanda, vì lý do này mà Như Lai, bậc A-la-hán, Chánh Đẳng Giác đáng được dựng tháp thờ. ",
  "dn16:5.12.8": "Và này Ānanda, vì lý do gì mà Độc Giác Phật đáng được dựng tháp thờ? ",
  "dn16:5.12.9": "Này Ānanda, khi nghĩ: 'Đây là tháp của Đức Độc Giác Phật', nhiều người khởi tâm tịnh tín. ",
  "dn16:5.12.10": "Sau khi tâm được tịnh tín, sau khi thân tan rã, sau khi chết, họ sẽ tái sanh vào cõi thiện, cõi trời. ",
  "dn16:5.12.11": "Này Ānanda, vì lý do này mà Độc Giác Phật đáng được dựng tháp thờ. ",
  "dn16:5.12.12": "Và này Ānanda, vì lý do gì mà đệ tử của Như Lai đáng được dựng tháp thờ? ",
  "dn16:5.12.13": "Này Ānanda, khi nghĩ: 'Đây là tháp của đệ tử của Đức Thế Tôn, bậc A-la-hán, Chánh Đẳng Giác', nhiều người khởi tâm tịnh tín. ",
  "dn16:5.12.14": "Sau khi tâm được tịnh tín, sau khi thân tan rã, sau khi chết, họ sẽ tái sanh vào cõi thiện, cõi trời. ",
  "dn16:5.12.15": "Này Ānanda, vì lý do này mà đệ tử của Như Lai đáng được dựng tháp thờ. ",
  "dn16:5.12.16": "Và này Ānanda, vì lý do gì mà Chuyển Luân Thánh Vương đáng được dựng tháp thờ? ",
  "dn16:5.12.17": "Này Ānanda, khi nghĩ: 'Đây là tháp của vị Pháp Vương cai trị đúng pháp', nhiều người khởi tâm tịnh tín. ",
  "dn16:5.12.18": "Sau khi tâm được tịnh tín, sau khi thân tan rã, sau khi chết, họ sẽ tái sanh vào cõi thiện, cõi trời. ",
  "dn16:5.12.19": "Này Ānanda, vì lý do này mà Chuyển Luân Thánh Vương đáng được dựng tháp thờ. ",
  "dn16:5.12.20": "Này Ānanda, đó là bốn hạng người đáng được dựng tháp thờ.\" ",
  "dn16:5.13.0": "31. Các Pháp Kỳ Diệu của Ānanda ",
  "dn16:5.13.1": "Rồi Tôn giả Ānanda đi vào tịnh thất, đứng tựa vào thanh cửa mà khóc: ",
  "dn16:5.13.2": "\"Thật vậy, ta vẫn còn là bậc hữu học, còn việc phải làm, thế mà Đức Đạo Sư của ta, bậc thương tưởng đến ta, lại sắp nhập Niết Bàn.\" ",
  "dn16:5.13.3": "Rồi Đức Thế Tôn gọi các Tỳ Kheo: ",
  "dn16:5.13.4": "\"Này các Tỳ Kheo, Ānanda đâu rồi?\" ",
  "dn16:5.13.5": "\"Bạch Thế Tôn, Tôn giả Ānanda đã đi vào tịnh thất, đứng tựa vào thanh cửa mà khóc: ",
  "dn16:5.13.6": "'Thật vậy, ta vẫn còn là bậc hữu học, còn việc phải làm, thế mà Đức Đạo Sư của ta, bậc thương tưởng đến ta, lại sắp nhập Niết Bàn.'\" ",
  "dn16:5.13.7": "Rồi Đức Thế Tôn gọi một Tỳ Kheo: ",
  "dn16:5.13.8": "\"Này Tỳ Kheo, hãy đi, nhân danh Ta gọi Ānanda: ",
  "dn16:5.13.9": "'Này hiền giả Ānanda, Đức Đạo Sư gọi ông.'\" ",
  "dn16:5.13.10": "\"Thưa vâng, bạch Thế Tôn\", vị Tỳ Kheo đó vâng lời Đức Thế Tôn, đi đến chỗ Tôn giả Ānanda; đến nơi, nói với Tôn giả Ānanda: ",
  "dn16:5.13.11": "\"Này hiền giả Ānanda, Đức Đạo Sư gọi ông.\" ",
  "dn16:5.14.1": "\"Thưa vâng, hiền giả\", Tôn giả Ānanda vâng lời vị Tỳ Kheo đó, đi đến chỗ Đức Thế Tôn; đến nơi, đảnh lễ Đức Thế Tôn rồi ngồi sang một bên. Khi Tôn giả Ānanda đã ngồi sang một bên, Đức Thế Tôn nói với Tôn giả: ",
  "dn16:5.14.2": "\"Thôi, này Ānanda, đừng sầu khổ, đừng than khóc. Này Ānanda, chẳng phải Ta đã nói trước kia rằng: ",
  "dn16:5.14.3": "'Tất cả những gì thân yêu, vừa lòng đều phải chia lìa, phân tán, biến đổi'? ",
  "dn16:5.14.4": "Này Ānanda, làm sao có thể được điều này, rằng cái gì đã sinh, đã thành, bị tạo tác, phải hoại diệt, mà lại không hoại diệt—ngay cả thân của Như Lai—điều đó không thể có được. ",
  "dn16:5.14.5": "Này Ānanda, đã từ lâu ngươi đã hầu cận Như Lai với thân nghiệp từ ái, lợi ích, an lạc, không hai, vô lượng; với khẩu nghiệp từ ái, lợi ích, an lạc, không hai, vô lượng; với ý nghiệp từ ái, lợi ích, an lạc, không hai, vô lượng. ",
  "dn16:5.14.6": "Ngươi đã làm được công đức, này Ānanda. Hãy tinh tấn, không lâu ngươi sẽ đoạn trừ các lậu hoặc.\" ",
  "dn16:5.15.1": "Rồi Đức Thế Tôn gọi các Tỳ Kheo: ",
  "dn16:5.15.2": "\"Này các Tỳ Kheo, tất cả chư Phật, bậc A-la-hán, Chánh Đẳng Giác trong quá khứ đều đã có những thị giả tối thắng như thế, như Ānanda đối với Ta. ",
  "dn16:5.15.3": "Này các Tỳ Kheo, tất cả chư Phật, bậc A-la-hán, Chánh Đẳng Giác trong tương lai cũng sẽ có những thị giả tối thắng như thế, như Ānanda đối với Ta. ",
  "dn16:5.15.4": "Này các Tỳ Kheo, Ānanda là bậc hiền trí; ",
  "dn16:5.15.5": "này các Tỳ Kheo, Ānanda là bậc sáng suốt. ",
  "dn16:5.15.6": "Ānanda biết: 'Đây là lúc các Tỳ Kheo đến chiêm ngưỡng Như Lai, đây là lúc các Tỳ Kheo ni, đây là lúc các nam cư sĩ, đây là lúc các nữ cư sĩ, đây là lúc các vua, đại thần, các ngoại đạo sư và đệ tử ngoại đạo đến chiêm ngưỡng Như Lai.' ",
  "dn16:5.16.1": "Này các Tỳ Kheo, có bốn pháp kỳ diệu, hy hữu nơi Ānanda. ",
  "dn16:5.16.2": "Bốn đó là gì? ",
  "dn16:5.16.3": "Này các Tỳ Kheo, nếu hội chúng Tỳ Kheo đến chiêm ngưỡng Ānanda, thì chỉ cần thấy Ānanda, họ đã hoan hỷ. ",
  "dn16:5.16.4": "Nếu Ānanda thuyết pháp tại đó, thì khi nghe pháp, họ cũng hoan hỷ. ",
  "dn16:5.16.5": "Này các Tỳ Kheo, hội chúng Tỳ Kheo vẫn chưa thỏa mãn, nhưng Ānanda đã ngừng nói. ",
  "dn16:5.16.6": "Này các Tỳ Kheo, nếu hội chúng Tỳ Kheo ni đến chiêm ngưỡng Ānanda, thì chỉ cần thấy Ānanda, họ đã hoan hỷ. ",
  "dn16:5.16.7": "Nếu Ānanda thuyết pháp tại đó, thì khi nghe pháp, họ cũng hoan hỷ. ",
  "dn16:5.16.8": "Này các Tỳ Kheo, hội chúng Tỳ Kheo ni vẫn chưa thỏa mãn, nhưng Ānanda đã ngừng nói. ",
  "dn16:5.16.9": "Này các Tỳ Kheo, nếu hội chúng nam cư sĩ đến chiêm ngưỡng Ānanda, thì chỉ cần thấy Ānanda, họ đã hoan hỷ. ",
  "dn16:5.16.10": "Nếu Ānanda thuyết pháp tại đó, thì khi nghe pháp, họ cũng hoan hỷ. ",
  "dn16:5.16.11": "Này các Tỳ Kheo, hội chúng nam cư sĩ vẫn chưa thỏa mãn, nhưng Ānanda đã ngừng nói. ",
  "dn16:5.16.12": "Này các Tỳ Kheo, nếu hội chúng nữ cư sĩ đến chiêm ngưỡng Ānanda, thì chỉ cần thấy Ānanda, họ đã hoan hỷ. ",
  "dn16:5.16.13": "Nếu Ānanda thuyết pháp tại đó, thì khi nghe pháp, họ cũng hoan hỷ. ",
  "dn16:5.16.14": "Này các Tỳ Kheo, hội chúng nữ cư sĩ vẫn chưa thỏa mãn, nhưng Ānanda đã ngừng nói. ",
  "dn16:5.16.15": "Này các Tỳ Kheo, đó là bốn pháp kỳ diệu, hy hữu nơi Ānanda. ",
  "dn16:5.16.16": "Này các Tỳ Kheo, có bốn pháp kỳ diệu, hy hữu nơi Chuyển Luân Thánh Vương. ",
  "dn16:5.16.17": "Bốn đó là gì? ",
  "dn16:5.16.18": "Này các Tỳ Kheo, nếu hội chúng sát-đế-lỵ đến chiêm ngưỡng Chuyển Luân Thánh Vương, thì chỉ cần thấy Ngài, họ đã hoan hỷ. ",
  "dn16:5.16.19": "Nếu Chuyển Luân Thánh Vương nói tại đó, thì khi nghe lời Ngài, họ cũng hoan hỷ. ",
  "dn16:5.16.20": "Này các Tỳ Kheo, hội chúng sát-đế-lỵ vẫn chưa thỏa mãn, nhưng Chuyển Luân Thánh Vương đã ngừng nói. ",
  "dn16:5.16.21": "Nếu này các Tỳ Kheo, hội chúng bà-la-môn …vân vân… ",
  "dn16:5.16.22": "hội chúng gia chủ …vân vân… ",
  "dn16:5.16.23": "hội chúng sa-môn đến chiêm ngưỡng Chuyển Luân Thánh Vương, thì chỉ cần thấy Ngài, họ đã hoan hỷ. ",
  "dn16:5.16.24": "Nếu Chuyển Luân Thánh Vương nói tại đó, thì khi nghe lời Ngài, họ cũng hoan hỷ. ",
  "dn16:5.16.25": "Này các Tỳ Kheo, hội chúng sa-môn vẫn chưa thỏa mãn, nhưng Chuyển Luân Thánh Vương đã ngừng nói. ",
  "dn16:5.16.26": "Cũng vậy, này các Tỳ Kheo, có bốn pháp kỳ diệu, hy hữu nơi Ānanda. ",
  "dn16:5.16.27": "Này các Tỳ Kheo, nếu hội chúng Tỳ Kheo đến chiêm ngưỡng Ānanda, thì chỉ cần thấy Ānanda, họ đã hoan hỷ. ",
  "dn16:5.16.28": "Nếu Ānanda thuyết pháp tại đó, thì khi nghe pháp, họ cũng hoan hỷ. ",
  "dn16:5.16.29": "Này các Tỳ Kheo, hội chúng Tỳ Kheo vẫn chưa thỏa mãn. ",
  "dn16:5.16.30": "Nhưng Ānanda đã ngừng nói. ",
  "dn16:5.16.31": "Nếu này các Tỳ Kheo, hội chúng Tỳ Kheo ni …vân vân… ",
  "dn16:5.16.32": "hội chúng nam cư sĩ …vân vân… ",
  "dn16:5.16.33": "hội chúng nữ cư sĩ đến chiêm ngưỡng Ānanda, thì chỉ cần thấy Ānanda, họ đã hoan hỷ. ",
  "dn16:5.16.34": "Nếu Ānanda thuyết pháp tại đó, thì khi nghe pháp, họ cũng hoan hỷ. ",
  "dn16:5.16.35": "Này các Tỳ Kheo, hội chúng nữ cư sĩ vẫn chưa thỏa mãn. ",
  "dn16:5.16.36": "Nhưng Ānanda đã ngừng nói. ",
  "dn16:5.16.37": "Này các Tỳ Kheo, đó là bốn pháp kỳ diệu, hy hữu nơi Ānanda.\" ",
  "dn16:5.17.0": "32. Bài Thuyết Pháp Về Kinh Mahāsudassana ",
  "dn16:5.17.1": "Khi được nghe nói như vậy, Tôn giả Ānanda bạch Đức Thế Tôn: ",
  "dn16:5.17.2": "\"Bạch Thế Tôn, xin Đức Thế Tôn đừng nhập Niết Bàn tại thị trấn nhỏ bé, hoang vắng, chỉ là một nhánh nhỏ này. ",
  "dn16:5.17.3": "Bạch Thế Tôn, có các thành phố lớn khác, đó là—",
  "dn16:5.17.4": "Campā, Rājagaha (Vương Xá), Sāvatthī, Sāketa, Kosambī, Bārāṇasī (Ba-la-nại); ",
  "dn16:5.17.5": "xin Đức Thế Tôn hãy nhập Niết Bàn tại đó. ",
  "dn16:5.17.6": "Tại đó có nhiều đại gia đình sát-đế-lỵ, đại gia đình bà-la-môn, đại gia đình gia chủ có lòng tịnh tín nơi Như Lai. ",
  "dn16:5.17.7": "Họ sẽ cúng dường thân xác Như Lai.\" ",
  "dn16:5.17.8": "\"Này Ānanda, đừng nói như vậy; này Ānanda, đừng nói như vậy: ",
  "dn16:5.17.9": "'thị trấn nhỏ bé, hoang vắng, chỉ là một nhánh nhỏ'. ",
  "dn16:5.18.1": "Thuở xưa, này Ānanda, có vị vua tên là Mahāsudassana, là Chuyển Luân Thánh Vương, đúng pháp, vị Pháp Vương, chinh phục bốn phương, giữ vững các quốc độ, đầy đủ bảy báu. ",
  "dn16:5.18.2": "Này Ānanda, vua Mahāsudassana có kinh đô chính là Kusinārā này, tên là Kusāvatī. ",
  "dn16:5.18.3": "Từ đông sang tây dài mười hai do-tuần; từ bắc xuống nam rộng bảy do-tuần. ",
  "dn16:5.18.4": "Này Ānanda, kinh đô Kusāvatī thịnh vượng, phồn vinh, đông dân, nhộn nhịp, có đầy đủ lương thực. ",
  "dn16:5.18.5": "Này Ānanda, giống như kinh đô Āḷakamandā của chư thiên thịnh vượng, phồn vinh, đông dân, nhộn nhịp với dạ-xoa, có đầy đủ lương thực; ",
  "dn16:5.18.6": "cũng vậy, này Ānanda, kinh đô Kusāvatī thịnh vượng, phồn vinh, đông dân, nhộn nhịp, có đầy đủ lương thực. ",
  "dn16:5.18.7": "Này Ānanda, kinh đô Kusāvatī ngày đêm không ngớt mười loại âm thanh, đó là—",
  "dn16:5.18.8": "tiếng voi, tiếng ngựa, tiếng xe, tiếng trống, tiếng trống cơm, tiếng đàn tỳ-bà, tiếng hát, tiếng tù và, tiếng chũm chọe, tiếng vỗ tay, và âm thanh thứ mười là 'ăn đi, uống đi, nhai đi'. ",
  "dn16:5.19.1": "Này Ānanda, ngươi hãy đi vào Kusinārā, thông báo cho dân Mallā ở Kusinārā: ",
  "dn16:5.19.2": "'Này các vị Vāseṭṭha, đêm nay, vào canh cuối, Như Lai sẽ nhập Niết Bàn. ",
  "dn16:5.19.3": "Này các vị Vāseṭṭha, hãy đến, hãy đến. ",
  "dn16:5.19.4": "Đừng để sau này các vị hối hận rằng—",
  "dn16:5.19.5": "Như Lai đã nhập Niết Bàn ngay trong địa phận làng mình, mà chúng ta không được chiêm ngưỡng Như Lai vào lúc cuối.'\" ",
  "dn16:5.19.6": "\"Thưa vâng, bạch Thế Tôn\", Tôn giả Ānanda vâng lời Đức Thế Tôn, đắp y, cầm y bát, cùng một vị đi vào Kusinārā. ",
  "dn16:5.20.0": "33. Dân Mallā Đến Đảnh Lễ ",
  "dn16:5.20.1": "Lúc bấy giờ, dân Mallā ở Kusinārā đang tập trung tại nhà hội vì một công việc nào đó. ",
  "dn16:5.20.2": "Rồi Tôn giả Ānanda đi đến nhà hội của dân Mallā ở Kusinārā; đến nơi, thông báo cho dân Mallā ở Kusinārā: ",
  "dn16:5.20.3": "\"Này các vị Vāseṭṭha, đêm nay, vào canh cuối, Như Lai sẽ nhập Niết Bàn. ",
  "dn16:5.20.4": "Này các vị Vāseṭṭha, hãy đến, hãy đến. ",
  "dn16:5.20.5": "Đừng để sau này các vị hối hận rằng: ",
  "dn16:5.20.6": "'Như Lai đã nhập Niết Bàn ngay trong địa phận làng mình, mà chúng ta không được chiêm ngưỡng Như Lai vào lúc cuối.'\" ",
  "dn16:5.21.1": "Nghe lời Tôn giả Ānanda nói, dân Mallā, con trai Mallā, con dâu Mallā, vợ các vị Mallā, đều sầu khổ, buồn bã, tâm đau đớn; có người xõa tóc khóc than, đưa tay khóc than, ngã lăn lộn, lăn qua lăn lại: ",
  "dn16:5.21.2": "\"Đức Thế Tôn nhập Niết Bàn quá sớm, bậc Thiện Thệ nhập Niết Bàn quá sớm, con mắt của thế gian biến mất quá sớm.\" ",
  "dn16:5.21.3": "Rồi dân Mallā, con trai Mallā, con dâu Mallā, vợ các vị Mallā, sầu khổ, buồn bã, tâm đau đớn, đi đến rừng sālā Upavattana của dân Mallā, đến chỗ Tôn giả Ānanda. ",
  "dn16:5.22.1": "Rồi Tôn giả Ānanda nghĩ: ",
  "dn16:5.22.2": "\"Nếu ta cho dân Mallā ở Kusinārā lần lượt từng người đảnh lễ Đức Thế Tôn, thì dân Mallā ở Kusinārā sẽ chưa đảnh lễ xong Đức Thế Tôn mà đêm đã qua. ",
  "dn16:5.22.3": "Vậy ta nên sắp xếp dân Mallā ở Kusinārā theo từng gia đình để đảnh lễ Đức Thế Tôn: ",
  "dn16:5.22.4": "'Bạch Thế Tôn, vị Mallā tên như vầy, cùng con cái, vợ con, tùy tùng, bạn hữu, cúi đầu đảnh lễ dưới chân Đức Thế Tôn.'\" ",
  "dn16:5.22.5": "Rồi Tôn giả Ānanda sắp xếp dân Mallā ở Kusinārā theo từng gia đình để đảnh lễ Đức Thế Tôn: ",
  "dn16:5.22.6": "\"Bạch Thế Tôn, vị Mallā tên như vầy, cùng con cái, vợ con, tùy tùng, bạn hữu, cúi đầu đảnh lễ dưới chân Đức Thế Tôn.\" ",
  "dn16:5.22.7": "Bằng cách này, Tôn giả Ānanda đã cho dân Mallā ở Kusinārā đảnh lễ Đức Thế Tôn xong trước canh đầu. ",
  "dn16:5.23.0": "34. Câu Chuyện Về Du Sĩ Subhadda ",
  "dn16:5.23.1": "Lúc bấy giờ, có một du sĩ ngoại đạo tên là Subhadda đang trú tại Kusinārā. ",
  "dn16:5.23.2": "Du sĩ Subhadda nghe tin: ",
  "dn16:5.23.3": "\"Nghe nói đêm nay, vào canh cuối, sa-môn Gotama sẽ nhập Niết Bàn.\" ",
  "dn16:5.23.4": "Rồi du sĩ Subhadda nghĩ: ",
  "dn16:5.23.5": "\"Ta đã từng nghe các du sĩ lớn tuổi, các bậc thầy của các thầy nói: ",
  "dn16:5.23.6": "'Thật hiếm hoi mới có Như Lai, bậc A-la-hán, Chánh Đẳng Giác xuất hiện ở đời.' ",
  "dn16:5.23.7": "Đêm nay, vào canh cuối, sa-môn Gotama sẽ nhập Niết Bàn. ",
  "dn16:5.23.8": "Có một mối nghi ngờ khởi lên trong tâm ta, ",
  "dn16:5.23.9": "ta có lòng tịnh tín nơi sa-môn Gotama như sau: 'Sa-môn Gotama có thể thuyết pháp cho ta, để ta có thể đoạn trừ mối nghi ngờ này.'\" ",
  "dn16:5.24.1": "Rồi du sĩ Subhadda đi đến rừng sālā Upavattana của dân Mallā, đến chỗ Tôn giả Ānanda; đến nơi, nói với Tôn giả Ānanda: ",
  "dn16:5.24.2": "\"Thưa Tôn giả Ānanda, tôi đã từng nghe các du sĩ lớn tuổi, các bậc thầy của các thầy nói: ",
  "dn16:5.24.3": "'Thật hiếm hoi mới có Như Lai, bậc A-la-hán, Chánh Đẳng Giác xuất hiện ở đời.' ",
  "dn16:5.24.4": "Đêm nay, vào canh cuối, sa-môn Gotama sẽ nhập Niết Bàn. ",
  "dn16:5.24.5": "Có một mối nghi ngờ khởi lên trong tâm tôi—",
  "dn16:5.24.6": "tôi có lòng tịnh tín nơi sa-môn Gotama rằng 'Sa-môn Gotama có thể thuyết pháp cho tôi, để tôi có thể đoạn trừ mối nghi ngờ này'. ",
  "dn16:5.24.7": "Thưa Tôn giả Ānanda, lành thay, xin cho tôi được gặp sa-môn Gotama.\" ",
  "dn16:5.24.8": "Khi được nghe nói như vậy, Tôn giả Ānanda nói với du sĩ Subhadda: ",
  "dn16:5.24.9": "\"Thôi, hiền giả Subhadda, đừng quấy rầy Đức Như Lai, Đức Thế Tôn đã mệt rồi.\" ",
  "dn16:5.24.10": "Lần thứ hai, du sĩ Subhadda …vân vân… ",
  "dn16:5.24.11": "lần thứ ba, du sĩ Subhadda nói với Tôn giả Ānanda: ",
  "dn16:5.24.12": "\"Thưa Tôn giả Ānanda, tôi đã từng nghe các du sĩ lớn tuổi, các bậc thầy của các thầy nói: ",
  "dn16:5.24.13": "'Thật hiếm hoi mới có Như Lai, bậc A-la-hán, Chánh Đẳng Giác xuất hiện ở đời.' ",
  "dn16:5.24.14": "Đêm nay, vào canh cuối, sa-môn Gotama sẽ nhập Niết Bàn. ",
  "dn16:5.24.15": "Có một mối nghi ngờ khởi lên trong tâm tôi—",
  "dn16:5.24.16": "tôi có lòng tịnh tín nơi sa-môn Gotama rằng 'Sa-môn Gotama có thể thuyết pháp cho tôi, để tôi có thể đoạn trừ mối nghi ngờ này'. ",
  "dn16:5.24.17": "Thưa Tôn giả Ānanda, lành thay, xin cho tôi được gặp sa-môn Gotama.\" ",
  "dn16:5.24.18": "Lần thứ ba, Tôn giả Ānanda nói với du sĩ Subhadda: ",
  "dn16:5.24.19": "\"Thôi, hiền giả Subhadda, đừng quấy rầy Đức Như Lai, Đức Thế Tôn đã mệt rồi.\" ",
  "dn16:5.25.1": "Đức Thế Tôn nghe được cuộc đối thoại giữa Tôn giả Ānanda và du sĩ Subhadda. ",
  "dn16:5.25.2": "Rồi Đức Thế Tôn gọi Tôn giả Ānanda: ",
  "dn16:5.25.3": "\"Thôi, này Ānanda, đừng ngăn Subhadda. Này Ānanda, hãy để Subhadda đến gặp Như Lai. ",
  "dn16:5.25.4": "Bất cứ điều gì Subhadda hỏi Ta, đều sẽ là để tìm hiểu, không phải để gây phiền nhiễu. ",
  "dn16:5.25.5": "Và bất cứ điều gì Ta trả lời, vị ấy sẽ hiểu ngay.\" ",
  "dn16:5.25.6": "Rồi Tôn giả Ānanda nói với du sĩ Subhadda: ",
  "dn16:5.25.7": "\"Hãy vào đi, hiền giả Subhadda, Đức Thế Tôn cho phép ông.\" ",
  "dn16:5.26.1": "Rồi du sĩ Subhadda đi đến chỗ Đức Thế Tôn; đến nơi, chào hỏi Đức Thế Tôn. Sau khi nói lời chào hỏi thân tình, đáng ghi nhớ, ông ngồi sang một bên. Ngồi sang một bên, du sĩ Subhadda bạch Đức Thế Tôn: ",
  "dn16:5.26.2": "\"Thưa Tôn giả Gotama, có những sa-môn, bà-la-môn có hội chúng, có đồ chúng, là thầy của các hội chúng, nổi tiếng, có tiếng tăm, lập giáo phái, được nhiều người coi là tốt đẹp, ",
  "dn16:5.26.3": "đó là—Pūraṇa Kassapa, Makkhali Gosāla, Ajita Kesakambala, Pakudha Kaccāyana, Sañcaya Belaṭṭhaputta, Nigaṇṭha Nāṭaputta, ",
  "dn16:5.26.4": "có phải tất cả các vị ấy đều chứng ngộ theo như họ tuyên bố, hay tất cả đều không chứng ngộ, hay một số chứng ngộ, một số không chứng ngộ?\" ",
  "dn16:5.26.5": "\"Thôi, này Subhadda, hãy bỏ qua việc đó: ",
  "dn16:5.26.6": "'Có phải tất cả các vị ấy đều chứng ngộ theo như họ tuyên bố, hay tất cả đều không chứng ngộ, hay một số chứng ngộ, một số không chứng ngộ?' ",
  "dn16:5.26.7": "Này Subhadda, Ta sẽ thuyết pháp cho ngươi; ",
  "dn16:5.26.8": "hãy lắng nghe, hãy khéo tác ý, Ta sẽ giảng.\" ",
  "dn16:5.26.9": "\"Thưa vâng, bạch Thế Tôn\", du sĩ Subhadda đáp lời Đức Thế Tôn. ",
  "dn16:5.26.10": "Đức Thế Tôn dạy như sau: ",
  "dn16:5.27.1": "\"Này Subhadda, trong giáo pháp và giới luật nào không có Bát Thánh Đạo, thì trong đó cũng không có bậc sa-môn thứ nhất. Trong đó cũng không có bậc sa-môn thứ hai. Trong đó cũng không có bậc sa-môn thứ ba. Trong đó cũng không có bậc sa-môn thứ tư. ",
  "dn16:5.27.2": "Này Subhadda, trong giáo pháp và giới luật nào có Bát Thánh Đạo, thì trong đó có bậc sa-môn thứ nhất, trong đó cũng có bậc sa-môn thứ hai, trong đó cũng có bậc sa-môn thứ ba, trong đó cũng có bậc sa-môn thứ tư. ",
  "dn16:5.27.3": "Này Subhadda, trong giáo pháp và giới luật này có Bát Thánh Đạo. Chỉ ở đây, này Subhadda, mới có bậc sa-môn, mới có bậc sa-môn thứ hai, mới có bậc sa-môn thứ ba, mới có bậc sa-môn thứ tư. Các tà thuyết ngoại đạo khác đều rỗng không, không có các bậc sa-môn chân chính. ",
  "dn16:5.27.4": "Và này Subhadda, nếu các Tỳ Kheo này sống đúng chánh pháp, thì đời này sẽ không vắng các bậc A-la-hán. ",
  "dn16:5.27.5": "Hai mươi chín tuổi, này Subhadda, ",
  "dn16:5.27.6": "Ta xuất gia tìm kiếm điều thiện; ",
  "dn16:5.27.7": "Đã hơn năm mươi năm, ",
  "dn16:5.27.8": "Kể từ khi Ta xuất gia, Subhadda; ",
  "dn16:5.27.9": "Sống trong phạm vi của Chánh Pháp, ",
  "dn16:5.27.10": "Ngoài đây ra không có bậc sa-môn nào. ",
  "dn16:5.27.11": "Cũng không có bậc sa-môn thứ hai. ",
  "dn16:5.27.12": "Cũng không có bậc sa-môn thứ ba. ",
  "dn16:5.27.13": "Cũng không có bậc sa-môn thứ tư. ",
  "dn16:5.27.14": "Các tà thuyết ngoại đạo khác đều rỗng không, không có các bậc sa-môn chân chính. ",
  "dn16:5.27.15": "Và này Subhadda, nếu các Tỳ Kheo này sống đúng chánh pháp, thì đời này sẽ không vắng các bậc A-la-hán.\" ",
  "dn16:5.28.1": "Khi được nghe nói như vậy, du sĩ Subhadda bạch Đức Thế Tôn: ",
  "dn16:5.28.2": "\"Thật vi diệu thay, bạch Thế Tôn! Thật vi diệu thay, bạch Thế Tôn! ",
  "dn16:5.28.3": "Bạch Thế Tôn, như người dựng đứng lại những gì bị lật úp, phơi bày những gì bị che đậy, chỉ đường cho kẻ lạc lối, hay cầm đèn dầu vào trong bóng tối với ý nghĩ: 'Người có mắt sẽ thấy được các vật'; cũng vậy, Đức Thế Tôn với nhiều phương tiện đã làm sáng tỏ Giáo Pháp. ",
  "dn16:5.28.4": "Bạch Thế Tôn, con xin quy y Đức Thế Tôn, quy y Pháp và quy y Tăng. ",
  "dn16:5.28.5": "Bạch Thế Tôn, xin cho con được xuất gia và thọ cụ túc giới trước mặt Đức Thế Tôn.\" ",
  "dn16:5.29.1": "\"Này Subhadda, ai là người trước kia theo ngoại đạo, muốn xuất gia, muốn thọ cụ túc giới trong giáo pháp và giới luật này, phải sống biệt trú bốn tháng. Sau bốn tháng, nếu các Tỳ Kheo hoan hỷ chấp thuận, thì cho xuất gia, cho thọ cụ túc giới làm Tỳ Kheo. ",
  "dn16:5.29.2": "Nhưng Ta nhận thấy có sự sai biệt cá nhân về điểm này.\" ",
  "dn16:5.29.3": "\"Bạch Thế Tôn, nếu những người trước kia theo ngoại đạo, muốn xuất gia, muốn thọ cụ túc giới trong giáo pháp và giới luật này, phải sống biệt trú bốn tháng, sau bốn tháng các Tỳ Kheo hoan hỷ chấp thuận thì cho xuất gia, cho thọ cụ túc giới làm Tỳ Kheo; thì con xin sống biệt trú bốn năm, sau bốn năm, nếu các Tỳ Kheo hoan hỷ chấp thuận, mong cho con được xuất gia, được thọ cụ túc giới làm Tỳ Kheo.\" ",
  "dn16:5.29.4": "Rồi Đức Thế Tôn gọi Tôn giả Ānanda: ",
  "dn16:5.29.5": "\"Này Ānanda, hãy cho Subhadda xuất gia.\" ",
  "dn16:5.29.6": "\"Thưa vâng, bạch Thế Tôn\", Tôn giả Ānanda vâng lời Đức Thế Tôn. ",
  "dn16:5.30.1": "Rồi du sĩ Subhadda nói với Tôn giả Ānanda: ",
  "dn16:5.30.2": "\"Lợi lộc thay cho hiền giả Ānanda! Phúc lớn thay cho hiền giả Ānanda, ",
  "dn16:5.30.3": "những người được đích thân Đức Đạo Sư phong làm đệ tử!\" ",
  "dn16:5.30.4": "Rồi du sĩ Subhadda được xuất gia và thọ cụ túc giới trước mặt Đức Thế Tôn. ",
  "dn16:5.30.5": "Không lâu sau khi thọ cụ túc giới, Tôn giả Subhadda sống một mình, viễn ly, không buông lung, tinh cần, chuyên chú, chẳng bao lâu—chính vì mục đích mà các người con gia đình cao quý từ bỏ gia đình xuất gia sống không nhà—Tôn giả đã ngay trong đời này tự mình chứng ngộ với thắng trí, chứng và trú viên mãn phạm hạnh vô thượng ấy. ",
  "dn16:5.30.6": "Vị Tôn giả đã liễu tri: \"Sanh đã tận, phạm hạnh đã thành, việc cần làm đã làm xong, không còn tái sanh đời khác.\" ",
  "dn16:5.30.7": "Và Tôn giả Subhadda trở thành một trong các bậc A-la-hán. ",
  "dn16:5.30.8": "Ngài là vị đệ tử cuối cùng được chính Đức Thế Tôn chứng nhận. ",
  "dn16:5.30.9": "Hết phần tụng đọc thứ năm. ",
  "dn16:6.1.0": "35. Lời Dạy Cuối Cùng của Như Lai ",
  "dn16:6.1.1": "Rồi Đức Thế Tôn gọi Tôn giả Ānanda: ",
  "dn16:6.1.2": "\"Này Ānanda, có thể các ông nghĩ rằng: ",
  "dn16:6.1.3": "'Lời dạy đã mất Đạo Sư, chúng ta không còn Đạo Sư.' ",
  "dn16:6.1.4": "Này Ānanda, không nên nghĩ như vậy. ",
  "dn16:6.1.5": "Này Ānanda, Pháp và Luật mà Ta đã giảng dạy, đã ban hành cho các ông, sau khi Ta nhập diệt, sẽ là Đạo Sư của các ông. ",
  "dn16:6.2.1": "Này Ānanda, hiện nay các Tỳ Kheo xưng hô nhau bằng tiếng 'hiền giả', sau khi Ta nhập diệt, không nên xưng hô như vậy nữa. ",
  "dn16:6.2.2": "Này Ānanda, Tỳ Kheo lớn hạ nên gọi Tỳ Kheo nhỏ hạ bằng tên, bằng họ, hoặc bằng tiếng 'hiền giả'. ",
  "dn16:6.2.3": "Còn Tỳ Kheo nhỏ hạ nên gọi Tỳ Kheo lớn hạ bằng 'Tôn giả' hoặc 'Đại đức'. ",
  "dn16:6.3.1": "Này Ānanda, nếu Tăng chúng muốn, sau khi Ta nhập diệt, có thể hủy bỏ các tiểu học giới và tiểu tiểu học giới. ",
  "dn16:6.4.1": "Này Ānanda, sau khi Ta nhập diệt, hãy dùng hình phạt Phạm đàn đối với Tỳ Kheo Channa.\" ",
  "dn16:6.4.2": "\"Bạch Thế Tôn, hình phạt Phạm đàn là gì?\" ",
  "dn16:6.4.3": "\"Này Ānanda, Tỳ Kheo Channa muốn nói gì thì nói. ",
  "dn16:6.4.4": "Các Tỳ Kheo không nên nói với vị ấy, không khuyên bảo, không giáo huấn.\" ",
  "dn16:6.5.1": "Rồi Đức Thế Tôn gọi các Tỳ Kheo: ",
  "dn16:6.5.2": "\"Này các Tỳ Kheo, nếu có Tỳ Kheo nào có nghi ngờ hay phân vân về Đức Phật, về Pháp, về Tăng, về Đạo, về sự tu tập, hãy hỏi đi, này các Tỳ Kheo, đừng để sau này hối hận: ",
  "dn16:6.5.3": "'Đức Đạo Sư đã ở trước mặt chúng ta, mà chúng ta không thể hỏi Đức Thế Tôn được.'\" ",
  "dn16:6.5.4": "Khi được nghe nói như vậy, các Tỳ Kheo im lặng. ",
  "dn16:6.6.1": "Lần thứ hai, Đức Thế Tôn …vân vân… ",
  "dn16:6.6.2": "lần thứ ba, Đức Thế Tôn gọi các Tỳ Kheo: ",
  "dn16:6.6.3": "\"Này các Tỳ Kheo, nếu có Tỳ Kheo nào có nghi ngờ hay phân vân về Đức Phật, về Pháp, về Tăng, về Đạo, về sự tu tập, hãy hỏi đi, này các Tỳ Kheo, đừng để sau này hối hận: ",
  "dn16:6.6.4": "'Đức Đạo Sư đã ở trước mặt chúng ta, mà chúng ta không thể hỏi Đức Thế Tôn được.'\" ",
  "dn16:6.6.5": "Lần thứ ba, các Tỳ Kheo vẫn im lặng. ",
  "dn16:6.6.6": "Rồi Đức Thế Tôn gọi các Tỳ Kheo: ",
  "dn16:6.6.7": "\"Này các Tỳ Kheo, có thể do lòng tôn kính Đạo Sư mà các ông không hỏi. Vậy này các Tỳ Kheo, người bạn hãy thông báo cho bạn mình.\" ",
  "dn16:6.6.8": "Khi được nghe nói như vậy, các Tỳ Kheo vẫn im lặng. ",
  "dn16:6.6.9": "Rồi Tôn giả Ānanda bạch Đức Thế Tôn: ",
  "dn16:6.6.10": "\"Thật kỳ diệu thay, bạch Thế Tôn! Thật hy hữu thay, bạch Thế Tôn! Bạch Thế Tôn, con có lòng tin như vầy, trong chúng Tỳ Kheo này, 'không có một Tỳ Kheo nào có nghi ngờ hay phân vân về Đức Phật, về Pháp, về Tăng, về Đạo, về sự tu tập'.\" ",
  "dn16:6.6.11": "\"Này Ānanda, ngươi nói do lòng tin, nhưng Như Lai ở đây có trí. Trong chúng Tỳ Kheo này, không có một Tỳ Kheo nào có nghi ngờ hay phân vân về Đức Phật, về Pháp, về Tăng, về Đạo, về sự tu tập. ",
  "dn16:6.6.12": "Này Ānanda, trong số năm trăm Tỳ Kheo này, vị Tỳ Kheo thấp nhất cũng là bậc Dự Lưu, không còn rơi vào ác đạo, chắc chắn hướng đến giác ngộ.\" ",
  "dn16:6.7.1": "Rồi Đức Thế Tôn gọi các Tỳ Kheo: ",
  "dn16:6.7.2": "\"Này các Tỳ Kheo, nay Ta nói với các ông, ",
  "dn16:6.7.3": "các pháp hữu vi là vô thường, hãy tinh cần không buông lung.\" ",
  "dn16:6.7.4": "Đây là lời dạy cuối cùng của Như Lai. ",
  "dn16:6.8.0": "36. Câu Chuyện Nhập Niết Bàn ",
  "dn16:6.8.1": "Rồi Đức Thế Tôn nhập Sơ Thiền, xuất Sơ Thiền, nhập Nhị Thiền, xuất Nhị Thiền, nhập Tam Thiền, xuất Tam Thiền, nhập Tứ Thiền, xuất Tứ Thiền, nhập Không Vô Biên Xứ, xuất Không Vô Biên Xứ, nhập Thức Vô Biên Xứ, xuất Thức Vô Biên Xứ, nhập Vô Sở Hữu Xứ, xuất Vô Sở Hữu Xứ, nhập Phi Tưởng Phi Phi Tưởng Xứ, xuất Phi Tưởng Phi Phi Tưởng Xứ, nhập Diệt Thọ Tưởng Định. ",
  "dn16:6.8.2": "Rồi Tôn giả Ānanda nói với Tôn giả Anuruddha: ",
  "dn16:6.8.3": "\"Thưa Tôn giả Anuruddha, Đức Thế Tôn đã nhập Niết Bàn rồi.\" ",
  "dn16:6.8.4": "\"Này hiền giả Ānanda, Đức Thế Tôn chưa nhập Niết Bàn, Ngài đang nhập Diệt Thọ Tưởng Định.\" ",
  "dn16:6.9.1": "Rồi Đức Thế Tôn xuất Diệt Thọ Tưởng Định, nhập Phi Tưởng Phi Phi Tưởng Xứ, xuất Phi Tưởng Phi Phi Tưởng Xứ, nhập Vô Sở Hữu Xứ, xuất Vô Sở Hữu Xứ, nhập Thức Vô Biên Xứ, xuất Thức Vô Biên Xứ, nhập Không Vô Biên Xứ, xuất Không Vô Biên Xứ, nhập Tứ Thiền, xuất Tứ Thiền, nhập Tam Thiền, xuất Tam Thiền, nhập Nhị Thiền, xuất Nhị Thiền, nhập Sơ Thiền, xuất Sơ Thiền, nhập Nhị Thiền, xuất Nhị Thiền, nhập Tam Thiền, xuất Tam Thiền, nhập Tứ Thiền, xuất Tứ Thiền, ngay sau đó Đức Thế Tôn nhập Niết Bàn. ",
  "dn16:6.10.1": "Khi Đức Thế Tôn nhập Niết Bàn, ngay lúc Niết Bàn, có trận động đất lớn, kinh hãi, rợn người. Sấm trời vang dội. ",
  "dn16:6.10.2": "Khi Đức Thế Tôn nhập Niết Bàn, ngay lúc Niết Bàn, Phạm Thiên Sahampati đọc bài kệ này: ",
  "dn16:6.10.3": "\"Tất cả chúng sanh trong đời, ",
  "dn16:6.10.4": "Rồi sẽ phải xả bỏ thân này; ",
  "dn16:6.10.5": "Ngay cả bậc Đạo Sư như vậy, ",
  "dn16:6.10.6": "Vô song trong đời; ",
  "dn16:6.10.7": "Như Lai đầy đủ đại lực, ",
  "dn16:6.10.8": "Đấng Chánh Đẳng Giác đã nhập Niết Bàn.\" ",
  "dn16:6.10.9": "Khi Đức Thế Tôn nhập Niết Bàn, ngay lúc Niết Bàn, Thiên chủ Đế Thích đọc bài kệ này: ",
  "dn16:6.10.10": "\"Các hành là vô thường, ",
  "dn16:6.10.11": "Có tánh sanh và diệt; ",
  "dn16:6.10.12": "Sanh khởi rồi diệt đi, ",
  "dn16:6.10.13": "Tịch tịnh chúng là lạc.\" ",
  "dn16:6.10.14": "Khi Đức Thế Tôn nhập Niết Bàn, ngay lúc Niết Bàn, Tôn giả Anuruddha đọc các bài kệ này: ",
  "dn16:6.10.15": "\"Không còn hơi thở ra vào, ",
  "dn16:6.10.16": "Tâm bất động như vậy; ",
  "dn16:6.10.17": "Không dao động, đạt tịch tịnh, ",
  "dn16:6.10.18": "Bậc Mâu-ni đã ra đi. ",
  "dn16:6.10.19": "Với tâm không tháo lui, ",
  "dn16:6.10.20": "Ngài chịu đựng cảm thọ; ",
  "dn16:6.10.21": "Như ngọn đèn tắt ngấm, ",
  "dn16:6.10.22": "Tâm Ngài được giải thoát.\" ",
  "dn16:6.10.23": "Khi Đức Thế Tôn nhập Niết Bàn, ngay lúc Niết Bàn, Tôn giả Ānanda đọc bài kệ này: ",
  "dn16:6.10.24": "\"Lúc ấy thật kinh hoàng, ",
  "dn16:6.10.25": "Lúc ấy thật rợn người; ",
  "dn16:6.10.26": "Khi bậc đầy đủ mọi tướng tốt, ",
  "dn16:6.10.27": "Đấng Chánh Đẳng Giác đã nhập Niết Bàn.\" ",
  "dn16:6.10.28": "Khi Đức Thế Tôn nhập Niết Bàn, các Tỳ Kheo chưa ly tham có mặt ở đó, có người đưa tay khóc than, ngã lăn lộn, lăn qua lăn lại: \"Đức Thế Tôn nhập Niết Bàn quá sớm, bậc Thiện Thệ nhập Niết Bàn quá sớm, con mắt của thế gian biến mất quá sớm.\" ",
  "dn16:6.10.29": "Còn những Tỳ Kheo đã ly tham, các vị ấy chánh niệm, tỉnh giác chịu đựng: ",
  "dn16:6.10.30": "\"Các hành là vô thường, làm sao có thể khác được.\" ",
  "dn16:6.11.1": "Rồi Tôn giả Anuruddha nói với các Tỳ Kheo: ",
  "dn16:6.11.2": "\"Thôi đủ rồi, các hiền giả, đừng sầu khổ, đừng than khóc. ",
  "dn16:6.11.3": "Chẳng phải Đức Thế Tôn đã nói trước kia rằng: ",
  "dn16:6.11.4": "'Tất cả những gì thân yêu, vừa lòng đều phải chia lìa, phân tán, biến đổi.' ",
  "dn16:6.11.5": "Này các hiền giả, làm sao có thể được điều này, rằng cái gì đã sinh, đã thành, bị tạo tác, phải hoại diệt, mà lại không hoại diệt—điều đó không thể có được. ",
  "dn16:6.11.6": "Này các hiền giả, các chư thiên đang than phiền.\" ",
  "dn16:6.11.7": "\"Thưa Tôn giả, các chư thiên mà Tôn giả Anuruddha đang nghĩ đến ở trong trạng thái nào?\" ",
  "dn16:6.11.8": "\"Này hiền giả Ānanda, có những chư thiên ở trên không trung có tưởng về đất, các vị ấy xõa tóc khóc than, đưa tay khóc than, ngã lăn lộn, lăn qua lăn lại: ",
  "dn16:6.11.9": "'Đức Thế Tôn nhập Niết Bàn quá sớm, bậc Thiện Thệ nhập Niết Bàn quá sớm, con mắt của thế gian biến mất quá sớm.' ",
  "dn16:6.11.10": "Này hiền giả Ānanda, có những chư thiên ở trên đất có tưởng về đất, các vị ấy xõa tóc khóc than, đưa tay khóc than, ngã lăn lộn, lăn qua lăn lại: ",
  "dn16:6.11.11": "'Đức Thế Tôn nhập Niết Bàn quá sớm, bậc Thiện Thệ nhập Niết Bàn quá sớm, con mắt của thế gian biến mất quá sớm.' ",
  "dn16:6.11.12": "Còn những chư thiên đã ly tham, các vị ấy chánh niệm, tỉnh giác chịu đựng: ",
  "dn16:6.11.13": "'Các hành là vô thường, làm sao có thể khác được.'\" ",
  "dn16:6.11.14": "Rồi Tôn giả Anuruddha và Tôn giả Ānanda trải qua phần đêm còn lại bằng lời pháp thoại. ",
  "dn16:6.12.1": "Rồi Tôn giả Anuruddha gọi Tôn giả Ānanda: ",
  "dn16:6.12.2": "\"Này hiền giả Ānanda, hãy đi vào Kusinārā thông báo cho dân Mallā ở Kusinārā: ",
  "dn16:6.12.3": "'Này các vị Vāseṭṭha, Đức Thế Tôn đã nhập Niết Bàn, ",
  "dn16:6.12.4": "xin các vị hãy làm những gì các vị thấy đúng thời.'\" ",
  "dn16:6.12.5": "\"Thưa vâng, Tôn giả\", Tôn giả Ānanda vâng lời Tôn giả Anuruddha, vào buổi sáng đắp y, cầm y bát, cùng một vị đi vào Kusinārā. ",
  "dn16:6.12.6": "Lúc bấy giờ, dân Mallā ở Kusinārā đang tập trung tại nhà hội vì chính công việc đó. ",
  "dn16:6.12.7": "Rồi Tôn giả Ānanda đi đến nhà hội của dân Mallā ở Kusinārā; đến nơi, thông báo cho dân Mallā ở Kusinārā: ",
  "dn16:6.12.8": "\"Này các vị Vāseṭṭha, Đức Thế Tôn đã nhập Niết Bàn, ",
  "dn16:6.12.9": "xin các vị hãy làm những gì các vị thấy đúng thời.\" ",
  "dn16:6.12.10": "Nghe lời Tôn giả Ānanda nói, dân Mallā, con trai Mallā, con dâu Mallā, vợ các vị Mallā, đều sầu khổ, buồn bã, tâm đau đớn; có người xõa tóc khóc than, đưa tay khóc than, ngã lăn lộn, lăn qua lăn lại: ",
  "dn16:6.12.11": "\"Đức Thế Tôn nhập Niết Bàn quá sớm, bậc Thiện Thệ nhập Niết Bàn quá sớm, con mắt của thế gian biến mất quá sớm.\" ",
  "dn16:6.13.0": "37. Cúng Dường Xá Lợi Đức Phật ",
  "dn16:6.13.1": "Rồi dân Mallā ở Kusinārā ra lệnh cho một số người: ",
  "dn16:6.13.2": "\"Này các ngươi, hãy tập hợp hương, hoa, và tất cả các nhạc cụ ở Kusinārā.\" ",
  "dn16:6.13.3": "Rồi dân Mallā ở Kusinārā mang theo hương, hoa, tất cả các nhạc cụ và năm trăm đôi vải, đi đến rừng sālā Upavattana của dân Mallā, đến chỗ thân Đức Thế Tôn; đến nơi, họ cung kính, tôn trọng, quý trọng, cúng dường thân Đức Thế Tôn bằng các điệu múa, bài hát, âm nhạc, hương hoa, che các tấm lọng vải, thiết lập các nhà mát hình vòng tròn, và trải qua một ngày như vậy. ",
  "dn16:6.13.4": "Rồi dân Mallā ở Kusinārā nghĩ: ",
  "dn16:6.13.5": "\"Hôm nay đã quá muộn để hỏa táng thân Đức Thế Tôn, ngày mai chúng ta sẽ hỏa táng thân Đức Thế Tôn.\" ",
  "dn16:6.13.6": "Rồi dân Mallā ở Kusinārā cung kính, tôn trọng, quý trọng, cúng dường thân Đức Thế Tôn bằng các điệu múa, bài hát, âm nhạc, hương hoa, che các tấm lọng vải, thiết lập các nhà mát hình vòng tròn, và trải qua ngày thứ hai như vậy, ngày thứ ba như vậy, ngày thứ tư như vậy, ngày thứ năm như vậy, ngày thứ sáu như vậy. ",
  "dn16:6.14.1": "Đến ngày thứ bảy, dân Mallā ở Kusinārā nghĩ: ",
  "dn16:6.14.2": "\"Chúng ta cung kính, tôn trọng, quý trọng, cúng dường thân Đức Thế Tôn bằng các điệu múa, bài hát, âm nhạc, hương hoa, rồi mang về phía nam thành, ra ngoài về phía nam thành để hỏa táng thân Đức Thế Tôn.\" ",
  "dn16:6.14.3": "Lúc bấy giờ, có tám vị thủ lĩnh Mallā đã gội đầu, mặc y phục mới: ",
  "dn16:6.14.4": "\"Chúng ta sẽ khiêng thân Đức Thế Tôn lên\"—nhưng các vị không thể khiêng lên được. ",
  "dn16:6.14.5": "Rồi dân Mallā ở Kusinārā nói với Tôn giả Anuruddha: ",
  "dn16:6.14.6": "\"Thưa Tôn giả Anuruddha, do nhân gì, do duyên gì mà tám vị thủ lĩnh Mallā này, đã gội đầu, mặc y phục mới: ",
  "dn16:6.14.7": "'Chúng ta sẽ khiêng thân Đức Thế Tôn lên', lại không thể khiêng lên được?\" ",
  "dn16:6.14.8": "\"Này các vị Vāseṭṭha, ý định của các vị là một, ý định của chư thiên là khác.\" ",
  "dn16:6.15.1": "\"Thưa Tôn giả, ý định của chư thiên là gì?\" ",
  "dn16:6.15.2": "\"Này các vị Vāseṭṭha, ý định của các vị là: ",
  "dn16:6.15.3": "'Chúng ta cung kính, tôn trọng, quý trọng, cúng dường thân Đức Thế Tôn bằng các điệu múa, bài hát, âm nhạc, hương hoa, rồi mang về phía nam thành, ra ngoài về phía nam thành để hỏa táng thân Đức Thế Tôn.' ",
  "dn16:6.15.4": "Nhưng này các vị Vāseṭṭha, ý định của chư thiên là: ",
  "dn16:6.15.5": "'Chúng ta cung kính, tôn trọng, quý trọng, cúng dường thân Đức Thế Tôn bằng các điệu múa, bài hát, âm nhạc, hương hoa của cõi trời, rồi mang về phía bắc thành, vào thành qua cửa bắc, đi qua giữa thành, ra cửa đông, rồi đến đền Makuṭabandhana của dân Mallā ở phía đông thành. Tại đó, chúng ta sẽ hỏa táng thân Đức Thế Tôn.'\" ",
  "dn16:6.15.6": "\"Thưa Tôn giả, xin cho ý định của chư thiên được thực hiện.\" ",
  "dn16:6.16.1": "Lúc bấy giờ, Kusinārā ngập đầy hoa mạn-đà-la đến đầu gối, cho đến các nơi giáp ranh và các đống rác. ",
  "dn16:6.16.2": "Rồi chư thiên và dân Mallā ở Kusinārā cùng cung kính, tôn trọng, quý trọng, cúng dường thân Đức Thế Tôn bằng các điệu múa, bài hát, âm nhạc, hương hoa của cõi trời và cõi người, mang về phía bắc thành, vào thành qua cửa bắc, đi qua giữa thành, ra cửa đông, rồi đến đền Makuṭabandhana của dân Mallā ở phía đông thành, và tại đó họ đặt thân Đức Thế Tôn xuống. ",
  "dn16:6.17.1": "Rồi dân Mallā ở Kusinārā nói với Tôn giả Ānanda: ",
  "dn16:6.17.2": "\"Thưa Tôn giả Ānanda, chúng con phải xử lý thân Như Lai như thế nào?\" ",
  "dn16:6.17.3": "\"Này các vị Vāseṭṭha, xử lý thân Như Lai cũng như xử lý thân của Chuyển Luân Thánh Vương.\" ",
  "dn16:6.17.4": "\"Thưa Tôn giả Ānanda, xử lý thân của Chuyển Luân Thánh Vương như thế nào?\" ",
  "dn16:6.17.5": "\"Này các vị Vāseṭṭha, thân của Chuyển Luân Thánh Vương được quấn bằng vải mới, quấn xong vải mới, lại quấn bằng bông đã được chải, quấn xong bông đã được chải, lại quấn bằng vải mới. ",
  "dn16:6.17.6": "Bằng cách này, quấn thân Chuyển Luân Thánh Vương bằng năm trăm lớp vải, đặt vào quan tài sắt chứa đầy dầu, đậy bằng một quan tài sắt khác, rồi làm một giàn hỏa táng bằng đủ các loại hương thơm, và hỏa táng thân Chuyển Luân Thánh Vương. ",
  "dn16:6.17.7": "Sau đó, dựng tháp tôn thờ Chuyển Luân Thánh Vương ở ngã tư đường. ",
  "dn16:6.17.8": "Này các vị Vāseṭṭha, đó là cách xử lý thân của Chuyển Luân Thánh Vương. ",
  "dn16:6.17.9": "Này các vị Vāseṭṭha, xử lý thân Như Lai cũng phải như cách xử lý thân của Chuyển Luân Thánh Vương. ",
  "dn16:6.17.10": "Tháp thờ Như Lai phải được dựng ở ngã tư đường. ",
  "dn16:6.17.11": "Những ai tại đó dâng hoa, hương liệu, bột thơm, đảnh lễ, hoặc khởi tâm tịnh tín, sẽ được lợi ích và an lạc lâu dài.\" ",
  "dn16:6.18.1": "Rồi dân Mallā ở Kusinārā ra lệnh cho một số người: ",
  "dn16:6.18.2": "\"Này các ngươi, hãy tập hợp bông đã chải của dân Mallā.\" ",
  "dn16:6.18.3": "Rồi dân Mallā ở Kusinārā quấn thân Đức Thế Tôn bằng vải mới, quấn xong vải mới, lại quấn bằng bông đã chải, quấn xong bông đã chải, lại quấn bằng vải mới. ",
  "dn16:6.18.4": "Bằng cách này, quấn thân Đức Thế Tôn bằng năm trăm lớp vải, đặt vào quan tài sắt chứa đầy dầu, đậy bằng một quan tài sắt khác, rồi làm một giàn hỏa táng bằng đủ các loại hương thơm, và đặt thân Đức Thế Tôn lên giàn hỏa. ",
  "dn16:6.19.0": "38. Câu Chuyện Về Trưởng lão Mahākassapa ",
  "dn16:6.19.1": "Lúc bấy giờ, Tôn giả Mahākassapa đang đi trên con đường từ Pāvā đến Kusinārā, cùng với đại chúng Tỳ Kheo khoảng năm trăm vị. ",
  "dn16:6.19.2": "Rồi Tôn giả Mahākassapa rời khỏi con đường và ngồi xuống dưới một gốc cây. ",
  "dn16:6.19.3": "Lúc bấy giờ, có một đạo sĩ lõa thể đang đi trên con đường từ Kusinārā đến Pāvā, mang theo một hoa mạn-đà-la. ",
  "dn16:6.19.4": "Tôn giả Mahākassapa thấy vị đạo sĩ lõa thể đó từ xa đi đến, thấy vậy, Ngài nói với vị đạo sĩ: ",
  "dn16:6.19.5": "\"Này hiền giả, ngươi có biết Đức Đạo Sư của chúng ta không?\" ",
  "dn16:6.19.6": "\"Có, hiền giả, tôi biết. Hôm nay là ngày thứ bảy sa-môn Gotama nhập Niết Bàn. ",
  "dn16:6.19.7": "Tôi lấy được hoa mạn-đà-la này từ nơi đó.\" ",
  "dn16:6.19.8": "Trong số các Tỳ Kheo có mặt ở đó, các Tỳ Kheo chưa ly tham có người đưa tay khóc than, ngã lăn lộn, lăn qua lăn lại: ",
  "dn16:6.19.9": "\"Đức Thế Tôn nhập Niết Bàn quá sớm, bậc Thiện Thệ nhập Niết Bàn quá sớm, con mắt của thế gian biến mất quá sớm.\" ",
  "dn16:6.19.10": "Còn những Tỳ Kheo đã ly tham, các vị ấy chánh niệm, tỉnh giác chịu đựng: ",
  "dn16:6.19.11": "\"Các hành là vô thường, làm sao có thể khác được.\" ",
  "dn16:6.20.1": "Lúc bấy giờ, có vị tên Subhadda, người xuất gia khi tuổi đã lớn, đang ngồi trong hội chúng đó. ",
  "dn16:6.20.2": "Rồi Subhadda, người xuất gia khi tuổi đã lớn, nói với các Tỳ Kheo: ",
  "dn16:6.20.3": "\"Thôi đủ rồi, các hiền giả, đừng sầu khổ, đừng than khóc. Chúng ta đã được giải thoát khỏi vị đại sa-môn ấy rồi. Chúng ta vẫn bị khổ sở với: ",
  "dn16:6.20.4": "'Điều này hợp với các ông, điều này không hợp với các ông.' ",
  "dn16:6.20.5": "Bây giờ, chúng ta muốn làm gì thì làm, không muốn làm gì thì không làm.\" ",
  "dn16:6.20.6": "Rồi Tôn giả Mahākassapa gọi các Tỳ Kheo: ",
  "dn16:6.20.7": "\"Thôi đủ rồi, các hiền giả, đừng sầu khổ, đừng than khóc. ",
  "dn16:6.20.8": "Chẳng phải Đức Thế Tôn đã nói trước kia rằng: ",
  "dn16:6.20.9": "'Tất cả những gì thân yêu, vừa lòng đều phải chia lìa, phân tán, biến đổi.' ",
  "dn16:6.20.10": "Này các hiền giả, làm sao có thể được điều này, rằng cái gì đã sinh, đã thành, bị tạo tác, phải hoại diệt, mà lại không hoại diệt—ngay cả thân của Như Lai—điều đó không thể có được.\" ",
  "dn16:6.21.1": "Lúc bấy giờ, có bốn vị thủ lĩnh Mallā đã gội đầu, mặc y phục mới: ",
  "dn16:6.21.2": "\"Chúng ta sẽ châm lửa giàn hỏa của Đức Thế Tôn\"—nhưng các vị không thể châm được. ",
  "dn16:6.21.3": "Rồi dân Mallā ở Kusinārā nói với Tôn giả Anuruddha: ",
  "dn16:6.21.4": "\"Thưa Tôn giả Anuruddha, do nhân gì, do duyên gì mà bốn vị thủ lĩnh Mallā này, đã gội đầu, mặc y phục mới: ",
  "dn16:6.21.5": "'Chúng ta sẽ châm lửa giàn hỏa của Đức Thế Tôn', lại không thể châm được?\" ",
  "dn16:6.21.6": "\"Này các vị Vāseṭṭha, ý định của chư thiên là khác.\" ",
  "dn16:6.21.7": "\"Thưa Tôn giả, ý định của chư thiên là gì?\" ",
  "dn16:6.21.8": "\"Này các vị Vāseṭṭha, ý định của chư thiên là: ",
  "dn16:6.21.9": "'Tôn giả Mahākassapa đang đi trên con đường từ Pāvā đến Kusinārā cùng với đại chúng Tỳ Kheo khoảng năm trăm vị. ",
  "dn16:6.21.10": "Giàn hỏa của Đức Thế Tôn sẽ không bốc cháy cho đến khi Tôn giả Mahākassapa cúi đầu đảnh lễ dưới chân Đức Thế Tôn.'\" ",
  "dn16:6.21.11": "\"Thưa Tôn giả, xin cho ý định của chư thiên được thực hiện.\" ",
  "dn16:6.22.1": "Rồi Tôn giả Mahākassapa đi đến đền Makuṭabandhana của dân Mallā ở Kusinārā, đến chỗ giàn hỏa của Đức Thế Tôn; đến nơi, Ngài đắp y một bên vai, chắp tay, đi nhiễu quanh giàn hỏa ba vòng theo chiều bên phải, rồi cúi đầu đảnh lễ dưới chân Đức Thế Tôn. ",
  "dn16:6.22.2": "Năm trăm vị Tỳ Kheo đó cũng đắp y một bên vai, chắp tay, đi nhiễu quanh giàn hỏa ba vòng theo chiều bên phải, rồi cúi đầu đảnh lễ dưới chân Đức Thế Tôn. ",
  "dn16:6.22.3": "Sau khi Tôn giả Mahākassapa và năm trăm vị Tỳ Kheo đã đảnh lễ, giàn hỏa của Đức Thế Tôn tự động bốc cháy. ",
  "dn16:6.23.1": "Khi thân Đức Thế Tôn được hỏa thiêu, những gì là da, thịt, gân hay tủy đều không để lại tro, không để lại bụi; ",
  "dn16:6.23.2": "chỉ còn lại các xá lợi. ",
  "dn16:6.23.3": "Giống như khi bơ sữa hoặc dầu được đốt cháy, không để lại tro, không để lại bụi; ",
  "dn16:6.23.4": "cũng vậy, khi thân Đức Thế Tôn được hỏa thiêu, những gì là da, thịt, gân hay tủy đều không để lại tro, không để lại bụi; ",
  "dn16:6.23.5": "chỉ còn lại các xá lợi. ",
  "dn16:6.23.6": "Trong năm trăm đôi vải, chỉ có hai tấm vải không cháy—tấm trong cùng và tấm ngoài cùng. ",
  "dn16:6.23.7": "Khi thân Đức Thế Tôn đã được hỏa thiêu xong, từ hư không xuất hiện dòng nước dập tắt giàn hỏa của Đức Thế Tôn. ",
  "dn16:6.23.8": "Nước cũng dâng lên từ dưới đất dập tắt giàn hỏa của Đức Thế Tôn. ",
  "dn16:6.23.9": "Và dân Mallā ở Kusinārā cũng dập tắt giàn hỏa của Đức Thế Tôn bằng đủ các loại nước thơm. ",
  "dn16:6.23.10": "Rồi dân Mallā ở Kusinārā đặt xá lợi Đức Thế Tôn tại nhà hội suốt bảy ngày, xung quanh là hàng rào giáo và hàng rào cung, cung kính, tôn trọng, quý trọng, cúng dường bằng các điệu múa, bài hát, âm nhạc, hương hoa. ",
  "dn16:6.24.0": "39. Phân Chia Xá Lợi ",
  "dn16:6.24.1": "Vua A-xà-thế, con bà Vedehi của nước Ma-kiệt-đà, nghe tin: ",
  "dn16:6.24.2": "\"Đức Thế Tôn đã nhập Niết Bàn tại Kusinārā.\" ",
  "dn16:6.24.3": "Rồi vua A-xà-thế, con bà Vedehi của nước Ma-kiệt-đà, sai sứ đến dân Mallā ở Kusinārā: ",
  "dn16:6.24.4": "\"Đức Thế Tôn thuộc dòng sát-đế-lỵ, ta cũng thuộc dòng sát-đế-lỵ. Ta xứng đáng được một phần xá lợi Đức Thế Tôn. Ta cũng sẽ dựng tháp thờ xá lợi Đức Thế Tôn và tổ chức lễ cúng dường lớn.\" ",
  "dn16:6.24.5": "Các vị Licchavi ở Vesāli nghe tin: ",
  "dn16:6.24.6": "\"Đức Thế Tôn đã nhập Niết Bàn tại Kusinārā.\" ",
  "dn16:6.24.7": "Rồi các vị Licchavi ở Vesāli sai sứ đến dân Mallā ở Kusinārā: ",
  "dn16:6.24.8": "\"Đức Thế Tôn thuộc dòng sát-đế-lỵ, chúng tôi cũng thuộc dòng sát-đế-lỵ. Chúng tôi xứng đáng được một phần xá lợi Đức Thế Tôn. Chúng tôi cũng sẽ dựng tháp thờ xá lợi Đức Thế Tôn và tổ chức lễ cúng dường lớn.\" ",
  "dn16:6.24.9": "Các vị Sākya ở Kapilavatthu nghe tin: ",
  "dn16:6.24.10": "\"Đức Thế Tôn đã nhập Niết Bàn tại Kusinārā.\" ",
  "dn16:6.24.11": "Rồi các vị Sākya ở Kapilavatthu sai sứ đến dân Mallā ở Kusinārā: ",
  "dn16:6.24.12": "\"Đức Thế Tôn là bà con tối thắng của chúng tôi. Chúng tôi xứng đáng được một phần xá lợi Đức Thế Tôn. Chúng tôi cũng sẽ dựng tháp thờ xá lợi Đức Thế Tôn và tổ chức lễ cúng dường lớn.\" ",
  "dn16:6.24.13": "Các vị Buli ở Allakappa nghe tin: ",
  "dn16:6.24.14": "\"Đức Thế Tôn đã nhập Niết Bàn tại Kusinārā.\" ",
  "dn16:6.24.15": "Rồi các vị Buli ở Allakappa sai sứ đến dân Mallā ở Kusinārā: ",
  "dn16:6.24.16": "\"Đức Thế Tôn thuộc dòng sát-đế-lỵ, chúng tôi cũng thuộc dòng sát-đế-lỵ. Chúng tôi xứng đáng được một phần xá lợi Đức Thế Tôn. Chúng tôi cũng sẽ dựng tháp thờ xá lợi Đức Thế Tôn và tổ chức lễ cúng dường lớn.\" ",
  "dn16:6.24.17": "Các vị Koḷiya ở Rāmagāma nghe tin: ",
  "dn16:6.24.18": "\"Đức Thế Tôn đã nhập Niết Bàn tại Kusinārā.\" ",
  "dn16:6.24.19": "Rồi các vị Koḷiya ở Rāmagāma sai sứ đến dân Mallā ở Kusinārā: ",
  "dn16:6.24.20": "\"Đức Thế Tôn thuộc dòng sát-đế-lỵ, chúng tôi cũng thuộc dòng sát-đế-lỵ. Chúng tôi xứng đáng được một phần xá lợi Đức Thế Tôn. Chúng tôi cũng sẽ dựng tháp thờ xá lợi Đức Thế Tôn và tổ chức lễ cúng dường lớn.\" ",
  "dn16:6.24.21": "Bà-la-môn ở Veṭṭhadīpa nghe tin: ",
  "dn16:6.24.22": "\"Đức Thế Tôn đã nhập Niết Bàn tại Kusinārā.\" ",
  "dn16:6.24.23": "Rồi bà-la-môn ở Veṭṭhadīpa sai sứ đến dân Mallā ở Kusinārā: ",
  "dn16:6.24.24": "\"Đức Thế Tôn thuộc dòng sát-đế-lỵ, còn ta là bà-la-môn. Ta xứng đáng được một phần xá lợi Đức Thế Tôn. Ta cũng sẽ dựng tháp thờ xá lợi Đức Thế Tôn và tổ chức lễ cúng dường lớn.\" ",
  "dn16:6.24.25": "Các vị Mallā ở Pāvā nghe tin: ",
  "dn16:6.24.26": "\"Đức Thế Tôn đã nhập Niết Bàn tại Kusinārā.\" ",
  "dn16:6.24.27": "Rồi các vị Mallā ở Pāvā sai sứ đến dân Mallā ở Kusinārā: ",
  "dn16:6.24.28": "\"Đức Thế Tôn thuộc dòng sát-đế-lỵ, chúng tôi cũng thuộc dòng sát-đế-lỵ. Chúng tôi xứng đáng được một phần xá lợi Đức Thế Tôn. Chúng tôi cũng sẽ dựng tháp thờ xá lợi Đức Thế Tôn và tổ chức lễ cúng dường lớn.\" ",
  "dn16:6.25.1": "Khi được nghe nói như vậy, dân Mallā ở Kusinārā nói với các hội chúng, các nhóm ấy: ",
  "dn16:6.25.2": "\"Đức Thế Tôn đã nhập Niết Bàn tại địa phận làng chúng tôi. Chúng tôi sẽ không chia phần xá lợi Đức Thế Tôn.\" ",
  "dn16:6.25.3": "Khi được nghe nói như vậy, bà-la-môn Doṇa nói với các hội chúng, các nhóm ấy: ",
  "dn16:6.25.4": "\"Thưa các vị, xin nghe một lời của tôi, ",
  "dn16:6.25.5": "Đức Phật của chúng ta đã dạy về nhẫn nhục; ",
  "dn16:6.25.6": "Thật không tốt nếu vì xá lợi của bậc Tối Thượng, ",
  "dn16:6.25.7": "Mà lại xảy ra tranh chấp. ",
  "dn16:6.25.8": "Tất cả chúng ta hãy hòa hợp, đoàn kết, ",
  "dn16:6.25.9": "Vui vẻ chia thành tám phần; ",
  "dn16:6.25.10": "Hãy để tháp được dựng khắp các phương, ",
  "dn16:6.25.11": "Cho nhiều người có lòng tịnh tín với bậc Hữu Nhãn.\" ",
  "dn16:6.25.12": "\"Vậy, này bà-la-môn, chính ngài hãy chia xá lợi Đức Thế Tôn thành tám phần bằng nhau.\" ",
  "dn16:6.25.13": "\"Thưa vâng\", bà-la-môn Doṇa vâng lời các hội chúng, các nhóm ấy, chia xá lợi Đức Thế Tôn thành tám phần bằng nhau rồi nói với các hội chúng, các nhóm ấy: ",
  "dn16:6.25.14": "\"Thưa các vị, xin hãy cho tôi cái bình đong, tôi cũng sẽ dựng tháp thờ cái bình đong và tổ chức lễ cúng dường lớn.\" ",
  "dn16:6.25.15": "Họ đưa cái bình đong cho bà-la-môn Doṇa. ",
  "dn16:6.26.1": "Các vị Moriya ở Pippalivana nghe tin: ",
  "dn16:6.26.2": "\"Đức Thế Tôn đã nhập Niết Bàn tại Kusinārā.\" ",
  "dn16:6.26.3": "Rồi các vị Moriya ở Pippalivana sai sứ đến dân Mallā ở Kusinārā: ",
  "dn16:6.26.4": "\"Đức Thế Tôn thuộc dòng sát-đế-lỵ, chúng tôi cũng thuộc dòng sát-đế-lỵ. Chúng tôi xứng đáng được một phần xá lợi Đức Thế Tôn. Chúng tôi cũng sẽ dựng tháp thờ xá lợi Đức Thế Tôn và tổ chức lễ cúng dường lớn.\" ",
  "dn16:6.26.5": "\"Không còn phần xá lợi Đức Thế Tôn nữa, xá lợi Đức Thế Tôn đã được chia hết rồi. ",
  "dn16:6.26.6": "Xin hãy lấy than từ đây.\" ",
  "dn16:6.26.7": "Họ lấy than từ đó. ",
  "dn16:6.27.0": "40. Cúng Dường Tháp Xá Lợi ",
  "dn16:6.27.1": "Rồi vua A-xà-thế, con bà Vedehi của nước Ma-kiệt-đà, dựng tháp thờ xá lợi Đức Thế Tôn tại thành Vương Xá và tổ chức lễ cúng dường lớn. ",
  "dn16:6.27.2": "Các vị Licchavi ở Vesāli cũng dựng tháp thờ xá lợi Đức Thế Tôn tại Vesāli và tổ chức lễ cúng dường lớn. ",
  "dn16:6.27.3": "Các vị Sākya ở Kapilavatthu cũng dựng tháp thờ xá lợi Đức Thế Tôn tại Kapilavatthu và tổ chức lễ cúng dường lớn. ",
  "dn16:6.27.4": "Các vị Buli ở Allakappa cũng dựng tháp thờ xá lợi Đức Thế Tôn tại Allakappa và tổ chức lễ cúng dường lớn. ",
  "dn16:6.27.5": "Các vị Koḷiya ở Rāmagāma cũng dựng tháp thờ xá lợi Đức Thế Tôn tại Rāmagāma và tổ chức lễ cúng dường lớn. ",
  "dn16:6.27.6": "Bà-la-môn ở Veṭṭhadīpa cũng dựng tháp thờ xá lợi Đức Thế Tôn tại Veṭṭhadīpa và tổ chức lễ cúng dường lớn. ",
  "dn16:6.27.7": "Các vị Mallā ở Pāvā cũng dựng tháp thờ xá lợi Đức Thế Tôn tại Pāvā và tổ chức lễ cúng dường lớn. ",
  "dn16:6.27.8": "Các vị Mallā ở Kusinārā cũng dựng tháp thờ xá lợi Đức Thế Tôn tại Kusinārā và tổ chức lễ cúng dường lớn. ",
  "dn16:6.27.9": "Bà-la-môn Doṇa cũng dựng tháp thờ cái bình đong và tổ chức lễ cúng dường lớn. ",
  "dn16:6.27.10": "Các vị Moriya ở Pippalivana cũng dựng tháp thờ than tại Pippalivana và tổ chức lễ cúng dường lớn. ",
  "dn16:6.27.11": "Như vậy có tám tháp xá lợi, tháp thứ chín là tháp bình đong, tháp thứ mười là tháp than. ",
  "dn16:6.27.12": "Sự việc đã xảy ra như vậy. ",
  "dn16:6.28.1": "Xá lợi của bậc Hữu Nhãn được chia thành tám đấu, ",
  "dn16:6.28.2": "Bảy đấu được tôn thờ tại Diêm-phù-đề (Jambudīpa); ",
  "dn16:6.28.3": "Một đấu của Bậc Tối Thượng Trong Các Bậc Trượng Phu, ",
  "dn16:6.28.4": "Được vua loài Rồng tôn thờ tại Rāmagāma. ",
  "dn16:6.28.5": "Một chiếc răng được chư thiên cõi Ba Mươi Ba cúng dường, ",
  "dn16:6.28.6": "Một chiếc khác được tôn thờ tại thành Gandhāra; ",
  "dn16:6.28.7": "Một chiếc nữa trong lãnh thổ vua Kāliṅga, ",
  "dn16:6.28.8": "Một chiếc được vua loài Rồng tôn thờ. ",
  "dn16:6.28.9": "Do uy lực của Ngài, trái đất này, ",
  "dn16:6.28.10": "Được trang hoàng bởi những nơi cúng dường tốt đẹp; ",
  "dn16:6.28.11": "Như vậy, xá lợi của bậc Hữu Nhãn này, ",
  "dn16:6.28.12": "Được tôn kính bởi những bậc đáng được tôn kính. ",
  "dn16:6.28.13": "Được thiên chủ, long vương, vua loài người tôn kính, ",
  "dn16:6.28.14": "Cũng được các bậc tối thượng trong loài người tôn kính; ",
  "dn16:6.28.15": "Hãy chắp tay đảnh lễ khi có được xá lợi ấy, ",
  "dn16:6.28.16": "Vì Đức Phật thật khó gặp trong hàng trăm kiếp. ",
  "dn16:6.28.17": "Bốn mươi chiếc răng cùng với tất cả, ",
  "dn16:6.28.18": "Tóc, lông khắp thân thể; ",
  "dn16:6.28.19": "Chư thiên mỗi vị lấy một phần, ",
  "dn16:6.28.20": "Mang đi khắp các cõi thế giới. ",
  "dn16:6.28.21": "Kinh Đại Bát Niết Bàn đã chấm dứt, là kinh thứ ba. "
}

